const CACHE_NAME = 'order-tracker-v1';
const ASSETS_TO_CACHE = [
  './',
  './index.html',
  './index.tsx',
  'https://cdn.tailwindcss.com',
  'https://unpkg.com/dexie/dist/dexie.js',
  'https://unpkg.com/papaparse/papaparse.min.js'
];

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      return cache.addAll(ASSETS_TO_CACHE);
    })
  );
});

self.addEventListener('fetch', (event) => {
  event.respondWith(
    caches.match(event.request).then((response) => {
      return response || fetch(event.request);
    })
  );
});

import Dexie, { Table } from 'dexie';

export interface Order {
  id?: number;
  customer: string;
  city: string;
  material: string;
  qty: number;
  createdAt: number;
  note?: string;
}

export class OrderTrackerDB extends Dexie {
  orders!: Table<Order>;

  constructor() {
    super('OrderTrackerDB');
    this.version(1).stores({
      orders: '++id, customer, city, material, qty, createdAt'
    });
  }
}

export const db = new OrderTrackerDB();

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppTab {
  ADD_ORDER = 'ADD_ORDER',
  ORDERS_LIST = 'ORDERS_LIST',
  SUMMARY = 'SUMMARY',
  BACKUP = 'BACKUP'
}

export interface SummaryRow {
  city: string;
  customer: string;
  material: string;
  orderCount: number;
  totalQty: number;
}

import React, { useState } from 'react';
import { AppTab } from './types';
import AddOrder from './components/AddOrder';
import OrdersList from './components/OrdersList';
import Summary from './components/Summary';
import Backup from './components/Backup';
import { 
  PlusIcon, 
  ListBulletIcon, 
  ChartBarIcon, 
  CloudArrowUpIcon 
} from '@heroicons/react/24/outline';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.ADD_ORDER);
  const [editingOrderId, setEditingOrderId] = useState<number | null>(null);

  const renderContent = () => {
    switch (activeTab) {
      case AppTab.ADD_ORDER:
        return <AddOrder 
          editId={editingOrderId} 
          onSuccess={() => {
            setEditingOrderId(null);
            setActiveTab(AppTab.ORDERS_LIST);
          }} 
          onCancel={() => {
            setEditingOrderId(null);
            setActiveTab(AppTab.ORDERS_LIST);
          }}
        />;
      case AppTab.ORDERS_LIST:
        return <OrdersList 
          onEdit={(id) => {
            setEditingOrderId(id);
            setActiveTab(AppTab.ADD_ORDER);
          }} 
        />;
      case AppTab.SUMMARY:
        return <Summary />;
      case AppTab.BACKUP:
        return <Backup />;
      default:
        return <AddOrder />;
    }
  };

  const navItems = [
    { id: AppTab.ADD_ORDER, label: 'Add', icon: <PlusIcon className="w-5 h-5" /> },
    { id: AppTab.ORDERS_LIST, label: 'List', icon: <ListBulletIcon className="w-5 h-5" /> },
    { id: AppTab.SUMMARY, label: 'Summary', icon: <ChartBarIcon className="w-5 h-5" /> },
    { id: AppTab.BACKUP, label: 'Backup', icon: <CloudArrowUpIcon className="w-5 h-5" /> },
  ];

  return (
    <div className="flex flex-col min-h-screen">
      <header className="bg-indigo-600 text-white p-4 shadow-md sticky top-0 z-10">
        <h1 className="text-xl font-bold">Order Tracker Pro</h1>
      </header>

      <main className="flex-1 pb-20 p-4 md:p-8 max-w-5xl mx-auto w-full">
        {renderContent()}
      </main>

      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 shadow-lg px-2 py-1 md:py-3 flex justify-around z-20">
        {navItems.map((item) => (
          <button
            key={item.id}
            onClick={() => {
              setActiveTab(item.id);
              if (item.id !== AppTab.ADD_ORDER) setEditingOrderId(null);
            }}
            className={`flex flex-col items-center justify-center w-full py-1 rounded-lg transition-colors ${
              activeTab === item.id ? 'text-indigo-600 bg-indigo-50' : 'text-gray-500 hover:text-gray-700'
            }`}
          >
            {item.icon}
            <span className="text-xs mt-1 font-medium">{item.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
};

export default App;

