import React, { useState, useEffect, useRef } from 'react';

interface Props {
  label: string;
  value: string;
  onChange: (val: string) => void;
  options: string[];
  placeholder?: string;
  required?: boolean;
}

const AutocompleteInput: React.FC<Props> = ({ label, value, onChange, options, placeholder, required }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [filteredOptions, setFilteredOptions] = useState<string[]>([]);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    const search = value.toLowerCase().trim();
    if (!search) {
      setFilteredOptions(options.slice(0, 50));
    } else {
      setFilteredOptions(options.filter(opt => opt.toLowerCase().includes(search)).slice(0, 50));
    }
  }, [value, options]);

  return (
    <div className="relative mb-4" ref={containerRef}>
      <label className="block text-sm font-medium text-gray-700 mb-1">
        {label} {required && <span className="text-red-500">*</span>}
      </label>
      <input
        type="text"
        value={value}
        onChange={(e) => {
          onChange(e.target.value);
          setIsOpen(true);
        }}
        onFocus={() => setIsOpen(true)}
        placeholder={placeholder}
        className="w-full px-4 py-2 border border-gray-300 rounded-md focus:ring-indigo-500 focus:border-indigo-500 shadow-sm"
        required={required}
      />

      {isOpen && filteredOptions.length > 0 && (
        <ul className="absolute z-30 w-full mt-1 bg-white border border-gray-200 rounded-md shadow-lg max-h-60 overflow-auto">
          {filteredOptions.map((option, idx) => (
            <li
              key={idx}
              className="px-4 py-2 hover:bg-indigo-50 cursor-pointer text-gray-700"
              onClick={() => {
                onChange(option);
                setIsOpen(false);
              }}
            >
              {option}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
};

export default AutocompleteInput;

import React, { useState, useEffect } from 'react';
import { db, Order } from '../db';
import AutocompleteInput from './AutocompleteInput';

interface Props {
  editId?: number | null;
  onSuccess: () => void;
  onCancel: () => void;
}

const AddOrder: React.FC<Props> = ({ editId, onSuccess, onCancel }) => {
  const [formData, setFormData] = useState({
    customer: '',
    city: '',
    material: '',
    qty: 0,
    note: ''
  });

  const [options, setOptions] = useState<{ customers: string[], cities: string[], materials: string[] }>({
    customers: [],
    cities: [],
    materials: []
  });

  useEffect(() => {
    const loadOptions = async () => {
      const orders = await db.orders.toArray();
      const distinct = (arr: string[]) => Array.from(new Set(arr.filter(Boolean).map(s => s.trim()))).sort();

      setOptions({
        customers: distinct(orders.map(o => o.customer)),
        cities: distinct(orders.map(o => o.city)),
        materials: distinct(orders.map(o => o.material)),
      });
    };
    loadOptions();

    if (editId) {
      db.orders.get(editId).then(order => {
        if (order) setFormData({ ...order });
      });
    }
  }, [editId]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const { customer, city, material, qty, note } = formData;

    if (!customer.trim() || !city.trim() || !material.trim() || qty <= 0) {
      alert("Please fill all required fields correctly.");
      return;
    }

    const orderData: Order = {
      customer: customer.trim(),
      city: city.trim(),
      material: material.trim(),
      qty: Number(qty),
      note: note.trim(),
      createdAt: editId ? formData.createdAt : Date.now()
    };

    try {
      if (editId) {
        await db.orders.update(editId, orderData);
      } else {
        await db.orders.add(orderData);
      }
      onSuccess();
    } catch (err) {
      console.error(err);
      alert("Failed to save order.");
    }
  };

  const clearForm = () => {
    setFormData({
      customer: '',
      city: '',
      material: '',
      qty: 0,
      note: ''
    });
  };

  return (
    <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-100">
      <h2 className="text-2xl font-bold mb-6 text-indigo-700">
        {editId ? 'Edit Order' : 'Add New Order'}
      </h2>
      <form onSubmit={handleSubmit} className="space-y-4">
        <AutocompleteInput
          label="Customer"
          value={formData.customer}
          onChange={(val) => setFormData({ ...formData, customer: val })}
          options={options.customers}
          placeholder="Enter customer name"
          required
        />
        <AutocompleteInput
          label="City / Destination"
          value={formData.city}
          onChange={(val) => setFormData({ ...formData, city: val })}
          options={options.cities}
          placeholder="Enter city"
          required
        />
        <AutocompleteInput
          label="Material Description"
          value={formData.material}
          onChange={(val) => setFormData({ ...formData, material: val })}
          options={options.materials}
          placeholder="Enter material type"
          required
        />

        <div className="mb-4">
          <label className="block text-sm font-medium text-gray-700 mb-1">Quantity <span className="text-red-500">*</span></label>
          <input
            type="number"
            value={formData.qty || ''}
            onChange={(e) => setFormData({ ...formData, qty: Number(e.target.value) })}
            className="w-full px-4 py-2 border border-gray-300 rounded-md focus:ring-indigo-500 focus:border-indigo-500 shadow-sm"
            required
            min="1"
          />
        </div>

        <div className="mb-4">
          <label className="block text-sm font-medium text-gray-700 mb-1">Note (Optional)</label>
          <textarea
            value={formData.note}
            onChange={(e) => setFormData({ ...formData, note: e.target.value })}
            className="w-full px-4 py-2 border border-gray-300 rounded-md focus:ring-indigo-500 focus:border-indigo-500 shadow-sm"
            rows={3}
          />
        </div>

        <div className="flex gap-3 pt-4">
          <button
            type="submit"
            className="flex-1 bg-indigo-600 text-white font-semibold py-3 px-4 rounded-lg hover:bg-indigo-700 transition shadow-lg active:scale-95"
          >
            {editId ? 'Update Order' : 'Save Order'}
          </button>
          {!editId ? (
            <button
              type="button"
              onClick={clearForm}
              className="px-6 py-3 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition font-medium"
            >
              Clear
            </button>
          ) : (
            <button
              type="button"
              onClick={onCancel}
              className="px-6 py-3 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition font-medium"
            >
              Cancel
            </button>
          )}
        </div>
      </form>
    </div>
  );
};

export default AddOrder;

import React, { useState, useEffect } from 'react';
import { db, Order } from '../db';
import { useLiveQuery } from 'dexie-react-hooks';

interface Props {
  onEdit: (id: number) => void;
}

const OrdersList: React.FC<Props> = ({ onEdit }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCity, setFilterCity] = useState('');
  const [filterCustomer, setFilterCustomer] = useState('');
  const [filterMaterial, setFilterMaterial] = useState('');

  const allOrders = useLiveQuery(() => db.orders.orderBy('createdAt').reverse().toArray());

  if (!allOrders) return <div className="p-8 text-center text-gray-500">Loading orders...</div>;

  const cities = Array.from(new Set(allOrders.map(o => o.city))).sort();
  const customers = Array.from(new Set(allOrders.map(o => o.customer))).sort();
  const materials = Array.from(new Set(allOrders.map(o => o.material))).sort();

  const filteredOrders = allOrders.filter(o => {
    const matchesSearch = 
      o.customer.toLowerCase().includes(searchTerm.toLowerCase()) ||
      o.city.toLowerCase().includes(searchTerm.toLowerCase()) ||
      o.material.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (o.note && o.note.toLowerCase().includes(searchTerm.toLowerCase()));

    const matchesCity = !filterCity || o.city === filterCity;
    const matchesCustomer = !filterCustomer || o.customer === filterCustomer;
    const matchesMaterial = !filterMaterial || o.material === filterMaterial;

    return matchesSearch && matchesCity && matchesCustomer && matchesMaterial;
  });

  const handleDelete = async (id: number) => {
    if (confirm("Are you sure you want to delete this order?")) {
      await db.orders.delete(id);
    }
  };

  return (
    <div className="space-y-4">
      <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 sticky top-[72px] z-10 space-y-3">
        <input
          type="text"
          placeholder="Search everywhere..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-indigo-500 focus:border-indigo-500"
        />
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-2">
          <select
            value={filterCity}
            onChange={(e) => setFilterCity(e.target.value)}
            className="px-3 py-2 border border-gray-300 rounded-lg text-sm"
          >
            <option value="">All Cities</option>
            {cities.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
          <select
            value={filterCustomer}
            onChange={(e) => setFilterCustomer(e.target.value)}
            className="px-3 py-2 border border-gray-300 rounded-lg text-sm"
          >
            <option value="">All Customers</option>
            {customers.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
          <select
            value={filterMaterial}
            onChange={(e) => setFilterMaterial(e.target.value)}
            className="px-3 py-2 border border-gray-300 rounded-lg text-sm"
          >
            <option value="">All Materials</option>
            {materials.map(m => <option key={m} value={m}>{m}</option>)}
          </select>
        </div>
      </div>

      <div className="space-y-3">
        {filteredOrders.length === 0 ? (
          <div className="p-12 text-center text-gray-500 bg-white rounded-xl border border-dashed border-gray-300">
            No orders found matching filters.
          </div>
        ) : (
          filteredOrders.map(order => (
            <div key={order.id} className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex flex-col gap-2 relative">
              <div className="flex justify-between items-start">
                <div>
                  <h3 className="font-bold text-lg text-indigo-900 leading-tight">{order.customer}</h3>
                  <p className="text-gray-600 text-sm font-medium">{order.city}</p>
                </div>
                <div className="text-right">
                  <span className="text-xl font-bold text-indigo-600">Qty: {order.qty}</span>
                </div>
              </div>
              <div className="border-t border-gray-50 pt-2 flex flex-col sm:flex-row sm:items-center sm:justify-between gap-2">
                <p className="text-sm font-semibold text-gray-800 bg-indigo-50 px-2 py-1 rounded inline-block w-fit">
                  {order.material}
                </p>
                <p className="text-xs text-gray-400">
                  {new Date(order.createdAt).toLocaleDateString()} {new Date(order.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </p>
              </div>
              {order.note && (
                <p className="text-sm italic text-gray-500 mt-1 bg-gray-50 p-2 rounded">
                  Note: {order.note}
                </p>
              )}
              <div className="flex justify-end gap-2 mt-2 pt-2 border-t border-gray-50">
                <button
                  onClick={() => onEdit(order.id!)}
                  className="px-3 py-1.5 text-sm font-medium text-indigo-600 bg-indigo-50 rounded hover:bg-indigo-100 transition"
                >
                  Edit
                </button>
                <button
                  onClick={() => handleDelete(order.id!)}
                  className="px-3 py-1.5 text-sm font-medium text-red-600 bg-red-50 rounded hover:bg-red-100 transition"
                >
                  Delete
                </button>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default OrdersList;

import React, { useState, useMemo } from 'react';
import { db } from '../db';
import { useLiveQuery } from 'dexie-react-hooks';
import { SummaryRow } from '../types';

const Summary: React.FC = () => {
  const [filterCity, setFilterCity] = useState('');
  const [filterMaterial, setFilterMaterial] = useState('');
  const [dateRange, setDateRange] = useState({ start: '', end: '' });

  const orders = useLiveQuery(() => db.orders.toArray());

  const summaryData = useMemo(() => {
    if (!orders) return [];

    // Apply filters first
    const filtered = orders.filter(o => {
      const cityMatch = !filterCity || o.city === filterCity;
      const materialMatch = !filterMaterial || o.material === filterMaterial;
      const startMatch = !dateRange.start || o.createdAt >= new Date(dateRange.start).getTime();
      const endMatch = !dateRange.end || o.createdAt <= new Date(dateRange.end).getTime() + 86400000;
      return cityMatch && materialMatch && startMatch && endMatch;
    });

    // Grouping
    const groups: Record<string, SummaryRow> = {};

    filtered.forEach(o => {
      const key = `${o.city.trim()}|${o.customer.trim()}|${o.material.trim()}`;
      if (!groups[key]) {
        groups[key] = {
          city: o.city.trim(),
          customer: o.customer.trim(),
          material: o.material.trim(),
          orderCount: 0,
          totalQty: 0
        };
      }
      groups[key].orderCount += 1;
      groups[key].totalQty += o.qty;
    });

    return Object.values(groups).sort((a, b) => b.totalQty - a.totalQty);
  }, [orders, filterCity, filterMaterial, dateRange]);

  const cities = useMemo(() => Array.from(new Set((orders || []).map(o => o.city))).sort(), [orders]);
  const materials = useMemo(() => Array.from(new Set((orders || []).map(o => o.material))).sort(), [orders]);

  if (!orders) return <div className="p-8 text-center text-gray-500">Loading summary...</div>;

  return (
    <div className="space-y-4">
      <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 space-y-3 sticky top-[72px] z-10">
        <h2 className="font-bold text-lg text-indigo-800">Summary Filters</h2>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3">
          <div>
            <label className="text-xs font-semibold text-gray-500 uppercase mb-1 block">City</label>
            <select
              value={filterCity}
              onChange={(e) => setFilterCity(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm bg-gray-50"
            >
              <option value="">All Cities</option>
              {cities.map(c => <option key={c} value={c}>{c}</option>)}
            </select>
          </div>
          <div>
            <label className="text-xs font-semibold text-gray-500 uppercase mb-1 block">Material</label>
            <select
              value={filterMaterial}
              onChange={(e) => setFilterMaterial(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm bg-gray-50"
            >
              <option value="">All Materials</option>
              {materials.map(m => <option key={m} value={m}>{m}</option>)}
            </select>
          </div>
          <div>
            <label className="text-xs font-semibold text-gray-500 uppercase mb-1 block">From Date</label>
            <input
              type="date"
              value={dateRange.start}
              onChange={(e) => setDateRange(prev => ({ ...prev, start: e.target.value }))}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm bg-gray-50"
            />
          </div>
          <div>
            <label className="text-xs font-semibold text-gray-500 uppercase mb-1 block">To Date</label>
            <input
              type="date"
              value={dateRange.end}
              onChange={(e) => setDateRange(prev => ({ ...prev, end: e.target.value }))}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm bg-gray-50"
            />
          </div>
        </div>
      </div>

      <div className="overflow-x-auto bg-white rounded-xl shadow-sm border border-gray-100">
        <table className="w-full text-left border-collapse">
          <thead className="bg-gray-50">
            <tr>
              <th className="px-4 py-3 text-sm font-bold text-gray-700 border-b">City</th>
              <th className="px-4 py-3 text-sm font-bold text-gray-700 border-b">Customer</th>
              <th className="px-4 py-3 text-sm font-bold text-gray-700 border-b">Material</th>
              <th className="px-4 py-3 text-sm font-bold text-center text-gray-700 border-b">Count</th>
