            {summaryData.length === 0 ? (
              <tr>
                <td colSpan={5} className="px-4 py-12 text-center text-gray-400">No data found matching current filters.</td>
              </tr>
            ) : (
              summaryData.map((row, idx) => (
                <tr key={idx} className="hover:bg-indigo-50 transition-colors">
                  <td className="px-4 py-3 text-sm text-gray-600">{row.city}</td>
                  <td className="px-4 py-3 text-sm font-semibold text-indigo-900">{row.customer}</td>
