                </tr>
              ))
            )}
          </tbody>
          {summaryData.length > 0 && (
            <tfoot className="bg-indigo-50 font-bold">
              <tr>
                <td colSpan={3} className="px-4 py-3 text-right">Grand Totals:</td>
                <td className="px-4 py-3 text-center">{summaryData.reduce((acc, curr) => acc + curr.orderCount, 0)}</td>
                <td className="px-4 py-3 text-right text-indigo-700">{summaryData.reduce((acc, curr) => acc + curr.totalQty, 0)}</td>
