const Backup: React.FC = () => {
  const [importing, setImporting] = useState(false);

  const handleExport = async () => {
    const orders = await db.orders.toArray();
    if (orders.length === 0) {
      alert("No data to export.");
      return;
    }
    exportToCSV(orders, `order_tracker_backup_${new Date().toISOString().split('T')[0]}.csv`);
  };

  const handleImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setImporting(true);
    try {
      const data = await parseCSV(file);

      const ordersToImport = data.map((item: any) => {
        // Basic normalization
        return {
          customer: String(item.customer || '').trim(),
          city: String(item.city || '').trim(),
          material: String(item.material || '').trim(),
          qty: Number(item.qty || 0),
          createdAt: Number(item.createdAt || Date.now()),
          note: item.note ? String(item.note).trim() : undefined
        };
      }).filter(o => o.customer && o.city && o.material && o.qty > 0);

      if (confirm(`Import ${ordersToImport.length} records? Existing records with matching IDs might be updated or duplicates created if no ID present.`)) {
        await db.orders.bulkAdd(ordersToImport);
        alert("Import successful!");
      }
    } catch (err) {
      console.error(err);
      alert("Error importing CSV. Ensure file format is correct.");
    } finally {
      setImporting(false);
      e.target.value = ''; // Reset input
    }
  };

  const handleReset = async () => {
    if (confirm("DANGER: This will delete ALL local data permanently. Make sure you have a backup! Continue?")) {
      await db.orders.clear();
      alert("Database cleared.");
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-100 max-w-2xl mx-auto space-y-8">
      <div>
        <h2 className="text-2xl font-bold mb-2 text-gray-800">Backup & Recovery</h2>
        <p className="text-gray-500 mb-6">Manage your local database. All data is stored in your browser's IndexedDB and is available offline.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="p-4 border border-gray-100 rounded-xl bg-indigo-50 hover:bg-indigo-100 transition-colors cursor-pointer group flex flex-col items-center text-center" onClick={handleExport}>
          <div className="w-12 h-12 bg-indigo-600 text-white rounded-full flex items-center justify-center mb-3 group-hover:scale-110 transition">
             <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
          </div>
          <h3 className="font-bold text-indigo-900">Export CSV</h3>
          <p className="text-xs text-indigo-700">Download all data as a CSV file for backup or Excel.</p>
        </div>

        <label className="p-4 border border-gray-100 rounded-xl bg-green-50 hover:bg-green-100 transition-colors cursor-pointer group flex flex-col items-center text-center">
          <input type="file" accept=".csv" onChange={handleImport} className="hidden" disabled={importing} />
          <div className="w-12 h-12 bg-green-600 text-white rounded-full flex items-center justify-center mb-3 group-hover:scale-110 transition">
             <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0l-4 4m4-4v12" /></svg>
          </div>
          <h3 className="font-bold text-green-900">{importing ? 'Processing...' : 'Import CSV'}</h3>
