    note: string;
    createdAt?: number;
  }>({
    customer: '',
    city: '',
    material: '',
    qty: 0,
    note: ''
  });

  const [options, setOptions] = useState<{ customers: string[], cities: string[], materials: string[] }>({
    customers: [],
    cities: [],
    materials: []
  });

  useEffect(() => {
    const loadOptions = async () => {
      const orders = await db.orders.toArray();
      const distinct = (arr: string[]) => Array.from(new Set(arr.filter(Boolean).map(s => s.trim()))).sort();

      setOptions({
        customers: distinct(orders.map(o => o.customer)),
        cities: distinct(orders.map(o => o.city)),
        materials: distinct(orders.map(o => o.material)),
      });
    };
    loadOptions();

    if (editId) {
      db.orders.get(editId).then(order => {
        if (order) {
          setFormData({
            customer: order.customer,
            city: order.city,
            material: order.material,
            qty: order.qty,
            note: order.note || '',
            createdAt: order.createdAt
          });
        }
      });
    }
  }, [editId]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const { customer, city, material, qty, note, createdAt } = formData;

    if (!customer.trim() || !city.trim() || !material.trim() || qty <= 0) {
      alert("Please fill all required fields correctly.");
      return;
    }

    const orderData: Order = {
      customer: customer.trim(),
      city: city.trim(),
      material: material.trim(),
      qty: Number(qty),
      note: note.trim(),
      createdAt: editId && createdAt ? createdAt : Date.now()
    };

    try {
      if (editId) {
        await db.orders.update(editId, orderData);
      } else {
        await db.orders.add(orderData);
      }
      onSuccess();
    } catch (err) {
      console.error(err);
      alert("Failed to save order.");
    }
  };

  const clearForm = () => {
    setFormData({
      customer: '',
      city: '',
      material: '',
      qty: 0,
      note: ''
    });
  };

  return (
    <div className="max-w-xl mx-auto">
      <div className="bg-white rounded-3xl shadow-xl shadow-gray-200/50 p-8 border border-gray-100">
        <header className="mb-8">
          <h2 className="text-3xl font-black text-gray-900 leading-tight">
            {editId ? 'Modify Record' : 'Create Entry'}
          </h2>
          <p className="text-gray-500 font-medium">Capture order details for local tracking.</p>
        </header>

        <form onSubmit={handleSubmit} className="space-y-6">
          <AutocompleteInput
            label="Customer Name"
            value={formData.customer}
            onChange={(val) => setFormData({ ...formData, customer: val })}
            options={options.customers}
            placeholder="e.g. Acme Corp"
            required
          />

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
            <AutocompleteInput
              label="City / Destination"
              value={formData.city}
              onChange={(val) => setFormData({ ...formData, city: val })}
              options={options.cities}
              placeholder="e.g. New York"
              required
            />
            <div className="relative">
              <label className="block text-sm font-bold text-gray-700 mb-2 uppercase tracking-wide">Quantity</label>
              <input
                type="number"
                value={formData.qty || ''}
                onChange={(e) => setFormData({ ...formData, qty: Number(e.target.value) })}
                className="w-full px-4 py-3 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-indigo-500 shadow-inner font-bold text-lg"
                required
                min="1"
              />
            </div>
          </div>

          <AutocompleteInput
            label="Material Description"
            value={formData.material}
            onChange={(val) => setFormData({ ...formData, material: val })}
            options={options.materials}
            placeholder="e.g. Steel Pipes"
            required
          />

          <div className="mb-4">
            <label className="block text-sm font-bold text-gray-700 mb-2 uppercase tracking-wide">Additional Notes</label>
            <textarea
              value={formData.note}
              onChange={(e) => setFormData({ ...formData, note: e.target.value })}
              className="w-full px-4 py-3 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-indigo-500 shadow-inner min-h-[100px]"
              placeholder="Any extra details..."
            />
          </div>

          <div className="flex flex-col sm:flex-row gap-3 pt-6">
            <button
              type="submit"
              className="flex-[2] bg-indigo-600 text-white font-black py-4 px-6 rounded-2xl hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-200 active:scale-95 text-lg"
            >
              {editId ? 'Save Changes' : 'Confirm Entry'}
            </button>
            <button
              type="button"
              onClick={editId ? onCancel : clearForm}
              className="flex-1 px-6 py-4 bg-gray-100 text-gray-600 rounded-2xl hover:bg-gray-200 transition font-bold"
            >
              {editId ? 'Cancel' : 'Reset'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default AddOrder;

import React, { useState, useEffect, useRef } from 'react';

interface Props {
  label: string;
  value: string;
  onChange: (val: string) => void;
  options: string[];
  placeholder?: string;
  required?: boolean;
}

const AutocompleteInput: React.FC<Props> = ({ label, value, onChange, options, placeholder, required }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [filteredOptions, setFilteredOptions] = useState<string[]>([]);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    const search = value.toLowerCase().trim();
    if (!search) {
      setFilteredOptions(options.slice(0, 50));
    } else {
      setFilteredOptions(options.filter(opt => opt.toLowerCase().includes(search)).slice(0, 50));
    }
  }, [value, options]);

  return (
    <div className="relative w-full" ref={containerRef}>
      <label className="block text-sm font-bold text-gray-700 mb-2 uppercase tracking-wide">
        {label} {required && <span className="text-red-500">*</span>}
      </label>
      <input
        type="text"
        value={value}
        onChange={(e) => {
          onChange(e.target.value);
          setIsOpen(true);
        }}
        onFocus={() => setIsOpen(true)}
        placeholder={placeholder}
        className="w-full px-4 py-3 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-indigo-500 shadow-inner font-medium text-gray-900 transition-all placeholder:text-gray-300"
        required={required}
      />

      {isOpen && filteredOptions.length > 0 && (
        <ul className="absolute z-50 w-full mt-2 bg-white border border-gray-100 rounded-2xl shadow-2xl max-h-64 overflow-auto py-2 animate-in slide-in-from-top-2 duration-200">
          {filteredOptions.map((option, idx) => (
            <li
              key={idx}
              className="px-5 py-3 hover:bg-indigo-50 cursor-pointer text-gray-700 font-medium border-b border-gray-50 last:border-none"
              onClick={() => {
                onChange(option);
                setIsOpen(false);
              }}
            >
              {option}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
};

export default AutocompleteInput;

