  const [searchTerm, setSearchTerm] = useState('');
  const [filterCity, setFilterCity] = useState('');
  const [filterCustomer, setFilterCustomer] = useState('');
  const [filterMaterial, setFilterMaterial] = useState('');
  const [filterStatus, setFilterStatus] = useState('');
  const [previewImage, setPreviewImage] = useState<string | null>(null);

  const allOrders = useLiveQuery(() => db.orders.orderBy('createdAt').reverse().toArray());

  if (!allOrders) return <div className="p-12 text-center text-gray-400 font-bold">Loading records...</div>;

  // Fix: Explicitly cast to string[] to resolve 'unknown' type inference issues in JSX maps.
  const cities = Array.from(new Set(allOrders.map(o => o.city))).sort() as string[];
  const customers = Array.from(new Set(allOrders.map(o => o.customer))).sort() as string[];
  const materials = Array.from(new Set(allOrders.map(o => o.material))).sort() as string[];

  const filteredOrders = allOrders.filter(o => {
    const matchesSearch = 
      o.customer.toLowerCase().includes(searchTerm.toLowerCase()) ||
      o.city.toLowerCase().includes(searchTerm.toLowerCase()) ||
      o.material.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (o.note && o.note.toLowerCase().includes(searchTerm.toLowerCase()));

    const matchesCity = !filterCity || o.city === filterCity;
    const matchesCustomer = !filterCustomer || o.customer === filterCustomer;
    const matchesMaterial = !filterMaterial || o.material === filterMaterial;
    const matchesStatus = !filterStatus || o.status === filterStatus;

    return matchesSearch && matchesCity && matchesCustomer && matchesMaterial && matchesStatus;
  });

  const handleDelete = async (id: number) => {
    if (confirm("Permanently delete this record?")) {
      await db.orders.delete(id);
    }
  };

  return (
    <div className="space-y-8 animate-in slide-in-from-bottom-4 duration-500">
      {/* Search & Filters */}
      <div className="bg-white/80 backdrop-blur-md p-6 rounded-3xl shadow-xl shadow-gray-200/40 border border-white sticky top-[80px] z-20 space-y-4">
        <div className="relative">
          <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400">
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          </span>
          <input
            type="text"
            placeholder="Search records..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-12 pr-4 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-indigo-500 shadow-inner font-medium text-lg"
          />
        </div>
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
          <select value={filterStatus} onChange={(e) => setFilterStatus(e.target.value)} className="px-4 py-3 bg-white border border-gray-100 rounded-xl text-xs font-bold shadow-sm focus:ring-2 focus:ring-indigo-500 outline-none">
            <option value="">All Statuses</option>
            {STATUS_OPTIONS.map(s => <option key={s} value={s}>{s}</option>)}
          </select>
          <select value={filterCity} onChange={(e) => setFilterCity(e.target.value)} className="px-4 py-3 bg-white border border-gray-100 rounded-xl text-xs font-bold shadow-sm focus:ring-2 focus:ring-indigo-500 outline-none">
            <option value="">All Cities</option>
            {cities.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
          <select value={filterCustomer} onChange={(e) => setFilterCustomer(e.target.value)} className="px-4 py-3 bg-white border border-gray-100 rounded-xl text-xs font-bold shadow-sm focus:ring-2 focus:ring-indigo-500 outline-none">
            <option value="">All Customers</option>
            {customers.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
          <select value={filterMaterial} onChange={(e) => setFilterMaterial(e.target.value)} className="px-4 py-3 bg-white border border-gray-100 rounded-xl text-xs font-bold shadow-sm focus:ring-2 focus:ring-indigo-500 outline-none">
            <option value="">All Materials</option>
            {materials.map(m => <option key={m} value={m}>{m}</option>)}
          </select>
        </div>
      </div>

      {/* Orders Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {filteredOrders.length === 0 ? (
          <div className="col-span-full p-20 text-center bg-white rounded-3xl border-2 border-dashed border-gray-200">
            <div className="text-6xl mb-4">📭</div>
            <h3 className="text-xl font-black text-gray-900">No Orders Found</h3>
            <p className="text-gray-500 mt-2">Try adjusting your search or filters.</p>
          </div>
        ) : (
          filteredOrders.map(order => (
            <div key={order.id} className="group bg-white p-6 rounded-3xl shadow-sm hover:shadow-xl hover:shadow-indigo-100/50 border border-gray-50 transition-all duration-300 relative overflow-hidden">
              <div className={`absolute top-0 right-0 w-32 h-32 opacity-10 rounded-full -mr-16 -mt-16 transition-colors duration-500 ${order.status === 'Delivered' ? 'bg-green-600' : 'bg-indigo-600'}`}></div>

              <div className="relative">
                <div className="flex justify-between items-start mb-4">
                  <div>
                    <div className="flex items-center gap-2 mb-2">
                       <span className="text-[10px] font-black uppercase tracking-widest text-indigo-500 bg-indigo-50 px-2 py-0.5 rounded-full">
                        {order.city}
                      </span>
                      <span className={`text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded-full border ${getStatusColor(order.status || 'Pending')}`}>
                        {order.status || 'Pending'}
                      </span>
                    </div>
                    <h3 className="font-black text-xl text-gray-900 leading-none">{order.customer}</h3>
                  </div>
                  <div className="bg-white shadow-md rounded-2xl p-2 px-3 flex flex-col items-center">
                    <span className="text-[10px] text-gray-400 font-black uppercase">Qty</span>
                    <span className="text-xl font-black text-indigo-600 leading-none">{order.qty}</span>
                  </div>
                </div>

                <div className="flex flex-wrap items-center gap-2 mb-4">
                  <span className="text-sm font-bold text-gray-700 bg-gray-100 px-3 py-1.5 rounded-xl">
                    {order.material}
                  </span>
                </div>

                {/* Attachments Preview */}
                {order.attachments && order.attachments.length > 0 && (
                  <div className="flex gap-2 overflow-x-auto pb-2 mb-4 scrollbar-hide">
                    {order.attachments.map((src, i) => (
                      <button
                        key={i}
                        onClick={() => setPreviewImage(src)}
                        className="flex-shrink-0 w-16 h-16 rounded-xl border border-gray-100 overflow-hidden shadow-sm hover:scale-105 transition-transform"
                      >
                        <img src={src} className="w-full h-full object-cover" alt="attachment" />
                      </button>
                    ))}
                  </div>
                )}

                {order.note && (
                  <div className="bg-yellow-50/50 p-3 rounded-2xl mb-4 text-sm text-yellow-800 italic border-l-4 border-yellow-200">
                    "{order.note}"
                  </div>
                )}

                <div className="flex justify-between items-center pt-4 border-t border-gray-50">
                  <span className="text-xs font-bold text-gray-400">
                    {new Date(order.createdAt).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}
                  </span>
                  <div className="flex gap-2">
                    <button onClick={() => onEdit(order.id!)} className="p-2.5 bg-gray-50 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition">
                      <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
                    </button>
                    <button onClick={() => handleDelete(order.id!)} className="p-2.5 bg-gray-50 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition">
                      <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                    </button>
                  </div>
                </div>
              </div>
            </div>
          ))
        )}
      </div>

      {/* Image Preview Modal */}
      {previewImage && (
        <div className="fixed inset-0 z-[100] bg-black/90 backdrop-blur-sm flex items-center justify-center p-4 animate-in fade-in duration-200" onClick={() => setPreviewImage(null)}>
          <button className="absolute top-6 right-6 text-white p-2 hover:bg-white/10 rounded-full transition">
            <svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
          <img src={previewImage} className="max-w-full max-h-full rounded-2xl shadow-2xl object-contain animate-in zoom-in-95 duration-300" alt="Full Preview" />
        </div>
      )}
    </div>
  );
};

export default OrdersList;

import React, { useState, useMemo } from 'react';
import { db } from '../db';
import { useLiveQuery } from 'dexie-react-hooks';
import { SummaryRow } from '../types';

const Summary: React.FC = () => {
  const [filterCity, setFilterCity] = useState('');
  const [filterMaterial, setFilterMaterial] = useState('');
  const [dateRange, setDateRange] = useState({ start: '', end: '' });

  const orders = useLiveQuery(() => db.orders.toArray());

  const summaryData = useMemo(() => {
    if (!orders) return [];

    const filtered = orders.filter(o => {
      const cityMatch = !filterCity || o.city === filterCity;
      const materialMatch = !filterMaterial || o.material === filterMaterial;
      const startMatch = !dateRange.start || o.createdAt >= new Date(dateRange.start).getTime();
      const endMatch = !dateRange.end || o.createdAt <= new Date(dateRange.end).getTime() + 86400000;
      return cityMatch && materialMatch && startMatch && endMatch;
    });

    const groups: Record<string, SummaryRow> = {};

    filtered.forEach(o => {
      const key = `${o.city.trim()}|${o.customer.trim()}|${o.material.trim()}`;
      if (!groups[key]) {
        groups[key] = {
          city: o.city.trim(),
          customer: o.customer.trim(),
          material: o.material.trim(),
          orderCount: 0,
          totalQty: 0
        };
      }
      groups[key].orderCount += 1;
      groups[key].totalQty += o.qty;
    });

    return Object.values(groups).sort((a, b) => b.totalQty - a.totalQty);
  }, [orders, filterCity, filterMaterial, dateRange]);

  const stats = useMemo(() => {
    if (!orders) return { totalOrders: 0, totalQty: 0, uniqueCustomers: 0 };
    return {
      totalOrders: orders.length,
      totalQty: orders.reduce((sum, o) => sum + o.qty, 0),
      uniqueCustomers: new Set(orders.map(o => o.customer)).size
    };
  }, [orders]);

  // Fix: Explicitly cast derived arrays to string[] to resolve 'unknown' type errors in mapping.
  const cities = useMemo(() => Array.from(new Set((orders || []).map(o => o.city))).sort() as string[], [orders]);
  const materials = useMemo(() => Array.from(new Set((orders || []).map(o => o.material))).sort() as string[], [orders]);

  if (!orders) return <div className="p-12 text-center text-gray-400 font-bold">Aggregating data...</div>;

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-50">
          <p className="text-[10px] font-black uppercase tracking-widest text-gray-400 mb-1">Total Entries</p>
          <p className="text-3xl font-black text-indigo-600">{stats.totalOrders}</p>
        </div>
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-50">
          <p className="text-[10px] font-black uppercase tracking-widest text-gray-400 mb-1">Accumulated Qty</p>
          <p className="text-3xl font-black text-indigo-600">{stats.totalQty.toLocaleString()}</p>
        </div>
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-50">
          <p className="text-[10px] font-black uppercase tracking-widest text-gray-400 mb-1">Unique Clients</p>
          <p className="text-3xl font-black text-indigo-600">{stats.uniqueCustomers}</p>
        </div>
      </div>

      <div className="bg-white p-6 rounded-3xl shadow-xl shadow-gray-200/40 border border-gray-100">
        <header className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
          <h2 className="text-2xl font-black text-gray-900 tracking-tight">Consolidated View</h2>
          <div className="flex flex-wrap gap-2">
             <select
              value={filterCity}
              onChange={(e) => setFilterCity(e.target.value)}
              className="px-3 py-2 bg-gray-50 border-none rounded-xl text-xs font-bold text-gray-600 focus:ring-2 focus:ring-indigo-500"
            >
              <option value="">All Cities</option>
              {cities.map(c => <option key={c} value={c}>{c}</option>)}
            </select>
            <select
              value={filterMaterial}
              onChange={(e) => setFilterMaterial(e.target.value)}
              className="px-3 py-2 bg-gray-50 border-none rounded-xl text-xs font-bold text-gray-600 focus:ring-2 focus:ring-indigo-500"
            >
              <option value="">All Materials</option>
              {materials.map(m => <option key={m} value={m}>{m}</option>)}
            </select>
          </div>
        </header>

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="border-b border-gray-50">
                <th className="pb-4 px-2 text-[10px] font-black uppercase tracking-widest text-gray-400">Location</th>
                <th className="pb-4 px-2 text-[10px] font-black uppercase tracking-widest text-gray-400">Customer</th>
                <th className="pb-4 px-2 text-[10px] font-black uppercase tracking-widest text-gray-400 text-center">Material</th>
                <th className="pb-4 px-2 text-[10px] font-black uppercase tracking-widest text-gray-400 text-center">Orders</th>
                <th className="pb-4 px-2 text-[10px] font-black uppercase tracking-widest text-gray-400 text-right">Qty</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {summaryData.length === 0 ? (
                <tr>
                  <td colSpan={5} className="py-20 text-center text-gray-300 font-bold italic">No matching groups found.</td>
                </tr>
              ) : (
                summaryData.map((row, idx) => (
                  <tr key={idx} className="group hover:bg-indigo-50/50 transition-colors">
                    <td className="py-4 px-2 text-sm font-bold text-gray-500">{row.city}</td>
                    <td className="py-4 px-2 text-sm font-black text-gray-900">{row.customer}</td>
                    <td className="py-4 px-2 text-sm text-center">
                      <span className="bg-gray-100 text-gray-600 px-3 py-1 rounded-full text-[10px] font-black uppercase">{row.material}</span>
                    </td>
                    <td className="py-4 px-2 text-sm text-center font-bold text-gray-400">{row.orderCount}</td>
                    <td className="py-4 px-2 text-sm text-right font-black text-indigo-600">{row.totalQty.toLocaleString()}</td>
                  </tr>
                ))
              )}
            </tbody>
            {summaryData.length > 0 && (
              <tfoot className="border-t-2 border-indigo-100">
                <tr className="bg-indigo-50/30">
                  <td colSpan={3} className="py-4 px-4 text-xs font-black text-indigo-400 uppercase tracking-widest text-right">Totals</td>
                  <td className="py-4 px-2 text-sm text-center font-black text-indigo-900">{summaryData.reduce((acc, curr) => acc + curr.orderCount, 0)}</td>
                  <td className="py-4 px-2 text-lg text-right font-black text-indigo-700">{summaryData.reduce((acc, curr) => acc + curr.totalQty, 0).toLocaleString()}</td>
                </tr>
              </tfoot>
            )}
          </table>
        </div>
      </div>
    </div>
  );
};

export default Summary;

import React, { useState, useEffect, useRef } from 'react';
import { db, Order } from '../db';
import AutocompleteInput from './AutocompleteInput';

interface Props {
  editId?: number | null;
  onSuccess: () => void;
  onCancel: () => void;
}

const STATUS_OPTIONS = ['Pending', 'Processing', 'Shipped', 'Delivered', 'Cancelled'];

const AddOrder: React.FC<Props> = ({ editId, onSuccess, onCancel }) => {
  const [formData, setFormData] = useState<{
    customer: string;
    city: string;
    material: string;
    qty: number;
    status: string;
    note: string;
    attachments: string[];
    createdAt?: number;
  }>({
    customer: '',
    city: '',
    material: '',
    qty: 0,
    status: 'Pending',
    note: '',
    attachments: []
  });

  const [options, setOptions] = useState<{ customers: string[], cities: string[], materials: string[] }>({
    customers: [],
    cities: [],
    materials: []
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const loadOptions = async () => {
      const orders = await db.orders.toArray();
      const masterCustomers = await db.customersMaster.toArray();
      const masterCities = await db.citiesMaster.toArray();
      const masterMaterials = await db.materialsMaster.toArray();

      const distinct = (arr: string[]) => Array.from(new Set(arr.filter(Boolean).map(s => s.trim()))).sort();

      setOptions({
        customers: distinct([...orders.map(o => o.customer), ...masterCustomers.map(c => c.name)]),
        cities: distinct([...orders.map(o => o.city), ...masterCities.map(c => c.name)]),
        materials: distinct([...orders.map(o => o.material), ...masterMaterials.map(m => m.name)]),
      });
    };
    loadOptions();

    if (editId) {
      db.orders.get(editId).then(order => {
        if (order) {
          setFormData({
            customer: order.customer,
            city: order.city,
            material: order.material,
            qty: order.qty,
            status: order.status || 'Pending',
            note: order.note || '',
            attachments: order.attachments || [],
            createdAt: order.createdAt
          });
        }
      });
    }
  }, [editId]);

  const readFileAsDataURL = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = (error) => reject(error);
      reader.readAsDataURL(file);
    });
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    try {
      const newAttachments = await Promise.all(
        Array.from(files).map(file => readFileAsDataURL(file))
      );

      setFormData(prev => ({
        ...prev,
        attachments: [...prev.attachments, ...newAttachments]
      }));
    } catch (err) {
      console.error("Error reading files:", err);
      alert("Failed to read one or more images. Please try again.");
    } finally {
      // Clear the input value so the same file can be selected again if needed
      if (e.target) e.target.value = '';
    }
  };

  const removeAttachment = (index: number) => {
    setFormData(prev => ({
      ...prev,
      attachments: prev.attachments.filter((_, i) => i !== index)
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const { customer, city, material, qty, status, note, attachments, createdAt } = formData;

    if (!customer.trim() || !city.trim() || !material.trim() || qty <= 0) {
      alert("Please fill all required fields correctly.");
      return;
    }

    const orderData: Order = {
      customer: customer.trim(),
      city: city.trim(),
      material: material.trim(),
      qty: Number(qty),
      status: status,
      note: note.trim(),
      attachments,
      createdAt: editId && createdAt ? createdAt : Date.now()
    };

    try {
      if (editId) {
        await db.orders.update(editId, orderData as any);
      } else {
        await db.orders.add(orderData);
      }
      onSuccess();
    } catch (err) {
      console.error(err);
      alert("Failed to save order.");
    }
  };

  const clearForm = () => {
    setFormData({
      customer: '',
      city: '',
      material: '',
      qty: 0,
      status: 'Pending',
      note: '',
      attachments: []
    });
  };

  return (
    <div className="max-w-xl mx-auto">
      <div className="bg-white rounded-3xl shadow-xl shadow-gray-200/50 p-8 border border-gray-100">
        <header className="mb-8">
          <h2 className="text-3xl font-black text-gray-900 leading-tight">
            {editId ? 'Modify Record' : 'Create Entry'}
          </h2>
          <p className="text-gray-500 font-medium">Capture order details and loading proof.</p>
        </header>

        <form onSubmit={handleSubmit} className="space-y-6">
          <AutocompleteInput
            label="Customer Name"
            value={formData.customer}
            onChange={(val) => setFormData({ ...formData, customer: val })}
            options={options.customers}
            placeholder="e.g. Acme Corp"
            required
          />

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
            <AutocompleteInput
              label="City / Destination"
              value={formData.city}
              onChange={(val) => setFormData({ ...formData, city: val })}
              options={options.cities}
              placeholder="e.g. New York"
              required
            />
            <div className="relative">
              <label className="block text-sm font-bold text-gray-700 mb-2 uppercase tracking-wide">Quantity</label>
              <input
                type="number"
                value={formData.qty || ''}
                onChange={(e) => setFormData({ ...formData, qty: Number(e.target.value) })}
                className="w-full px-4 py-3 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-indigo-500 shadow-inner font-bold text-lg"
                required
                min="1"
              />
            </div>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
            <AutocompleteInput
              label="Material Description"
              value={formData.material}
              onChange={(val) => setFormData({ ...formData, material: val })}
              options={options.materials}
              placeholder="e.g. Steel Pipes"
              required
            />
            <div className="relative">
              <label className="block text-sm font-bold text-gray-700 mb-2 uppercase tracking-wide">Order Status</label>
              <select
                value={formData.status}
                onChange={(e) => setFormData({ ...formData, status: e.target.value })}
                className="w-full px-4 py-3 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-indigo-500 shadow-inner font-bold text-gray-900 appearance-none"
              >
                {STATUS_OPTIONS.map(opt => (
                  <option key={opt} value={opt}>{opt}</option>
                ))}
              </select>
            </div>
          </div>

          <div>
            <label className="block text-sm font-bold text-gray-700 mb-3 uppercase tracking-wide">Proof of Loading / Vehicle Images</label>
            <div className="grid grid-cols-3 sm:grid-cols-4 gap-3">
              {formData.attachments.map((src, idx) => (
                <div key={idx} className="relative aspect-square rounded-xl overflow-hidden group border border-gray-100 shadow-sm">
                  <img src={src} className="w-full h-full object-cover" alt="attachment" />
                  <button
                    type="button"
                    onClick={() => removeAttachment(idx)}
                    className="absolute top-1 right-1 bg-red-500 text-white p-1 rounded-full opacity-0 group-hover:opacity-100 transition-opacity shadow-lg"
                  >
                    <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
                  </button>
                </div>
              ))}
              <button
                type="button"
                onClick={() => fileInputRef.current?.click()}
