// Fix: Use named import for Dexie to ensure the class type is correctly inherited and the 'version' method is recognized.
import { Dexie, type Table } from 'dexie';

export interface Order {
  id?: number;
  customer: string;
  city: string;
  material: string;
  qty: number;
  status: string;
  createdAt: number;
  note?: string;
  attachments?: string[]; // Array of base64 strings
}

export interface MasterItem {
  id?: number;
  name: string;
}

export class OrderTrackerDB extends Dexie {
  orders!: Table<Order>;
  customersMaster!: Table<MasterItem>;
  citiesMaster!: Table<MasterItem>;
  materialsMaster!: Table<MasterItem>;

  constructor() {
    super('OrderTrackerDB');
    // Define the database version and schema using the inherited 'version' method.
    this.version(4).stores({
      orders: '++id, customer, city, material, qty, status, createdAt',
      customersMaster: '++id, &name',
      citiesMaster: '++id, &name',
      materialsMaster: '++id, &name'
    });
  }
}

export const db = new OrderTrackerDB();

const CACHE_NAME = 'order-tracker-v3';
const CORE_ASSETS = [
  './',
  'index.html',
  'manifest.json',
  'https://cdn.tailwindcss.com',
  'https://cdnjs.cloudflare.com/ajax/libs/PapaParse/5.4.1/papaparse.min.js'
];

// Install Event - Only cache the essential shell
self.addEventListener('install', (event) => {
  self.skipWaiting();
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      return cache.addAll(CORE_ASSETS);
    })
  );
});

// Activate Event - Clean up old caches
self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((cacheNames) => {
      return Promise.all(
        cacheNames.map((cache) => {
          if (cache !== CACHE_NAME) {
            return caches.delete(cache);
          }
        })
      );
    }).then(() => self.clients.claim())
  );
});

// Fetch Event - Stale-While-Revalidate Strategy
self.addEventListener('fetch', (event) => {
  // Only handle GET requests
  if (event.request.method !== 'GET') return;

  event.respondWith(
    caches.match(event.request).then((cachedResponse) => {
      const fetchPromise = fetch(event.request).then((networkResponse) => {
        // Cache valid responses from our own origin or specific CDNs
        if (
          networkResponse && 
          networkResponse.status === 200 && 
          (event.request.url.startsWith(self.location.origin) || 
           event.request.url.includes('cdn.tailwindcss.com') ||
           event.request.url.includes('cdnjs.cloudflare.com'))
        ) {
          const responseToCache = networkResponse.clone();
          caches.open(CACHE_NAME).then((cache) => {
            cache.put(event.request, responseToCache);
          });
        }
        return networkResponse;
      }).catch(() => {
        // Fallback for offline if not in cache
        return null;
      });

      return cachedResponse || fetchPromise;
    })
  );
});

const CACHE_NAME = 'order-tracker-v4';
const CORE_ASSETS = [
  'index.html',
  'manifest.json'
];

// Install Event
self.addEventListener('install', (event) => {
  self.skipWaiting();
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      // Use relative paths for local assets
      return cache.addAll(CORE_ASSETS);
    })
  );
});

// Activate Event
self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((cacheNames) => {
      return Promise.all(
        cacheNames.map((cache) => {
          if (cache !== CACHE_NAME) {
            return caches.delete(cache);
          }
        })
      );
    }).then(() => self.clients.claim())
  );
});

// Fetch Event
self.addEventListener('fetch', (event) => {
  if (event.request.method !== 'GET') return;

  event.respondWith(
    caches.match(event.request).then((cachedResponse) => {
      if (cachedResponse) return cachedResponse;

      return fetch(event.request).then((networkResponse) => {
        // Cache external CDNs and local assets on the fly
        const isSafeToCache = 
          networkResponse.status === 200 && 
          (event.request.url.includes('cdn.tailwindcss.com') || 
           event.request.url.includes('cdnjs.cloudflare.com') ||
           event.request.url.startsWith(self.location.origin));

        if (isSafeToCache) {
          const responseToCache = networkResponse.clone();
          caches.open(CACHE_NAME).then((cache) => {
            cache.put(event.request, responseToCache);
          });
        }
        return networkResponse;
      }).catch(() => {
        // Return index.html for navigation requests (SPA support)
        if (event.request.mode === 'navigate') {
          return caches.match('index.html');
        }
        return null;
      });
    })
  );
});

