const CACHE_NAME = 'order-tracker-v6';
const ASSETS_TO_CACHE = [
  'index.html',
  'manifest.json',
  'https://cdn.tailwindcss.com',
  'https://cdnjs.cloudflare.com/ajax/libs/PapaParse/5.4.1/papaparse.min.js'
];

self.addEventListener('install', (event) => {
  self.skipWaiting();
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      // Cache the base path and index.html explicitly to ensure offline start
      return cache.addAll(['./', 'index.html', ...ASSETS_TO_CACHE.slice(1)]);
    })
  );
});

self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((keys) => {
      return Promise.all(
        keys.map((key) => {
          if (key !== CACHE_NAME) return caches.delete(key);
        })
      );
    }).then(() => self.clients.claim())
  );
});

self.addEventListener('fetch', (event) => {
  if (event.request.method !== 'GET') return;

  const url = new URL(event.request.url);

  // Strategy: Cache First, then Network
  event.respondWith(
    caches.match(event.request, { ignoreSearch: true }).then((response) => {
      if (response) return response;

      // Handle navigation requests specifically for GitHub Pages subdirectories
      if (event.request.mode === 'navigate') {
        return caches.match('index.html');
      }

      return fetch(event.request).then((networkResponse) => {
        if (!networkResponse || networkResponse.status !== 200 || networkResponse.type !== 'basic') {
          return networkResponse;
        }

        // Cache successful local requests and essential CDNs
        if (url.origin === self.location.origin || url.hostname.includes('tailwindcss.com') || url.hostname.includes('cloudflare.com')) {
          const responseToCache = networkResponse.clone();
          caches.open(CACHE_NAME).then((cache) => {
            cache.put(event.request, responseToCache);
          });
        }

        return networkResponse;
      }).catch(() => {
        // Final fallback for navigation requests if both cache and network fail
        if (event.request.mode === 'navigate') {
          return caches.match('index.html');
        }
        return null;
      });
    })
  );
});

