// Fetch Event: Cache-first for assets, Navigation-fallback for UI
self.addEventListener('fetch', (event) => {
  if (event.request.method !== 'GET') return;

  const url = new URL(event.request.url);

  // For navigation requests (like clicking a link or refreshing), 
  // try the network first, but fall back to cached index.html if offline or 404
  if (event.request.mode === 'navigate') {
    event.respondWith(
      fetch(event.request).catch(() => {
        return caches.match('index.html') || caches.match('./');
      })
    );
    return;
  }

  // For all other assets (JS, CSS, Images, CDNs)
  event.respondWith(
    caches.match(event.request).then((response) => {
      if (response) return response;

      return fetch(event.request).then((networkResponse) => {
        // Cache external CDNs and local project files
        const isSafeToCache = 
          networkResponse.status === 200 && 
          (url.origin === self.location.origin || 
           url.hostname.includes('tailwindcss.com') || 
           url.hostname.includes('cloudflare.com'));

        if (isSafeToCache) {
          const responseToCache = networkResponse.clone();
          caches.open(CACHE_NAME).then((cache) => {
            cache.put(event.request, responseToCache);
          });
        }
        return networkResponse;
      }).catch(() => null);
    })
  );
});

