                        </div>
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {order.note && (
                <div className="bg-amber-50/50 p-3 rounded-2xl text-xs font-medium text-amber-900 mb-4 border border-amber-100 italic">
                  "{order.note}"
