      <section className="bg-white p-8 rounded-[2.5rem] shadow-xl border border-gray-100">
        <div className="flex items-center gap-4 mb-8">
          <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-indigo-200">
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M3 15a4 4 0 004 4h9a5 5 0 10-.1-9.999 5.002 5.002 0 10-9.78 2.096A4.001 4.001 0 003 15z" /></svg>
          </div>
          <div>
            <h3 className="text-2xl font-black text-gray-900 leading-tight">Supabase Synchronization</h3>
            <p className="text-sm text-gray-500 font-medium">Bi-directional Push/Pull sync logic.</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8 bg-indigo-50/50 p-4 rounded-2xl border border-indigo-100/50">
          <div className="space-y-1">
            <h5 className="text-xs font-black text-indigo-900 uppercase">Push (Local → Cloud)</h5>
            <p className="text-[11px] text-indigo-700 leading-tight">Syncs any local changes made since your last connection to Supabase.</p>
          </div>
          <div className="space-y-1">
            <h5 className="text-xs font-black text-indigo-900 uppercase">Pull (Cloud → Local)</h5>
            <p className="text-[11px] text-indigo-700 leading-tight">Downloads updates made on other devices or directly in the cloud dashboard.</p>
          </div>
        </div>

        <div className="space-y-4 mb-8">
          <div>
            <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1.5 ml-1">Supabase Project URL</label>
            <input 
              type="text" 
              value={cloudConfig.url} 
