            </div>
          </div>
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-3 uppercase tracking-wide">Attachments</label>
            <div className="grid grid-cols-4 gap-3">
              {formData.attachments.map((src, idx) => (
