                    )}
                  </div>
                  <h3 className="text-2xl font-black text-gray-900 leading-none">{order.customer}</h3>
                </div>
                <div className="bg-indigo-600 rounded-2xl p-4 min-w-[70px] text-center shadow-lg shadow-indigo-100">
