import React, { useState, useEffect, useRef } from 'react';
import { db, Order } from '../db';
import AutocompleteInput from './AutocompleteInput';
import { StorageMode } from '../types';
import { saveOrder } from '../services/orderService';

interface Props {
  mode: StorageMode;
  editId?: number | null;
  onSuccess: () => void;
  onCancel: () => void;
}

const STATUS_OPTIONS = ['Pending', 'Processing', 'Shipped', 'Delivered', 'Cancelled'];

const AddOrder: React.FC<Props> = ({ mode, editId, onSuccess, onCancel }) => {
  const [formData, setFormData] = useState<{
    uuid: string;
    customer: string;
    city: string;
    material: string;
    qty: number;
    status: string;
    note: string;
    attachments: string[];
    createdAt?: number;
  }>({
    uuid: crypto.randomUUID(),
    customer: '',
    city: '',
    material: '',
    qty: 0,
    status: 'Pending',
    note: '',
    attachments: []
  });

  const [isProcessingImages, setIsProcessingImages] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [options, setOptions] = useState<{ customers: string[], cities: string[], materials: string[] }>({
    customers: [],
    cities: [],
    materials: []
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const loadOptions = async () => {
      const orders = await db.orders.toArray();
      const masterCustomers = await db.customersMaster.toArray();
      const masterCities = await db.citiesMaster.toArray();
      const masterMaterials = await db.materialsMaster.toArray();

      const distinct = (arr: string[]) => Array.from(new Set(arr.filter(Boolean).map(s => s.trim()))).sort();

      setOptions({
        customers: distinct([...orders.map(o => o.customer), ...masterCustomers.map(c => c.name)]),
        cities: distinct([...orders.map(o => o.city), ...masterCities.map(c => c.name)]),
        materials: distinct([...orders.map(o => o.material), ...masterMaterials.map(m => m.name)]),
      });
    };
    loadOptions();

    if (editId) {
      if (mode === StorageMode.OFFLINE) {
        db.orders.get(editId).then(order => {
          if (order) {
            setFormData({
              uuid: order.uuid || crypto.randomUUID(), 
              customer: order.customer,
              city: order.city,
              material: order.material,
              qty: order.qty,
              status: order.status || 'Pending',
              note: order.note || '',
              attachments: order.attachments || [],
              createdAt: order.createdAt
            });
          }
        });
      } else {
        // Logic to fetch single order from cloud if editing in online mode
        // For now, assume editId is valid and handled by the list component passing full data if needed
      }
    }
  }, [editId, mode]);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    setIsProcessingImages(true);
    try {
      const readFileAsDataURL = (file: File): Promise<string> => {
        return new Promise((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = () => resolve(reader.result as string);
          reader.onerror = (error) => reject(error);
          reader.readAsDataURL(file);
        });
      };

      const downscaleImage = (dataUrl: string, maxWidth = 1200, quality = 0.7): Promise<string> => {
        return new Promise((resolve) => {
          const img = new Image();
          img.src = dataUrl;
          img.onload = () => {
            const canvas = document.createElement('canvas');
            let width = img.width;
            let height = img.height;
            if (width > maxWidth) {
              height = (maxWidth / width) * height;
              width = maxWidth;
            }
            canvas.width = width;
            canvas.height = height;
            const ctx = canvas.getContext('2d');
            ctx?.drawImage(img, 0, 0, width, height);
            resolve(canvas.toDataURL('image/jpeg', quality));
          };
          img.onerror = () => resolve(dataUrl);
        });
      };

      const rawDataUrls = await Promise.all(
        Array.from(files).map(file => readFileAsDataURL(file as File))
      );
      const optimizedAttachments = await Promise.all(
        rawDataUrls.map(url => downscaleImage(url))
      );
      setFormData(prev => ({
        ...prev,
        attachments: [...prev.attachments, ...optimizedAttachments]
      }));
    } catch (err) {
      console.error("Error reading files:", err);
    } finally {
      setIsProcessingImages(false);
      if (e.target) e.target.value = '';
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (isSaving) return;

    const { uuid, customer, city, material, qty, status, note, attachments, createdAt } = formData;

    if (!customer.trim() || !city.trim() || !material.trim() || qty <= 0) {
      alert("Please fill all required fields.");
      return;
    }

    setIsSaving(true);
    const now = Date.now();
    const finalCreatedAt = (editId && createdAt && !isNaN(createdAt)) ? createdAt : now;

    const orderData: Order = {
      uuid: uuid || crypto.randomUUID(),
      customer: customer.trim(),
      city: city.trim(),
      material: material.trim(),
      qty: Number(qty),
      status: status,
      note: note.trim(),
      attachments,
      createdAt: finalCreatedAt,
      updatedAt: now 
    };

    try {
      await saveOrder(mode, orderData, editId);
      onSuccess();
    } catch (err: any) {
      console.error(err);
      alert(`Save failed: ${err.message}`);
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div className="max-w-xl mx-auto">
      <div className="bg-white rounded-3xl shadow-xl p-8 border border-gray-100">
        <header className="mb-8 flex justify-between items-start">
          <div>
            <h2 className="text-3xl font-black text-gray-900 leading-tight">
              {editId ? 'Modify Record' : 'Create Entry'}
            </h2>
            <p className="text-gray-500 font-medium">Mode: {mode === StorageMode.ONLINE ? 'Cloud' : 'Local'}</p>
          </div>
          <div className={`w-3 h-3 rounded-full ${mode === StorageMode.ONLINE ? 'bg-blue-600' : 'bg-emerald-500'}`}></div>
        </header>

        <form onSubmit={handleSubmit} className="space-y-6">
          <AutocompleteInput
            label="Customer Name"
            value={formData.customer}
            onChange={(val) => setFormData({ ...formData, customer: val })}
            options={options.customers}
            placeholder="e.g. Acme Corp"
            required
          />
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
            <AutocompleteInput
              label="City / Destination"
              value={formData.city}
              onChange={(val) => setFormData({ ...formData, city: val })}
              options={options.cities}
              placeholder="e.g. New York"
              required
            />
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2 uppercase tracking-wide">Quantity</label>
              <input
                type="number"
                value={formData.qty || ''}
                onChange={(e) => setFormData({ ...formData, qty: Number(e.target.value) })}
                className="w-full px-4 py-3 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-indigo-500 shadow-inner font-bold"
                required
                min="1"
              />
            </div>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
            <AutocompleteInput
              label="Material"
              value={formData.material}
              onChange={(val) => setFormData({ ...formData, material: val })}
              options={options.materials}
              placeholder="e.g. Steel"
              required
            />
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2 uppercase tracking-wide">Status</label>
              <select
                value={formData.status}
                onChange={(e) => setFormData({ ...formData, status: e.target.value })}
                className="w-full px-4 py-3 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-indigo-500 shadow-inner font-bold"
              >
                {STATUS_OPTIONS.map(opt => <option key={opt} value={opt}>{opt}</option>)}
              </select>
            </div>
          </div>
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-3 uppercase tracking-wide">Attachments</label>
            <div className="grid grid-cols-4 gap-3">
              {formData.attachments.map((src, idx) => (
                <div key={idx} className="relative aspect-square rounded-xl overflow-hidden border border-gray-100 group">
                  <img src={src} className="w-full h-full object-cover" alt="attachment" />
                  <button 
                    type="button"
                    onClick={() => setFormData(p => ({ ...p, attachments: p.attachments.filter((_, i) => i !== idx) }))}
                    className="absolute top-1 right-1 bg-red-500 text-white p-1 rounded-full opacity-0 group-hover:opacity-100 transition-opacity"
                  >
                    <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
                  </button>
                </div>
              ))}
              <button
                type="button"
                onClick={() => fileInputRef.current?.click()}
                disabled={isProcessingImages}
                className="aspect-square rounded-xl border-2 border-dashed border-gray-200 text-gray-400 hover:bg-indigo-50 flex items-center justify-center disabled:opacity-50"
              >
                {isProcessingImages ? (
                   <div className="w-5 h-5 border-2 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
                ) : (
                   <svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M12 4v16m8-8H4" strokeWidth={2} /></svg>
                )}
              </button>
            </div>
            <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept="image/*" multiple />
          </div>
          <textarea
            value={formData.note}
            onChange={(e) => setFormData({ ...formData, note: e.target.value })}
            className="w-full px-4 py-3 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-indigo-500 shadow-inner min-h-[80px]"
            placeholder="Notes..."
          />
          <div className="flex gap-3 pt-6">
            <button 
              type="submit" 
              disabled={isSaving}
              className={`flex-[2] text-white font-black py-4 rounded-2xl shadow-lg transition-all active:scale-95 disabled:opacity-50 ${mode === StorageMode.ONLINE ? 'bg-blue-600 hover:bg-blue-700' : 'bg-indigo-600 hover:bg-indigo-700'}`}
            >
              {isSaving ? 'Saving...' : 'Save Record'}
            </button>
            <button type="button" onClick={onCancel} className="flex-1 bg-gray-100 text-gray-600 font-bold py-4 rounded-2xl hover:bg-gray-200 transition-colors">Cancel</button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default AddOrder;

import React, { useState, useMemo, useEffect } from 'react';
import { db, Order } from '../db';
import { useLiveQuery } from 'dexie-react-hooks';
import { StorageMode } from '../types';
import { getOrders, deleteOrder } from '../services/orderService';

interface Props {
  mode: StorageMode;
  onEdit: (id: number) => void;
}

const STATUS_OPTIONS = ['Pending', 'Processing', 'Shipped', 'Delivered', 'Cancelled'];

const getStatusColor = (status: string) => {
  switch (status) {
    case 'Pending': return 'bg-yellow-50 text-yellow-600 border-yellow-100';
    case 'Processing': return 'bg-blue-50 text-blue-600 border-blue-100';
    case 'Shipped': return 'bg-indigo-50 text-indigo-600 border-indigo-100';
    case 'Delivered': return 'bg-green-50 text-green-600 border-green-100';
    case 'Cancelled': return 'bg-red-50 text-red-600 border-red-100';
    default: return 'bg-gray-50 text-gray-600 border-gray-100';
  }
};

const OrdersList: React.FC<Props> = ({ mode, onEdit }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCity, setFilterCity] = useState('');
  const [filterCustomer, setFilterCustomer] = useState('');
  const [filterMaterial, setFilterMaterial] = useState('');
  const [filterStatus, setFilterStatus] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  const [onlineOrders, setOnlineOrders] = useState<Order[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [galleryState, setGalleryState] = useState<{ images: string[], index: number } | null>(null);

  // Local data is live
  const localOrders = useLiveQuery(() => 
    db.orders.filter(o => o.deleted !== 1).reverse().sortBy('createdAt')
  );

  const fetchOnline = async () => {
    if (mode !== StorageMode.ONLINE) return;
    setIsLoading(true);
    try {
      const data = await getOrders(StorageMode.ONLINE);
      setOnlineOrders(data);
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (mode === StorageMode.ONLINE) {
      fetchOnline();
    }
  }, [mode]);

  const activeOrders = mode === StorageMode.OFFLINE ? (localOrders || []) : onlineOrders;

  const cities = useMemo(() => Array.from(new Set(activeOrders.map(o => o.city.trim()))).sort() as string[], [activeOrders]);
  const customers = useMemo(() => Array.from(new Set(activeOrders.map(o => o.customer.trim()))).sort() as string[], [activeOrders]);
  const materials = useMemo(() => Array.from(new Set(activeOrders.map(o => o.material.trim()))).sort() as string[], [activeOrders]);

  const filteredOrders = useMemo(() => {
    return activeOrders.filter(o => {
      const searchStr = searchTerm.toLowerCase().trim();
      const matchesSearch = !searchStr || 
        o.customer.toLowerCase().includes(searchStr) ||
        o.city.toLowerCase().includes(searchStr) ||
        o.material.toLowerCase().includes(searchStr) ||
        (o.note && o.note.toLowerCase().includes(searchStr));

      const matchesCity = !filterCity || o.city.trim() === filterCity;
      const matchesCustomer = !filterCustomer || o.customer.trim() === filterCustomer;
      const matchesMaterial = !filterMaterial || o.material.trim() === filterMaterial;
      const matchesStatus = !filterStatus || o.status === filterStatus;

      const orderDate = new Date(o.createdAt).setHours(0,0,0,0);
      const start = startDate ? new Date(startDate).setHours(0,0,0,0) : null;
      const end = endDate ? new Date(endDate).setHours(23,59,59,999) : null;

      const matchesStart = !start || orderDate >= start;
      const matchesEnd = !end || orderDate <= end;

      return matchesSearch && matchesCity && matchesCustomer && matchesMaterial && matchesStatus && matchesStart && matchesEnd;
    });
  }, [activeOrders, searchTerm, filterCity, filterCustomer, filterMaterial, filterStatus, startDate, endDate]);

  const hasActiveFilters = searchTerm || filterCity || filterCustomer || filterMaterial || filterStatus || startDate || endDate;

  const handleDelete = async (order: Order) => {
    if (confirm(`Delete record for ${order.customer}?`)) {
      try {
        await deleteOrder(mode, order.id!, order.uuid);
        if (mode === StorageMode.ONLINE) fetchOnline();
      } catch (err: any) {
        alert("Delete failed: " + err.message);
      }
    }
  };

  return (
    <div className="space-y-6">
      {/* Search and Advanced Filters */}
      <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-gray-100 sticky top-[80px] z-20 space-y-5">
        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="relative flex-1 w-full">
            <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400">
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
            </span>
            <input
              type="text"
              placeholder={`Search ${mode === StorageMode.ONLINE ? 'cloud' : 'local'} history...`}
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-12 pr-4 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-indigo-500 shadow-inner font-bold text-gray-900"
            />
          </div>
          <div className="flex gap-2 w-full md:w-auto">
            {mode === StorageMode.ONLINE && (
              <button 
                onClick={fetchOnline}
                disabled={isLoading}
                className="p-4 bg-blue-50 text-blue-600 rounded-2xl hover:bg-blue-100 transition-colors disabled:opacity-50"
              >
                <svg className={`w-6 h-6 ${isLoading ? 'animate-spin' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
              </button>
            )}
            {hasActiveFilters && (
              <button 
                onClick={() => { setSearchTerm(''); setFilterCity(''); setFilterCustomer(''); setFilterMaterial(''); setFilterStatus(''); setStartDate(''); setEndDate(''); }} 
                className="px-6 py-4 bg-gray-50 text-gray-400 rounded-2xl font-black text-sm whitespace-nowrap hover:bg-gray-100 transition-colors"
              >
                Reset
              </button>
            )}
          </div>
        </div>

        <div className="grid grid-cols-2 lg:grid-cols-6 gap-3">
          <div className="flex flex-col">
             <label className="text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Customer</label>
             <select value={filterCustomer} onChange={(e) => setFilterCustomer(e.target.value)} className="px-3 py-2.5 bg-white border border-gray-100 rounded-xl text-xs font-bold shadow-sm focus:ring-2 focus:ring-indigo-500 outline-none cursor-pointer">
                <option value="">All Clients</option>
                {customers.map(c => <option key={c} value={c}>{c}</option>)}
             </select>
          </div>
          <div className="flex flex-col">
             <label className="text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Status</label>
             <select value={filterStatus} onChange={(e) => setFilterStatus(e.target.value)} className="px-3 py-2.5 bg-white border border-gray-100 rounded-xl text-xs font-bold shadow-sm focus:ring-2 focus:ring-indigo-500 outline-none cursor-pointer">
                <option value="">All Statuses</option>
                {STATUS_OPTIONS.map(s => <option key={s} value={s}>{s}</option>)}
             </select>
          </div>
          <div className="flex flex-col">
             <label className="text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Location</label>
             <select value={filterCity} onChange={(e) => setFilterCity(e.target.value)} className="px-3 py-2.5 bg-white border border-gray-100 rounded-xl text-xs font-bold shadow-sm focus:ring-2 focus:ring-indigo-500 outline-none cursor-pointer">
                <option value="">All Cities</option>
                {cities.map(c => <option key={c} value={c}>{c}</option>)}
             </select>
          </div>
          <div className="flex flex-col">
             <label className="text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Material</label>
             <select value={filterMaterial} onChange={(e) => setFilterMaterial(e.target.value)} className="px-3 py-2.5 bg-white border border-gray-100 rounded-xl text-xs font-bold shadow-sm focus:ring-2 focus:ring-indigo-500 outline-none cursor-pointer">
                <option value="">All Materials</option>
                {materials.map(m => <option key={m} value={m}>{m}</option>)}
             </select>
          </div>
          <div className="flex flex-col">
             <label className="text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">From</label>
             <input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="px-3 py-2.5 bg-white border border-gray-100 rounded-xl text-xs font-bold shadow-sm focus:ring-2 focus:ring-indigo-500 outline-none" />
          </div>
          <div className="flex flex-col">
             <label className="text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">To</label>
             <input type="date" value={endDate} onChange={(e) => setEndDate(e.target.value)} className="px-3 py-2.5 bg-white border border-gray-100 rounded-xl text-xs font-bold shadow-sm focus:ring-2 focus:ring-indigo-500 outline-none" />
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pb-24">
        {isLoading ? (
           <div className="col-span-full py-24 text-center">
              <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
              <p className="text-blue-600 font-black uppercase tracking-widest text-sm">Accessing Cloud Storage...</p>
           </div>
        ) : filteredOrders.length === 0 ? (
          <div className="col-span-full py-24 text-center bg-white rounded-[3rem] border-2 border-dashed border-gray-100">
            <p className="text-gray-300 font-black text-xl italic uppercase tracking-widest">No Matches Found</p>
          </div>
        ) : (
          filteredOrders.map(order => (
            <div key={order.uuid} className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-gray-50 flex flex-col hover:shadow-xl hover:shadow-indigo-100/30 transition-all duration-300 group">
              <div className="flex justify-between items-start mb-4">
                <div className="flex-1">
                  <div className="flex flex-wrap items-center gap-2 mb-2">
                    <span className="text-[9px] font-black uppercase tracking-widest bg-indigo-50 text-indigo-600 px-2.5 py-1 rounded-full">
                      {order.city}
                    </span>
                    <span className={`text-[9px] font-black uppercase tracking-widest px-2.5 py-1 rounded-full border ${getStatusColor(order.status)}`}>
                      {order.status}
                    </span>
                  </div>
                  <h3 className="text-2xl font-black text-gray-900 leading-none">{order.customer}</h3>
                </div>
                <div className={`${mode === StorageMode.ONLINE ? 'bg-blue-600' : 'bg-indigo-600'} rounded-2xl p-4 min-w-[70px] text-center shadow-lg`}>
                  <span className="block text-[10px] opacity-70 text-white font-black uppercase tracking-tighter">Qty</span>
                  <span className="block text-2xl font-black text-white leading-none mt-1">{order.qty}</span>
                </div>
              </div>

              <div className="mb-4">
                <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest block mb-1">Material Details</span>
                <p className="text-sm font-bold text-gray-700 bg-gray-50 border border-gray-100 px-3 py-2 rounded-xl">{order.material}</p>
              </div>

              {order.attachments && order.attachments.length > 0 && (
                <div className="mb-4">
                  <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
                    {order.attachments.map((src, idx) => (
                      <button 
                        key={idx}
                        onClick={() => setGalleryState({ images: order.attachments!, index: idx })}
                        className="relative w-20 h-20 rounded-2xl overflow-hidden border-2 border-white shadow-sm flex-shrink-0 group/img hover:scale-105 transition-transform"
                      >
                        <img src={src} className="w-full h-full object-cover" alt="attachment" loading="lazy" />
                      </button>
                    ))}
                  </div>
                </div>
              )}

              <div className="mt-auto pt-4 border-t border-gray-50 flex items-center justify-between">
                <span className="text-[10px] font-black text-gray-300 uppercase tracking-widest">
                  {new Date(order.createdAt).toLocaleDateString()}
                </span>
                <div className="flex gap-2">
                  <button onClick={() => onEdit(order.id!)} className="p-3 bg-gray-50 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all">
                    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
                  </button>
                  <button onClick={() => handleDelete(order)} className="p-3 bg-gray-50 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all">
                    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                  </button>
                </div>
              </div>
            </div>
          ))
        )}
      </div>

      {galleryState && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-md flex flex-col items-center justify-center p-4 animate-in fade-in duration-300" onClick={() => setGalleryState(null)}>
           <div className="relative w-full max-w-4xl flex flex-col items-center gap-6" onClick={e => e.stopPropagation()}>
              <img src={galleryState.images[galleryState.index]} className="max-w-full max-h-[75vh] object-contain rounded-2xl shadow-2xl" alt="Proof" />
              <button onClick={() => setGalleryState(null)} className="px-8 py-3 bg-white/10 text-white rounded-full border border-white/20 font-black uppercase tracking-widest text-sm hover:bg-white/20">Close</button>
           </div>
        </div>
      )}
    </div>
  );
};

export default OrdersList;

import React, { useState, useMemo, useEffect } from 'react';
import { db, Order } from '../db';
import { useLiveQuery } from 'dexie-react-hooks';
import { SummaryRow, StorageMode } from '../types';
import { getOrders } from '../services/orderService';

interface Props {
  mode: StorageMode;
}

const STATUS_OPTIONS = ['Pending', 'Processing', 'Shipped', 'Delivered', 'Cancelled'];

const Summary: React.FC<Props> = ({ mode }) => {
  const [filterCity, setFilterCity] = useState('');
  const [filterCustomer, setFilterCustomer] = useState('');
  const [filterMaterial, setFilterMaterial] = useState('');
  const [filterStatus, setFilterStatus] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  const [onlineOrders, setOnlineOrders] = useState<Order[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  // Local data is live
  const localOrders = useLiveQuery(() => db.orders.filter(o => o.deleted !== 1).toArray());

  useEffect(() => {
    const fetch = async () => {
      if (mode === StorageMode.ONLINE) {
        setIsLoading(true);
        try {
          const data = await getOrders(StorageMode.ONLINE);
          setOnlineOrders(data);
        } catch (err) {
          console.error(err);
        } finally {
          setIsLoading(false);
        }
      }
    };
    fetch();
  }, [mode]);

  const activeOrders = mode === StorageMode.OFFLINE ? (localOrders || []) : onlineOrders;

  const filteredOrders = useMemo(() => {
    return activeOrders.filter(o => {
      const cityMatch = !filterCity || o.city.trim() === filterCity;
      const customerMatch = !filterCustomer || o.customer.trim() === filterCustomer;
      const materialMatch = !filterMaterial || o.material.trim() === filterMaterial;
      const statusMatch = !filterStatus || o.status === filterStatus;

      const orderDate = new Date(o.createdAt).setHours(0,0,0,0);
      const start = startDate ? new Date(startDate).setHours(0,0,0,0) : null;
      const end = endDate ? new Date(endDate).setHours(23,59,59,999) : null;

      const matchesStart = !start || orderDate >= start;
      const matchesEnd = !end || orderDate <= end;

      return cityMatch && customerMatch && materialMatch && statusMatch && matchesStart && matchesEnd;
    });
  }, [activeOrders, filterCity, filterCustomer, filterMaterial, filterStatus, startDate, endDate]);

  const summaryData = useMemo(() => {
    const groups: Record<string, SummaryRow> = {};
    filteredOrders.forEach(o => {
      const key = `${o.city.trim()}|${o.customer.trim()}|${o.material.trim()}`;
      if (!groups[key]) {
        groups[key] = {
          city: o.city.trim(),
          customer: o.customer.trim(),
          material: o.material.trim(),
          orderCount: 0,
          totalQty: 0
        };
      }
      groups[key].orderCount += 1;
      groups[key].totalQty += o.qty;
    });
    return Object.values(groups).sort((a, b) => b.totalQty - a.totalQty);
  }, [filteredOrders]);

  const stats = useMemo(() => {
    return {
      totalOrders: filteredOrders.length,
      totalQty: filteredOrders.reduce((sum, o) => sum + o.qty, 0),
      uniqueCustomers: new Set(filteredOrders.map(o => o.customer.trim())).size
    };
  }, [filteredOrders]);

  const cities = useMemo(() => Array.from(new Set(activeOrders.map(o => o.city.trim()))).sort() as string[], [activeOrders]);
  const customers = useMemo(() => Array.from(new Set(activeOrders.map(o => o.customer.trim()))).sort() as string[], [activeOrders]);
  const materials = useMemo(() => Array.from(new Set(activeOrders.map(o => o.material.trim()))).sort() as string[], [activeOrders]);

  if (isLoading) return <div className="p-12 text-center text-blue-600 font-black animate-pulse">Querying Cloud Datastore...</div>;

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-50">
          <p className="text-[10px] font-black uppercase tracking-widest text-gray-400 mb-1">Total Orders</p>
          <p className={`text-3xl font-black ${mode === StorageMode.ONLINE ? 'text-blue-600' : 'text-indigo-600'}`}>{stats.totalOrders}</p>
        </div>
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-50">
          <p className="text-[10px] font-black uppercase tracking-widest text-gray-400 mb-1">Accumulated Qty</p>
          <p className={`text-3xl font-black ${mode === StorageMode.ONLINE ? 'text-blue-600' : 'text-indigo-600'}`}>{stats.totalQty.toLocaleString()}</p>
        </div>
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-50">
          <p className="text-[10px] font-black uppercase tracking-widest text-gray-400 mb-1">Unique Clients</p>
