import React, { useState, useEffect } from 'react';
import { db } from '../db';
import { exportToCSV, parseCSV } from '../services/csvService';
import { saveSyncConfig, getSyncConfig, syncWithSupabase, clearSupabaseData, getDeletedCount, purgeLocalDeletedRecords } from '../services/syncService';

const Backup: React.FC = () => {
  const [importing, setImporting] = useState(false);
  const [exporting, setExporting] = useState(false);
  const [syncing, setSyncing] = useState(false);
  const [clearingCloud, setClearingCloud] = useState(false);
  const [purging, setPurging] = useState(false);
  const [lastSync, setLastSync] = useState<string | null>(null);
  const [deletedCount, setDeletedCount] = useState(0);

  const [cloudConfig, setCloudConfig] = useState({
    url: '',
    publishableKey: ''
  });

  useEffect(() => {
    const config = getSyncConfig();
    if (config) setCloudConfig(config);
    setLastSync(localStorage.getItem('order_tracker_last_sync_time'));
    refreshStats();
  }, []);

  const refreshStats = async () => {
    const count = await getDeletedCount();
    setDeletedCount(count);
  };

  const handleSaveConfig = () => {
    if (!cloudConfig.url || !cloudConfig.publishableKey) {
      alert("Please provide both Supabase URL and Publishable Key.");
      return;
    }
    saveSyncConfig(cloudConfig);
    alert("Configuration saved! You can now sync with your cloud database.");
  };

  const handleSyncNow = async () => {
    if (!cloudConfig.url) {
      alert("Please configure your cloud settings first.");
      return;
    }
    setSyncing(true);
    try {
      const result = await syncWithSupabase();
      setLastSync(localStorage.getItem('order_tracker_last_sync_time'));
      await refreshStats();
      alert(`Sync Successful!\n\n- Pushed ${result.pushed} local changes\n- Pulled ${result.pulled} cloud updates`);
    } catch (err: any) {
      console.error(err);
      alert(`Sync Failed: ${err.message}`);
    } finally {
      setSyncing(false);
    }
  };

  const handlePurge = async () => {
    if (deletedCount === 0) return;
    if (!confirm(`Purge ${deletedCount} deleted records from local storage? This action cannot be undone. Make sure you have synced first to ensure the cloud knows about these deletions!`)) return;

    setPurging(true);
    try {
      const purged = await purgeLocalDeletedRecords();
      alert(`Maintenance complete. Permanently removed ${purged} records.`);
      await refreshStats();
    } catch (err) {
      alert("Purge failed.");
    } finally {
      setPurging(false);
    }
  };

  const handleWipeCloud = async () => {
    if (!confirm("DANGER: This will permanently delete ALL records from your remote Supabase 'orders' table. Your local data will not be affected. Continue?")) return;

    setClearingCloud(true);
    try {
      await clearSupabaseData();
      alert("Cloud database cleared successfully.");
      setLastSync(null);
    } catch (err: any) {
      console.error(err);
      alert(`Failed to clear cloud: ${err.message}`);
    } finally {
      setClearingCloud(false);
    }
  };

  const handleExport = async () => {
    setExporting(true);
    try {
      const orders = await db.orders.toArray();
      if (orders.length === 0) {
        alert("No records to export.");
        return;
      }
      exportToCSV(orders, `order_tracker_pro_backup_${new Date().toISOString().split('T')[0]}.csv`);
    } catch (err) {
      alert("Export failed.");
    } finally {
      setExporting(false);
    }
  };

  const handleImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setImporting(true);
    try {
      const data = await parseCSV(file);
      if (!Array.isArray(data)) throw new Error("Invalid CSV data format.");

      let count = 0;
      for (const item of data) {
        if (!item.uuid) item.uuid = crypto.randomUUID();

        if (typeof item.attachments === 'string') {
          try {
            item.attachments = JSON.parse(item.attachments);
          } catch {
            item.attachments = [];
          }
        }

        const existing = await db.orders.where('uuid').equals(item.uuid).first();
        if (existing) {
          await db.orders.update(existing.id!, { ...item, updatedAt: Date.now() });
        } else {
          await db.orders.add({ ...item, updatedAt: Date.now() });
        }
        count++;
      }
      await refreshStats();
      alert(`Import complete! Processed ${count} records.`);
    } catch (err: any) {
      console.error(err);
      alert(`Import failed: ${err.message}`);
    } finally {
      setImporting(false);
      if (e.target) e.target.value = '';
    }
  };

  return (
    <div className="max-w-3xl mx-auto space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-700 pb-24">
      <header className="text-center">
        <h2 className="text-4xl font-black text-gray-900 mb-2 tracking-tight uppercase">Data & Cloud</h2>
        <p className="text-gray-500 font-medium italic">Advanced synchronization and recovery tools.</p>
      </header>

      {/* Cloud Connectivity Card */}
      <section className="bg-white p-8 rounded-[2.5rem] shadow-2xl shadow-indigo-100/50 border border-gray-100 relative overflow-hidden">
        <div className="absolute top-0 right-0 p-8 opacity-[0.03] pointer-events-none">
          <svg className="w-48 h-48" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm-1 17.93c-3.95-.49-7-3.85-7-7.93 0-.62.08-1.21.21-1.79L9 15v1c0 1.1.9 2 2 2v1.93zm6.9-2.54c-.26-.81-1-1.39-1.9-1.39h-1v-3c0-.55-.45-1-1-1H8v-2h2c.55 0 1-.45 1-1V7h2c1.1 0 2-.9 2-2v-.41c2.93 1.19 5 4.06 5 7.41 0 2.08-.8 3.97-2.1 5.39z"/></svg>
        </div>

        <div className="flex items-center gap-4 mb-8">
          <div className="w-14 h-14 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-indigo-200">
            <svg className="w-7 h-7" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M3 15a4 4 0 004 4h9a5 5 0 10-.1-9.999 5.002 5.002 0 10-9.78 2.096A4.001 4.001 0 003 15z" /></svg>
          </div>
          <div>
            <h3 className="text-2xl font-black text-gray-900 uppercase">Supabase Sync</h3>
            <p className="text-xs text-indigo-500 font-black uppercase tracking-[0.2em]">Secure Cloud Bridge</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-5 mb-10">
          <div className="group">
            <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1 transition-colors group-focus-within:text-indigo-600">Project Endpoint</label>
            <input 
              type="text" 
              value={cloudConfig.url} 
              onChange={e => setCloudConfig({ ...cloudConfig, url: e.target.value })}
              className="w-full px-5 py-4 bg-gray-50 border-2 border-transparent rounded-2xl focus:bg-white focus:border-indigo-100 focus:ring-4 focus:ring-indigo-50/50 transition-all font-medium text-sm"
              placeholder="https://xxxx.supabase.co"
            />
          </div>
          <div className="group">
            <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1 transition-colors group-focus-within:text-indigo-600">Anon Public Key</label>
            <input 
              type="password" 
              value={cloudConfig.publishableKey} 
              onChange={e => setCloudConfig({ ...cloudConfig, publishableKey: e.target.value })}
              className="w-full px-5 py-4 bg-gray-50 border-2 border-transparent rounded-2xl focus:bg-white focus:border-indigo-100 focus:ring-4 focus:ring-indigo-50/50 transition-all font-medium text-sm"
              placeholder="eyJhbG..."
            />
          </div>
          <div className="md:col-span-2">
            <button 
              onClick={handleSaveConfig}
              className="text-indigo-600 font-black text-xs hover:bg-indigo-50 px-6 py-3 rounded-xl transition-all border border-indigo-50 active:scale-95"
            >
              Update Cloud Credentials
            </button>
          </div>
        </div>

        <div className="bg-indigo-50/40 p-6 rounded-[2rem] border border-indigo-100/50 flex flex-col md:flex-row items-center gap-6">
          <button 
            onClick={handleSyncNow}
            disabled={syncing || !cloudConfig.url}
            className={`w-full md:w-auto py-5 px-10 rounded-2xl font-black text-xl shadow-2xl transition-all active:scale-95 flex items-center justify-center gap-4 ${
              syncing ? 'bg-indigo-300' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200'
            } text-white`}
          >
            {syncing ? (
              <div className="w-6 h-6 border-3 border-white/30 border-t-white rounded-full animate-spin"></div>
            ) : (
              <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
            )}
            {syncing ? 'Connecting...' : 'Sync Data Now'}
          </button>

          <div className="flex-1 text-center md:text-left">
            <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Status Report</p>
            <p className="text-base font-black text-gray-700">
              {lastSync ? `Last Sync: ${new Date(Number(lastSync)).toLocaleString()}` : 'No sync history found'}
            </p>
          </div>
        </div>
      </section>

      {/* CSV Operations Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
        <button 
          onClick={handleExport}
          disabled={exporting}
          className="bg-white p-8 rounded-[2.5rem] border border-gray-100 shadow-lg hover:shadow-emerald-100/40 transition-all flex flex-col items-center gap-5 text-center group active:scale-95"
        >
          <div className="w-20 h-20 bg-emerald-50 text-emerald-600 rounded-[2rem] flex items-center justify-center group-hover:bg-emerald-600 group-hover:text-white transition-all duration-300 shadow-inner">
            <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
            </svg>
          </div>
          <div>
            <h4 className="font-black text-gray-900 text-xl uppercase tracking-tight">Snapshot Export</h4>
            <p className="text-xs text-gray-500 font-medium mt-1">Download local database as .csv</p>
          </div>
        </button>

        <label className="bg-white p-8 rounded-[2.5rem] border border-gray-100 shadow-lg hover:shadow-amber-100/40 transition-all flex flex-col items-center gap-5 text-center cursor-pointer group active:scale-95">
          <input type="file" accept=".csv" className="hidden" onChange={handleImport} disabled={importing} />
          <div className="w-20 h-20 bg-amber-50 text-amber-600 rounded-[2rem] flex items-center justify-center group-hover:bg-amber-600 group-hover:text-white transition-all duration-300 shadow-inner">
            {importing ? (
              <div className="w-8 h-8 border-4 border-amber-600 group-hover:border-white border-t-transparent rounded-full animate-spin"></div>
            ) : (
              <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
              </svg>
            )}
          </div>
          <div>
            <h4 className="font-black text-gray-900 text-xl uppercase tracking-tight">{importing ? 'Importing...' : 'Restore Backup'}</h4>
            <p className="text-xs text-gray-500 font-medium mt-1">Upload and merge .csv history</p>
          </div>
        </label>
      </div>

      {/* Maintenance Section */}
      <section className="bg-white p-8 rounded-[2.5rem] border border-gray-100 shadow-sm flex flex-col md:flex-row items-center gap-6">
        <div className="w-16 h-16 bg-gray-50 text-gray-400 rounded-2xl flex items-center justify-center flex-shrink-0">
          <svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
        </div>
        <div className="flex-1 text-center md:text-left">
           <h4 className="font-black text-gray-900 text-lg uppercase tracking-tight">Local Storage Maintenance</h4>
           <p className="text-sm text-gray-500 font-medium">
             Permanently clear <span className="text-red-500 font-black">{deletedCount}</span> "deleted" markers from local memory.
           </p>
        </div>
        <button 
          onClick={handlePurge}
          disabled={purging || deletedCount === 0}
          className="px-8 py-4 bg-gray-900 text-white rounded-2xl font-black text-sm hover:bg-black transition-all active:scale-95 disabled:opacity-20 shadow-xl shadow-gray-200"
        >
          {purging ? 'Cleaning...' : 'Purge Deleted Data'}
        </button>
      </section>

      {/* Danger Zone */}
      <section className="bg-red-50/50 p-8 rounded-[2.5rem] border-2 border-dashed border-red-100 flex flex-col md:flex-row items-center justify-between gap-6">
        <div className="flex gap-4">
          <div className="w-12 h-12 bg-red-100 text-red-600 rounded-2xl flex items-center justify-center flex-shrink-0">
             <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
          </div>
          <div>
            <h4 className="text-red-900 font-black text-xl uppercase tracking-tight">Remote Reset</h4>
            <p className="text-red-700/70 text-sm font-medium">Permanently wipe all records from the remote cloud datastore.</p>
          </div>
        </div>
        <button 
          onClick={handleWipeCloud}
          disabled={clearingCloud || !cloudConfig.url}
          className="w-full md:w-auto px-8 py-4 bg-white text-red-600 border-2 border-red-100 font-black rounded-2xl hover:bg-red-600 hover:text-white transition-all shadow-sm active:scale-95 disabled:opacity-50"
        >
          {clearingCloud ? 'Processing...' : 'Wipe Cloud Database'}
        </button>
      </section>
    </div>
  );
};

export default Backup;

import React, { useState, useEffect } from 'react';
import { AppTab, StorageMode } from './types';
import AddOrder from './components/AddOrder';
import OrdersList from './components/OrdersList';
import Summary from './components/Summary';
import Backup from './components/Backup';
import MasterData from './components/MasterData';
import { getSyncConfig } from './services/syncService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.ADD_ORDER);
  const [editingOrderId, setEditingOrderId] = useState<number | null>(null);
  const [storageMode, setStorageMode] = useState<StorageMode>(() => {
    const saved = localStorage.getItem('app_storage_mode');
    return (saved as StorageMode) || StorageMode.OFFLINE;
  });

  useEffect(() => {
    localStorage.setItem('app_storage_mode', storageMode);
  }, [storageMode]);

  const toggleMode = () => {
    if (storageMode === StorageMode.OFFLINE) {
      const config = getSyncConfig();
      if (!config) {
        alert("Configuration Required: Please set up Supabase in the 'Cloud' tab to enable Online mode.");
        setActiveTab(AppTab.BACKUP);
        return;
      }
      setStorageMode(StorageMode.ONLINE);
    } else {
      setStorageMode(StorageMode.OFFLINE);
    }
  };

  const renderContent = () => {
    switch (activeTab) {
      case AppTab.ADD_ORDER:
        return <AddOrder 
          mode={storageMode}
          editId={editingOrderId} 
          onSuccess={() => {
            setEditingOrderId(null);
            setActiveTab(AppTab.ORDERS_LIST);
          }} 
          onCancel={() => {
            setEditingOrderId(null);
            setActiveTab(AppTab.ORDERS_LIST);
          }}
        />;
      case AppTab.ORDERS_LIST:
        return <OrdersList 
          mode={storageMode}
          onEdit={(id) => {
            setEditingOrderId(id);
            setActiveTab(AppTab.ADD_ORDER);
          }} 
        />;
      case AppTab.SUMMARY:
        return <Summary mode={storageMode} />;
      case AppTab.MASTER_DATA:
        return <MasterData mode={storageMode} />;
      case AppTab.BACKUP:
        return <Backup />;
      default:
        return <AddOrder 
          mode={storageMode}
          onSuccess={() => setActiveTab(AppTab.ORDERS_LIST)} 
          onCancel={() => setActiveTab(AppTab.ORDERS_LIST)} 
        />;
    }
  };

  const navItems = [
    { id: AppTab.ADD_ORDER, label: 'Add', icon: <PlusIcon className="w-6 h-6" /> },
    { id: AppTab.ORDERS_LIST, label: 'History', icon: <ListBulletIcon className="w-6 h-6" /> },
    { id: AppTab.SUMMARY, label: 'Stats', icon: <ChartBarIcon className="w-6 h-6" /> },
    { id: AppTab.MASTER_DATA, label: 'Manage', icon: <Cog6ToothIcon className="w-6 h-6" /> },
    { id: AppTab.BACKUP, label: 'Cloud', icon: <CloudArrowUpIcon className="w-6 h-6" /> },
  ];

  return (
    <div className={`flex flex-col min-h-screen transition-colors duration-500 ${storageMode === StorageMode.ONLINE ? 'bg-[#F0F7FF]' : 'bg-[#F8FAFC]'}`}>
      <header className="bg-white/90 border-b border-gray-100 px-6 py-4 sticky top-0 z-50 backdrop-blur-xl">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className={`w-11 h-11 shadow-2xl rounded-2xl overflow-hidden flex items-center justify-center transition-all duration-500 transform hover:scale-105 ${storageMode === StorageMode.ONLINE ? 'bg-blue-600 shadow-blue-200' : 'bg-indigo-600 shadow-indigo-200'}`}>
               <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100" className="w-full h-full p-2">
                  <path d="M30 40 L50 30 L70 40 L50 50 Z" fill="#fff" />
                  <path d="M30 40 V60 L50 70 V50 Z" fill="#e0e7ff" />
                  <path d="M70 40 V60 L50 70 V50 Z" fill="#c7d2fe" />
                  <circle cx="72" cy="72" r="18" fill="#fff" />
                  <path d="M64 72 L70 78 L80 68" fill="none" stroke={storageMode === StorageMode.ONLINE ? '#2563eb' : '#4f46e5'} strokeWidth="4" strokeLinecap="round" strokeLinejoin="round" />
               </svg>
            </div>
            <div>
              <h1 className="text-xl font-black text-gray-900 tracking-tight leading-none">ORDER TRACKER <span className={storageMode === StorageMode.ONLINE ? 'text-blue-600' : 'text-indigo-600'}>PRO</span></h1>
              <p className="text-[9px] font-black uppercase tracking-[0.3em] text-gray-400 mt-1">Enterprise Management</p>
            </div>
          </div>

          <div className="flex items-center gap-6">
            <div className="flex items-center bg-gray-100 p-1.5 rounded-[1.25rem] border border-gray-200 shadow-inner">
               <button 
                 onClick={() => setStorageMode(StorageMode.OFFLINE)}
                 className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-[0.15em] transition-all duration-300 ${storageMode === StorageMode.OFFLINE ? 'bg-white text-indigo-600 shadow-lg' : 'text-gray-400 hover:text-gray-600'}`}
               >
                 Local
               </button>
               <button 
                 onClick={toggleMode}
                 className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-[0.15em] transition-all duration-300 ${storageMode === StorageMode.ONLINE ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-400 hover:text-gray-600'}`}
               >
                 Cloud
               </button>
            </div>

            <div className="hidden md:flex gap-1">
               {navItems.map(item => (
                  <button 
                    key={item.id}
                    onClick={() => setActiveTab(item.id)}
                    className={`px-5 py-2.5 rounded-2xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === item.id ? (storageMode === StorageMode.ONLINE ? 'bg-blue-600 text-white shadow-xl shadow-blue-100' : 'bg-indigo-600 text-white shadow-xl shadow-indigo-100') : 'text-gray-500 hover:bg-gray-100 hover:text-gray-900'}`}
                  >
                    {item.label}
                  </button>
               ))}
            </div>
          </div>
        </div>
      </header>

      <main className="flex-1 pb-24 p-4 md:p-8 max-w-6xl mx-auto w-full animate-in fade-in zoom-in-95 duration-500">
        <div className="mb-8 flex items-center justify-center">
           <div className={`px-6 py-2.5 rounded-full border text-[10px] font-black uppercase tracking-[0.25em] flex items-center gap-3 shadow-md transition-all ${storageMode === StorageMode.ONLINE ? 'bg-blue-50 border-blue-100 text-blue-700' : 'bg-indigo-50 border-indigo-100 text-indigo-700'}`}>
              <div className={`w-2 h-2 rounded-full ${storageMode === StorageMode.ONLINE ? 'bg-blue-600 animate-ping' : 'bg-indigo-500'}`}></div>
              {storageMode === StorageMode.ONLINE ? 'Live Cloud Datastore' : 'Standalone Local Database'}
           </div>
        </div>
        {renderContent()}
      </main>

      <nav className="fixed bottom-6 left-1/2 -translate-x-1/2 w-[92%] max-w-md bg-white/80 backdrop-blur-2xl border border-white shadow-[0_20px_50px_rgba(0,0,0,0.1)] rounded-[2.5rem] flex justify-around p-2.5 z-50 md:hidden">
        {navItems.map((item) => (
          <button
            key={item.id}
            onClick={() => {
              setActiveTab(item.id);
              if (item.id !== AppTab.ADD_ORDER) setEditingOrderId(null);
            }}
            className={`flex flex-col items-center justify-center px-4 py-2.5 rounded-3xl transition-all duration-300 ${
              activeTab === item.id 
                ? (storageMode === StorageMode.ONLINE ? 'text-blue-600 bg-blue-50/50 scale-110 shadow-inner' : 'text-indigo-600 bg-indigo-50/50 scale-110 shadow-inner')
                : 'text-gray-400 hover:text-gray-600'
            }`}
          >
            {item.icon}
            <span className="text-[9px] mt-1.5 font-black uppercase tracking-widest">{item.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
};

