          <span className="w-12 h-1 bg-indigo-600 rounded-full"></span>
        </div>
      </header>

      {/* CSV Operations Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <button 
          onClick={handleExport}
          disabled={exporting}
          className="bg-white p-10 rounded-[3rem] border border-gray-100 shadow-2xl shadow-gray-200/50 hover:shadow-indigo-100 transition-all flex flex-col items-center gap-6 text-center group active:scale-95"
        >
          <div className="w-24 h-24 bg-indigo-50 text-indigo-600 rounded-[2.5rem] flex items-center justify-center group-hover:bg-indigo-600 group-hover:text-white transition-all duration-500 shadow-inner">
             <svg className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
               <path strokeLinecap="round" strokeLinejoin="round" d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
             </svg>
          </div>
          <div>
            <h4 className="font-black text-gray-900 text-2xl uppercase tracking-tighter">Export CSV</h4>
            <p className="text-[11px] text-gray-400 font-bold uppercase tracking-widest mt-2">Create Local Backup</p>
          </div>
        </button>

        <label className="bg-white p-10 rounded-[3rem] border border-gray-100 shadow-2xl shadow-gray-200/50 hover:shadow-emerald-100 transition-all flex flex-col items-center gap-6 text-center cursor-pointer group active:scale-95">
          <input type="file" accept=".csv" className="hidden" onChange={handleImport} disabled={importing} />
          <div className="w-24 h-24 bg-emerald-50 text-emerald-600 rounded-[2.5rem] flex items-center justify-center group-hover:bg-emerald-600 group-hover:text-white transition-all duration-500 shadow-inner">
            {importing ? (
              <div className="w-10 h-10 border-[5px] border-emerald-600 group-hover:border-white border-t-transparent rounded-full animate-spin"></div>
            ) : (
              <svg className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M12 16V10m0 0l-3 3m3-3l3 3m2-8H7a2 2 0 00-2 2v14a2 2 0 002 2h10a2 2 0 002-2V9l-5-5z" />
              </svg>
            )}
          </div>
          <div>
            <h4 className="font-black text-gray-900 text-2xl uppercase tracking-tighter">{importing ? 'Importing...' : 'Restore CSV'}</h4>
            <p className="text-[11px] text-gray-400 font-bold uppercase tracking-widest mt-2">Restore from File</p>
          </div>
        </label>
      </div>

      {/* Cloud Connectivity Card */}
      <section className="bg-white p-10 rounded-[3.5rem] shadow-[0_25px_80px_-15px_rgba(0,0,0,0.05)] border border-gray-100 relative overflow-hidden">
        <div className="absolute top-0 right-0 p-12 opacity-[0.03] pointer-events-none transform rotate-12">
          <svg className="w-64 h-64" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm-1 17.93c-3.95-.49-7-3.85-7-7.93 0-.62.08-1.21.21-1.79L9 15v1c0 1.1.9 2 2 2v1.93zm6.9-2.54c-.26-.81-1-1.39-1.9-1.39h-1v-3c0-.55-.45-1-1-1H8v-2h2c.55 0 1-.45 1-1V7h2c1.1 0 2-.9 2-2v-.41c2.93 1.19 5 4.06 5 7.41 0 2.08-.8 3.97-2.1 5.39z"/></svg>
        </div>

        <div className="flex flex-col md:flex-row items-center gap-6 mb-10 text-center md:text-left">
