export default Backup;

import { createClient, SupabaseClient } from '@supabase/supabase-js';
import { db, Order } from '../db';

let supabase: SupabaseClient | null = null;

const SYNC_CONFIG_KEY = 'order_tracker_supabase_config';
const LAST_SYNC_KEY = 'order_tracker_last_sync_time';

interface SyncConfig {
  url: string;
  publishableKey: string;
}

export const getSyncConfig = (): SyncConfig | null => {
  const data = localStorage.getItem(SYNC_CONFIG_KEY);
  return data ? JSON.parse(data) : null;
};

export const saveSyncConfig = (config: SyncConfig) => {
  localStorage.setItem(SYNC_CONFIG_KEY, JSON.stringify(config));
  // Create client only when needed to prevent unnecessary background overhead
  supabase = createClient(config.url, config.publishableKey);
};

export const initSupabase = () => {
  const config = getSyncConfig();
  if (config && !supabase) {
    try {
      supabase = createClient(config.url, config.publishableKey);
    } catch (e) {
      console.error("Supabase Init Failed", e);
      return null;
    }
  }
  return supabase;
};

/**
 * Physically removes soft-deleted records from the local IndexedDB.
 */
export const purgeLocalDeletedRecords = async () => {
  // Use numeric 1 for indexing as booleans are not standard IndexableTypes in IndexedDB
  const deletedRecords = await db.orders.where('deleted').equals(1).toArray();
  if (deletedRecords.length === 0) return 0;

  const ids = deletedRecords.map(r => r.id).filter((id): id is number => id !== undefined);
  await db.orders.bulkDelete(ids);
  return ids.length;
};

/**
 * Returns count of records currently marked as deleted locally.
 */
export const getDeletedCount = async () => {
  try {
    return await db.orders.where('deleted').equals(1).count();
  } catch (e) {
    const all = await db.orders.toArray();
    return all.filter(o => o.deleted === 1).length;
  }
};

/**
 * Wipes all data from the remote Supabase 'orders' table.
 */
export const clearSupabaseData = async () => {
  const client = initSupabase();
  if (!client) throw new Error("Supabase is not configured. Go to the Cloud tab.");

  const { error } = await client
    .from('orders')
    .delete()
    .neq('uuid', '00000000-0000-0000-0000-000000000000'); 

  if (error) throw error;
  localStorage.removeItem(LAST_SYNC_KEY);
};

const repairLocalData = async () => {
  const legacyOrders = await db.orders.filter(o => !o.uuid || o.uuid === 'null' || o.uuid === '').toArray();
  if (legacyOrders.length > 0) {
    for (const order of legacyOrders) {
      if (order.id) {
        await db.orders.update(order.id, { 
          uuid: crypto.randomUUID(),
          updatedAt: Date.now() 
        });
      }
    }
  }
};

/**
 * Main Bridge: Sync Local Standalone Database with Remote Supabase
 */
export const syncWithSupabase = async () => {
  const client = initSupabase();
  if (!client) throw new Error("Cloud Datastore not configured.");

  await repairLocalData();

  const storedLastSync = localStorage.getItem(LAST_SYNC_KEY);
  let lastSync = 0;
  if (storedLastSync) {
    const parsed = Number(storedLastSync);
    if (!isNaN(parsed)) lastSync = parsed;
  }

  const now = Date.now();

  // 1. PUSH: Local Changes -> Cloud
  const localChanges = await db.orders
    .where('updatedAt')
    .above(lastSync)
    .toArray();

  const validLocalChanges = localChanges.filter(o => !!o.uuid && o.uuid !== 'null');

  if (validLocalChanges.length > 0) {
    const pushData = validLocalChanges.map(o => ({
      uuid: o.uuid,
      customer: o.customer,
      city: o.city,
      material: o.material,
      qty: o.qty,
      status: o.status,
      note: o.note,
      attachments: o.attachments,
      deleted: o.deleted === 1,
      created_at: new Date(o.createdAt || now).toISOString(),
      updated_at: new Date(o.updatedAt || now).toISOString()
    }));

    const { error: pushError } = await client
      .from('orders')
      .upsert(pushData, { onConflict: 'uuid' });

    if (pushError) throw new Error(`Push Operation Failed: ${pushError.message}`);
  }

  // 2. PULL: Cloud Changes -> Local
  let query = client.from('orders').select('*');
  if (lastSync > 0) {
    query = query.gt('updated_at', new Date(lastSync).toISOString());
  }

  const { data: remoteChanges, error: pullError } = await query;
  if (pullError) throw new Error(`Pull Operation Failed: ${pullError.message}`);

  let pullCount = 0;
  if (remoteChanges && remoteChanges.length > 0) {
    for (const remote of remoteChanges) {
      if (!remote.uuid) continue;
      const local = await db.orders.where('uuid').equals(remote.uuid).first();
      const remoteUpdatedAt = remote.updated_at ? new Date(remote.updated_at).getTime() : 0;

      if (!local || remoteUpdatedAt > (local.updatedAt || 0)) {
        const orderData: Order = {
          ...(local || {}),
          uuid: remote.uuid,
          customer: remote.customer,
          city: remote.city,
          material: remote.material,
          qty: remote.qty,
          status: remote.status,
          note: remote.note,
          attachments: remote.attachments,
          deleted: remote.deleted ? 1 : 0,
          createdAt: remote.created_at ? new Date(remote.created_at).getTime() : (local?.createdAt || now),
          updatedAt: remoteUpdatedAt || now
        };

        if (local && local.id) {
          await db.orders.update(local.id, orderData as any);
        } else {
          await db.orders.put(orderData);
        }
        pullCount++;
      }
    }
  }

  localStorage.setItem(LAST_SYNC_KEY, now.toString());
  return { pushed: validLocalChanges.length, pulled: pullCount };
};

import React, { useState, useEffect } from 'react';
import { AppTab, StorageMode } from './types';
import AddOrder from './components/AddOrder';
import OrdersList from './components/OrdersList';
import Summary from './components/Summary';
import Backup from './components/Backup';
import MasterData from './components/MasterData';
import { getSyncConfig } from './services/syncService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.ADD_ORDER);
  const [editingOrderId, setEditingOrderId] = useState<number | null>(null);
  const [storageMode, setStorageMode] = useState<StorageMode>(() => {
    const saved = localStorage.getItem('app_storage_mode');
    return (saved as StorageMode) || StorageMode.OFFLINE;
  });

  useEffect(() => {
    localStorage.setItem('app_storage_mode', storageMode);
  }, [storageMode]);

  const toggleMode = () => {
    if (storageMode === StorageMode.OFFLINE) {
      const config = getSyncConfig();
      if (!config) {
        alert("Configuration Required: Please set up your Supabase project in the 'Cloud' tab to enable Online mode.");
        setActiveTab(AppTab.BACKUP);
        return;
      }
      setStorageMode(StorageMode.ONLINE);
    } else {
      setStorageMode(StorageMode.OFFLINE);
    }
  };

  const renderContent = () => {
    switch (activeTab) {
      case AppTab.ADD_ORDER:
        return <AddOrder 
          mode={storageMode}
          editId={editingOrderId} 
          onSuccess={() => {
            setEditingOrderId(null);
            setActiveTab(AppTab.ORDERS_LIST);
          }} 
          onCancel={() => {
            setEditingOrderId(null);
            setActiveTab(AppTab.ORDERS_LIST);
          }}
        />;
      case AppTab.ORDERS_LIST:
        return <OrdersList 
          mode={storageMode}
          onEdit={(id) => {
            setEditingOrderId(id);
            setActiveTab(AppTab.ADD_ORDER);
          }} 
        />;
      case AppTab.SUMMARY:
        return <Summary mode={storageMode} />;
      case AppTab.MASTER_DATA:
        return <MasterData mode={storageMode} />;
      case AppTab.BACKUP:
        return <Backup />;
      default:
        return <AddOrder 
          mode={storageMode}
          onSuccess={() => setActiveTab(AppTab.ORDERS_LIST)} 
          onCancel={() => setActiveTab(AppTab.ORDERS_LIST)} 
        />;
    }
  };

  const navItems = [
    { id: AppTab.ADD_ORDER, label: 'Add', icon: <PlusIcon className="w-6 h-6" /> },
    { id: AppTab.ORDERS_LIST, label: 'History', icon: <ListBulletIcon className="w-6 h-6" /> },
    { id: AppTab.SUMMARY, label: 'Stats', icon: <ChartBarIcon className="w-6 h-6" /> },
    { id: AppTab.MASTER_DATA, label: 'Manage', icon: <Cog6ToothIcon className="w-6 h-6" /> },
    { id: AppTab.BACKUP, label: 'Cloud', icon: <CloudArrowUpIcon className="w-6 h-6" /> },
  ];

  return (
    <div className={`flex flex-col min-h-screen transition-colors duration-500 ${storageMode === StorageMode.ONLINE ? 'bg-[#F0F7FF]' : 'bg-[#F8FAFC]'}`}>
      <header className="bg-white/95 border-b border-gray-100 px-6 py-4 sticky top-0 z-50 backdrop-blur-xl">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className={`w-11 h-11 shadow-2xl rounded-2xl flex items-center justify-center transition-all duration-500 transform hover:scale-105 ${storageMode === StorageMode.ONLINE ? 'bg-blue-600 shadow-blue-200' : 'bg-indigo-600 shadow-indigo-200'}`}>
               <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100" className="w-full h-full p-2">
                  <path d="M30 40 L50 30 L70 40 L50 50 Z" fill="#fff" />
                  <path d="M30 40 V60 L50 70 V50 Z" fill="#e0e7ff" />
                  <path d="M70 40 V60 L50 70 V50 Z" fill="#c7d2fe" />
                  <circle cx="72" cy="72" r="18" fill="#fff" />
                  <path d="M64 72 L70 78 L80 68" fill="none" stroke={storageMode === StorageMode.ONLINE ? '#2563eb' : '#4f46e5'} strokeWidth="4" strokeLinecap="round" strokeLinejoin="round" />
               </svg>
            </div>
            <div>
              <h1 className="text-xl font-black text-gray-900 tracking-tight leading-none">ORDER TRACKER <span className={storageMode === StorageMode.ONLINE ? 'text-blue-600' : 'text-indigo-600'}>PRO</span></h1>
              <p className="text-[9px] font-black uppercase tracking-[0.3em] text-gray-400 mt-1">Standalone & Remote Data</p>
            </div>
          </div>

          <div className="flex items-center gap-6">
            <div className="flex items-center bg-gray-100 p-1.5 rounded-[1.25rem] border border-gray-200 shadow-inner">
               <button 
                 onClick={() => setStorageMode(StorageMode.OFFLINE)}
                 className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-[0.15em] transition-all duration-300 ${storageMode === StorageMode.OFFLINE ? 'bg-white text-indigo-600 shadow-lg' : 'text-gray-400 hover:text-gray-600'}`}
               >
                 Local
               </button>
               <button 
                 onClick={toggleMode}
                 className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-[0.15em] transition-all duration-300 ${storageMode === StorageMode.ONLINE ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-400 hover:text-gray-600'}`}
               >
                 Cloud
               </button>
            </div>

            <div className="hidden md:flex gap-1">
               {navItems.map(item => (
                  <button 
                    key={item.id}
                    onClick={() => setActiveTab(item.id)}
                    className={`px-5 py-2.5 rounded-2xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === item.id ? (storageMode === StorageMode.ONLINE ? 'bg-blue-600 text-white shadow-xl shadow-blue-100' : 'bg-indigo-600 text-white shadow-xl shadow-indigo-100') : 'text-gray-500 hover:bg-gray-100 hover:text-gray-900'}`}
                  >
                    {item.label}
                  </button>
               ))}
            </div>
          </div>
        </div>
      </header>

      <main className="flex-1 pb-24 p-4 md:p-8 max-w-6xl mx-auto w-full animate-in fade-in zoom-in-95 duration-500">
        <div className="mb-8 flex items-center justify-center">
