          customers: distinct([...(ordersRes.data?.map(o => o.customer) || []), ...(customersRes.data?.map(c => c.name) || [])]),
          cities: distinct([...(ordersRes.data?.map(o => o.city) || []), ...(citiesRes.data?.map(c => c.name) || [])]),
          materials: distinct([...(ordersRes.data?.map(o => o.material) || []), ...(materialsRes.data?.map(m => m.name) || [])]),
        });
      }
    };
    loadOptions();

    if (editId) {
      if (mode === StorageMode.OFFLINE) {
        db.orders.get(editId).then(order => {
          if (order) {
            setFormData({
              uuid: order.uuid || crypto.randomUUID(), 
              customer: order.customer,
              city: order.city,
              material: order.material,
              qty: order.qty,
              status: order.status || 'Pending',
              note: order.note || '',
              attachments: order.attachments || [],
              createdAt: order.createdAt
            });
          }
        });
      } else {
        // In Online mode, the OrdersList component usually manages the selection.
        // For direct editId lookup, we'd fetch from Supabase.
        const supabase = initSupabase();
        if (supabase) {
           supabase.from('orders').select('*').eq('id', editId).single().then(({ data }) => {
             if (data) {
               setFormData({
                 uuid: data.uuid,
                 customer: data.customer,
                 city: data.city,
                 material: data.material,
                 qty: data.qty,
                 status: data.status,
                 note: data.note,
                 attachments: data.attachments || [],
                 createdAt: new Date(data.created_at).getTime()
               });
             }
           });
        }
      }
    }
  }, [editId, mode]);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    setIsProcessingImages(true);
    try {
      const readFileAsDataURL = (file: File): Promise<string> => {
        return new Promise((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = () => resolve(reader.result as string);
          reader.onerror = (error) => reject(error);
          reader.readAsDataURL(file);
        });
      };

      const downscaleImage = (dataUrl: string, maxWidth = 1200, quality = 0.7): Promise<string> => {
        return new Promise((resolve) => {
          const img = new Image();
          img.src = dataUrl;
          img.onload = () => {
            const canvas = document.createElement('canvas');
            let width = img.width;
            let height = img.height;
            if (width > maxWidth) {
              height = (maxWidth / width) * height;
              width = maxWidth;
            }
            canvas.width = width;
            canvas.height = height;
            const ctx = canvas.getContext('2d');
            ctx?.drawImage(img, 0, 0, width, height);
            resolve(canvas.toDataURL('image/jpeg', quality));
          };
          img.onerror = () => resolve(dataUrl);
        });
      };

      const rawDataUrls = await Promise.all(
        Array.from(files).map(file => readFileAsDataURL(file as File))
      );
      const optimizedAttachments = await Promise.all(
        rawDataUrls.map(url => downscaleImage(url))
      );
      setFormData(prev => ({
        ...prev,
        attachments: [...prev.attachments, ...optimizedAttachments]
      }));
    } catch (err) {
      console.error("Error reading files:", err);
    } finally {
      setIsProcessingImages(false);
      if (e.target) e.target.value = '';
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (isSaving) return;

    const { uuid, customer, city, material, qty, status, note, attachments, createdAt } = formData;

    if (!customer.trim() || !city.trim() || !material.trim() || qty <= 0) {
      alert("Please fill all required fields.");
      return;
    }

    setIsSaving(true);
    const now = Date.now();
    const finalCreatedAt = (editId && createdAt && !isNaN(createdAt)) ? createdAt : now;

    const orderData: Order = {
      uuid: uuid || crypto.randomUUID(),
      customer: customer.trim(),
      city: city.trim(),
      material: material.trim(),
      qty: Number(qty),
      status: status,
      note: note.trim(),
      attachments,
      createdAt: finalCreatedAt,
      updatedAt: now 
    };

    try {
      await saveOrder(mode, orderData, editId);
      onSuccess();
    } catch (err: any) {
      console.error(err);
      alert(`Save failed: ${err.message}`);
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div className="max-w-xl mx-auto">
      <div className="bg-white rounded-[2.5rem] shadow-2xl p-8 border border-gray-100">
        <header className="mb-8 flex justify-between items-start">
          <div>
            <h2 className="text-3xl font-black text-gray-900 leading-tight uppercase tracking-tighter">
              {editId ? 'Edit Order' : 'Add Order'}
            </h2>
            <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest mt-1">Environment: {mode === StorageMode.ONLINE ? 'Cloud Live' : 'Standalone Local'}</p>
          </div>
          <div className={`w-3.5 h-3.5 rounded-full ${mode === StorageMode.ONLINE ? 'bg-blue-600 animate-pulse shadow-[0_0_12px_rgba(37,99,235,0.4)]' : 'bg-indigo-500 shadow-[0_0_12px_rgba(79,70,229,0.3)]'}`}></div>
        </header>

        <form onSubmit={handleSubmit} className="space-y-6">
          <AutocompleteInput
            label="Customer Name"
            value={formData.customer}
            onChange={(val) => setFormData({ ...formData, customer: val })}
            options={options.customers}
            placeholder="Search or enter client..."
            required
          />

          <AutocompleteInput
            label="Material"
            value={formData.material}
            onChange={(val) => setFormData({ ...formData, material: val })}
            options={options.materials}
            placeholder="Search material..."
            required
          />

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
            <AutocompleteInput
              label="Destination City"
              value={formData.city}
              onChange={(val) => setFormData({ ...formData, city: val })}
              options={options.cities}
              placeholder="Select city..."
              required
            />
            <div>
              <label className="block text-xs font-black text-gray-500 mb-2 uppercase tracking-widest">Quantity</label>
              <input
                type="number"
                value={formData.qty || ''}
                onChange={(e) => setFormData({ ...formData, qty: Number(e.target.value) })}
                className="w-full px-5 py-3.5 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-indigo-500 shadow-inner font-black text-lg"
                required
                min="1"
              />
            </div>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
            <div>
              <label className="block text-xs font-black text-gray-500 mb-2 uppercase tracking-widest">Order Status</label>
              <select
                value={formData.status}
                onChange={(e) => setFormData({ ...formData, status: e.target.value })}
                className="w-full px-5 py-3.5 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-indigo-500 shadow-inner font-bold cursor-pointer"
              >
                {STATUS_OPTIONS.map(opt => <option key={opt} value={opt}>{opt}</option>)}
              </select>
            </div>
          </div>

          <div>
            <label className="block text-xs font-black text-gray-500 mb-3 uppercase tracking-widest">Attachments</label>
            <div className="grid grid-cols-4 gap-3">
              {formData.attachments.map((src, idx) => (
                <div key={idx} className="relative aspect-square rounded-2xl overflow-hidden border-2 border-white shadow-md group">
                  <img src={src} className="w-full h-full object-cover" alt="attachment" />
                  <button 
                    type="button"
                    onClick={() => setFormData(p => ({ ...p, attachments: p.attachments.filter((_, i) => i !== idx) }))}
                    className="absolute top-1.5 right-1.5 bg-red-500 text-white p-1.5 rounded-full opacity-0 group-hover:opacity-100 transition-opacity shadow-lg"
                  >
                    <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={4} d="M6 18L18 6M6 6l12 12" /></svg>
                  </button>
                </div>
              ))}
              <button
                type="button"
                onClick={() => fileInputRef.current?.click()}
                disabled={isProcessingImages}
                className="aspect-square rounded-2xl border-2 border-dashed border-gray-200 text-gray-400 hover:bg-indigo-50 hover:border-indigo-200 hover:text-indigo-500 flex flex-col items-center justify-center disabled:opacity-50 transition-all shadow-inner"
              >
                {isProcessingImages ? (
                   <div className="w-6 h-6 border-3 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
                ) : (
                   <>
                    <svg className="w-8 h-8 mb-1" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M12 4v16m8-8H4" strokeWidth={2.5} /></svg>
                    <span className="text-[8px] font-black uppercase">Attach</span>
                   </>
                )}
              </button>
            </div>
            <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept="image/*" multiple />
          </div>
          <div>
             <label className="block text-xs font-black text-gray-500 mb-2 uppercase tracking-widest">Operational Notes</label>
             <textarea
                value={formData.note}
                onChange={(e) => setFormData({ ...formData, note: e.target.value })}
                className="w-full px-5 py-4 bg-gray-50 border-none rounded-[1.5rem] focus:ring-2 focus:ring-indigo-500 shadow-inner min-h-[100px] font-medium"
                placeholder="Internal memo..."
              />
          </div>
          <div className="flex gap-4 pt-4">
            <button 
              type="submit" 
              disabled={isSaving}
              className={`flex-[2] text-white font-black py-5 rounded-2xl shadow-2xl transition-all active:scale-95 disabled:opacity-50 uppercase tracking-widest text-sm ${mode === StorageMode.ONLINE ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-200' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200'}`}
            >
              {isSaving ? 'Processing...' : (editId ? 'Commit Changes' : 'Add Order')}
            </button>
            <button type="button" onClick={onCancel} className="flex-1 bg-gray-100 text-gray-500 font-black py-5 rounded-2xl hover:bg-gray-200 transition-colors uppercase tracking-widest text-xs">Cancel</button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default AddOrder;

import React, { useState, useEffect } from 'react';
import { AppTab, StorageMode } from './types';
import AddOrder from './components/AddOrder';
import OrdersList from './components/OrdersList';
import Summary from './components/Summary';
import Backup from './components/Backup';
import MasterData from './components/MasterData';
import { getSyncConfig } from './services/syncService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.ADD_ORDER);
  const [editingOrderId, setEditingOrderId] = useState<number | null>(null);
  const [storageMode, setStorageMode] = useState<StorageMode>(() => {
    const saved = localStorage.getItem('app_storage_mode');
    return (saved as StorageMode) || StorageMode.OFFLINE;
  });

  useEffect(() => {
    localStorage.setItem('app_storage_mode', storageMode);
  }, [storageMode]);

  const toggleMode = () => {
    if (storageMode === StorageMode.OFFLINE) {
      const config = getSyncConfig();
      if (!config) {
        alert("Configuration Required: Please set up your Supabase project in the 'Cloud' tab to enable Online mode.");
        setActiveTab(AppTab.BACKUP);
        return;
      }
      setStorageMode(StorageMode.ONLINE);
    } else {
      setStorageMode(StorageMode.OFFLINE);
    }
  };

  const renderContent = () => {
    switch (activeTab) {
      case AppTab.ADD_ORDER:
        return <AddOrder 
          mode={storageMode}
          editId={editingOrderId} 
          onSuccess={() => {
            setEditingOrderId(null);
            setActiveTab(AppTab.ORDERS_LIST);
          }} 
          onCancel={() => {
            setEditingOrderId(null);
            setActiveTab(AppTab.ORDERS_LIST);
          }}
        />;
      case AppTab.ORDERS_LIST:
        return <OrdersList 
          mode={storageMode}
          onEdit={(id) => {
            setEditingOrderId(id);
            setActiveTab(AppTab.ADD_ORDER);
          }} 
        />;
      case AppTab.SUMMARY:
        return <Summary mode={storageMode} />;
      case AppTab.MASTER_DATA:
        return <MasterData mode={storageMode} />;
      case AppTab.BACKUP:
        return <Backup />;
      default:
        return <AddOrder 
          mode={storageMode}
          onSuccess={() => setActiveTab(AppTab.ORDERS_LIST)} 
          onCancel={() => setActiveTab(AppTab.ORDERS_LIST)} 
        />;
    }
  };

  const navItems = [
    { id: AppTab.ADD_ORDER, label: 'Add Order', icon: <PlusIcon className="w-6 h-6" /> },
    { id: AppTab.ORDERS_LIST, label: 'History', icon: <ListBulletIcon className="w-6 h-6" /> },
    { id: AppTab.SUMMARY, label: 'Stats', icon: <ChartBarIcon className="w-6 h-6" /> },
    { id: AppTab.MASTER_DATA, label: 'Manage', icon: <Cog6ToothIcon className="w-6 h-6" /> },
    { id: AppTab.BACKUP, label: 'Cloud', icon: <CloudArrowUpIcon className="w-6 h-6" /> },
  ];

  return (
    <div className={`flex flex-col min-h-screen transition-colors duration-500 ${storageMode === StorageMode.ONLINE ? 'bg-[#F0F7FF]' : 'bg-[#F8FAFC]'}`}>
      <header className="bg-white/95 border-b border-gray-100 px-6 py-4 sticky top-0 z-50 backdrop-blur-xl">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className={`w-11 h-11 shadow-2xl rounded-2xl flex items-center justify-center transition-all duration-500 transform hover:scale-105 ${storageMode === StorageMode.ONLINE ? 'bg-blue-600 shadow-blue-200' : 'bg-indigo-600 shadow-indigo-200'}`}>
               <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100" className="w-full h-full p-2">
                  <path d="M30 40 L50 30 L70 40 L50 50 Z" fill="#fff" />
                  <path d="M30 40 V60 L50 70 V50 Z" fill="#e0e7ff" />
                  <path d="M70 40 V60 L50 70 V50 Z" fill="#c7d2fe" />
                  <circle cx="72" cy="72" r="18" fill="#fff" />
                  <path d="M64 72 L70 78 L80 68" fill="none" stroke={storageMode === StorageMode.ONLINE ? '#2563eb' : '#4f46e5'} strokeWidth="4" strokeLinecap="round" strokeLinejoin="round" />
               </svg>
            </div>
            <div>
              <h1 className="text-xl font-black text-gray-900 tracking-tight leading-none">ORDER TRACKER <span className={storageMode === StorageMode.ONLINE ? 'text-blue-600' : 'text-indigo-600'}>PRO</span></h1>
              <p className="text-[9px] font-black uppercase tracking-[0.3em] text-gray-400 mt-1">Standalone & Remote Data</p>
            </div>
          </div>

          <div className="flex items-center gap-6">
            <div className="flex items-center bg-gray-100 p-1.5 rounded-[1.25rem] border border-gray-200 shadow-inner">
               <button 
                 onClick={() => setStorageMode(StorageMode.OFFLINE)}
                 className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-[0.15em] transition-all duration-300 ${storageMode === StorageMode.OFFLINE ? 'bg-white text-indigo-600 shadow-lg' : 'text-gray-400 hover:text-gray-600'}`}
               >
                 Offline
               </button>
               <button 
                 onClick={toggleMode}
                 className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-[0.15em] transition-all duration-300 ${storageMode === StorageMode.ONLINE ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-400 hover:text-gray-600'}`}
               >
                 Online
               </button>
            </div>

            <div className="hidden md:flex gap-1">
               {navItems.map(item => (
                  <button 
                    key={item.id}
                    onClick={() => setActiveTab(item.id)}
                    className={`px-5 py-2.5 rounded-2xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === item.id ? (storageMode === StorageMode.ONLINE ? 'bg-blue-600 text-white shadow-xl shadow-blue-100' : 'bg-indigo-600 text-white shadow-xl shadow-indigo-100') : 'text-gray-500 hover:bg-gray-100 hover:text-gray-900'}`}
                  >
                    {item.label}
                  </button>
               ))}
            </div>
          </div>
        </div>
      </header>

      <main className="flex-1 pb-24 p-4 md:p-8 max-w-6xl mx-auto w-full animate-in fade-in zoom-in-95 duration-500">
        <div className="mb-8 flex items-center justify-center">
           <div className={`px-6 py-2.5 rounded-full border text-[10px] font-black uppercase tracking-[0.25em] flex items-center gap-3 shadow-md transition-all ${storageMode === StorageMode.ONLINE ? 'bg-blue-50 border-blue-100 text-blue-700' : 'bg-indigo-50 border-indigo-100 text-indigo-700'}`}>
              <div className={`w-2 h-2 rounded-full ${storageMode === StorageMode.ONLINE ? 'bg-blue-600 animate-ping' : 'bg-emerald-500'}`}></div>
              Mode: {storageMode === StorageMode.ONLINE ? 'Online' : 'Offline'}
           </div>
        </div>
        {renderContent()}
      </main>

      <nav className="fixed bottom-6 left-1/2 -translate-x-1/2 w-[92%] max-w-md bg-white/80 backdrop-blur-2xl border border-white shadow-[0_20px_50px_rgba(0,0,0,0.1)] rounded-[2.5rem] flex justify-around p-2.5 z-50 md:hidden">
        {navItems.map((item) => (
          <button
            key={item.id}
            onClick={() => {
              setActiveTab(item.id);
              if (item.id !== AppTab.ADD_ORDER) setEditingOrderId(null);
            }}
            className={`flex flex-col items-center justify-center px-4 py-2.5 rounded-3xl transition-all duration-300 ${
              activeTab === item.id 
                ? (storageMode === StorageMode.ONLINE ? 'text-blue-600 bg-blue-50/50 scale-110 shadow-inner' : 'text-indigo-600 bg-indigo-50/50 scale-110 shadow-inner')
                : 'text-gray-400 hover:text-gray-600'
            }`}
          >
            {item.icon}
            <span className="text-[9px] mt-1.5 font-black uppercase tracking-widest">{item.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
};

export default App;

