import React, { useState, useMemo, useRef } from 'react';
import { db, Order, Shipment } from '../db';
import { useLiveQuery } from 'dexie-react-hooks';
import { StorageMode } from '../types';

interface Props {
  mode: StorageMode;
}

const Archive: React.FC<Props> = ({ mode }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [selectedOrderUuids, setSelectedOrderUuids] = useState<Set<string>>(new Set());
  const [reference, setReference] = useState('');
  const [dispatchDate, setDispatchDate] = useState(new Date().toISOString().split('T')[0]);
  const [note, setNote] = useState('');
  const [attachments, setAttachments] = useState<string[]>([]);
  const [isProcessingImages, setIsProcessingImages] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Filter states
  const [filterRef, setFilterRef] = useState('');
  const [filterStartDate, setFilterStartDate] = useState('');
  const [filterEndDate, setFilterEndDate] = useState('');
  const [isFilterExpanded, setIsFilterExpanded] = useState(false);

  // Use local data for archiving
  const orders = useLiveQuery(() => db.orders.reverse().sortBy('createdAt'));
  const shipments = useLiveQuery(() => db.shipments.reverse().sortBy('dispatchDate'));

  const availableOrders = useMemo(() => {
    if (!orders) return [];
    const archivedUuids = new Set(shipments?.flatMap(s => s.orderUuids) || []);
    return orders.filter(o => !archivedUuids.has(o.uuid));
  }, [orders, shipments]);

  const filteredShipments = useMemo(() => {
    if (!shipments) return [];
    return shipments.filter(s => {
      const matchesRef = !filterRef || s.reference.toLowerCase().includes(filterRef.toLowerCase());

      const sDate = new Date(s.dispatchDate).setHours(0,0,0,0);
      const start = filterStartDate ? new Date(filterStartDate).setHours(0,0,0,0) : null;
      const end = filterEndDate ? new Date(filterEndDate).setHours(23,59,59,999) : null;

      const matchesStart = !start || sDate >= start;
      const matchesEnd = !end || sDate <= end;

      return matchesRef && matchesStart && matchesEnd;
    });
  }, [shipments, filterRef, filterStartDate, filterEndDate]);

  const handleToggleOrder = (uuid: string) => {
    const next = new Set(selectedOrderUuids);
    if (next.has(uuid)) next.delete(uuid);
    else next.add(uuid);
    setSelectedOrderUuids(next);
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    setIsProcessingImages(true);
    try {
      const readFileAsDataURL = (file: File): Promise<string> => {
        return new Promise((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = () => resolve(reader.result as string);
          reader.onerror = (error) => reject(error);
          reader.readAsDataURL(file);
        });
      };

      const downscaleImage = (dataUrl: string, maxWidth = 1200, quality = 0.7): Promise<string> => {
        return new Promise((resolve) => {
          const img = new Image();
          img.src = dataUrl;
          img.onload = () => {
            const canvas = document.createElement('canvas');
            let width = img.width;
            let height = img.height;
            if (width > maxWidth) {
              height = (maxWidth / width) * height;
              width = maxWidth;
            }
            canvas.width = width;
            canvas.height = height;
            const ctx = canvas.getContext('2d');
            ctx?.drawImage(img, 0, 0, width, height);
            resolve(canvas.toDataURL('image/jpeg', quality));
          };
          img.onerror = () => resolve(dataUrl);
        });
      };

      const rawDataUrls = await Promise.all(
        Array.from(files).map(file => readFileAsDataURL(file as File))
      );
      const optimized = await Promise.all(rawDataUrls.map(url => downscaleImage(url)));
      setAttachments(prev => [...prev, ...optimized]);
    } finally {
      setIsProcessingImages(false);
      if (e.target) e.target.value = '';
    }
  };

  const handleCreateShipment = async () => {
    if (!reference.trim() || selectedOrderUuids.size === 0 || !dispatchDate) {
      alert("Please provide a reference, dispatch date, and select at least one order.");
      return;
    }

    const newShipment: Shipment = {
      uuid: crypto.randomUUID(),
      reference: reference.trim(),
      orderUuids: Array.from(selectedOrderUuids),
      attachments,
      note: note.trim(),
      dispatchDate: new Date(`${dispatchDate}T12:00:00`).getTime(),
      createdAt: Date.now(),
      updatedAt: Date.now()
    };

    try {
      await db.shipments.add(newShipment);
      setReference('');
      setNote('');
      setAttachments([]);
      setSelectedOrderUuids(new Set());
      setDispatchDate(new Date().toISOString().split('T')[0]);
      setIsCreating(false);
    } catch (err) {
      alert("Failed to create shipment record.");
    }
  };

  const handleDeleteShipment = async (id: number) => {
    if (confirm("Delete this shipment grouping? The orders will become available for archiving again.")) {
      await db.shipments.delete(id);
    }
  };

  const hasActiveFilters = filterRef || filterStartDate || filterEndDate;

  if (isCreating) {
    return (
      <div className="max-w-4xl mx-auto animate-in fade-in slide-in-from-bottom-4 duration-500 pb-24">
        <div className="bg-white rounded-[3rem] shadow-2xl p-8 border border-gray-100 mb-8">
          <header className="mb-8 flex justify-between items-center">
            <div>
              <h2 className="text-3xl font-black text-gray-900 uppercase tracking-tighter">New Shipment</h2>
              <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest mt-1">Group loading proof for transit</p>
            </div>
            <button onClick={() => setIsCreating(false)} className="text-gray-400 hover:text-gray-900 transition-colors">
              <svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </header>

          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-xs font-black text-gray-500 mb-2 uppercase tracking-widest">Shipment Ref (Truck/Container)</label>
                <input
                  type="text"
                  value={reference}
                  onChange={(e) => setReference(e.target.value)}
                  className="w-full px-5 py-3.5 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-indigo-500 shadow-inner font-black text-lg"
                  placeholder="Ex: T-402-B"
                />
              </div>
              <div>
                <label className="block text-xs font-black text-gray-500 mb-2 uppercase tracking-widest">Dispatch Date</label>
                <input
                  type="date"
                  value={dispatchDate}
                  onChange={(e) => setDispatchDate(e.target.value)}
                  className="w-full px-5 py-3.5 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-indigo-500 shadow-inner font-bold outline-none"
                  required
                />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
               <div>
                  <label className="block text-xs font-black text-gray-500 mb-4 uppercase tracking-widest">Select Orders ({selectedOrderUuids.size})</label>
                  <div className="bg-gray-50 rounded-[2rem] p-4 h-[400px] overflow-auto shadow-inner space-y-2 border border-gray-100">
                     {availableOrders.length === 0 ? (
                        <p className="text-center py-10 text-gray-300 font-bold italic text-sm">No available orders to group.</p>
                     ) : (
                        availableOrders.map(order => (
                           <div 
                             key={order.uuid} 
                             onClick={() => handleToggleOrder(order.uuid)}
                             className={`p-4 rounded-2xl cursor-pointer transition-all border-2 flex items-center gap-4 ${selectedOrderUuids.has(order.uuid) ? 'bg-indigo-600 border-indigo-600 shadow-lg shadow-indigo-100' : 'bg-white border-transparent hover:border-indigo-100'}`}
                           >
                              <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-colors ${selectedOrderUuids.has(order.uuid) ? 'bg-white border-white' : 'border-gray-200'}`}>
                                 {selectedOrderUuids.has(order.uuid) && <svg className="w-4 h-4 text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path d="M5 13l4 4L19 7" /></svg>}
                              </div>
                              <div className="flex-1">
                                 <p className={`text-sm font-black ${selectedOrderUuids.has(order.uuid) ? 'text-white' : 'text-gray-900'}`}>{order.customer}</p>
                                 <p className={`text-[10px] font-bold uppercase tracking-widest ${selectedOrderUuids.has(order.uuid) ? 'text-indigo-100' : 'text-gray-400'}`}>{order.city} • {order.qty} units</p>
                              </div>
                           </div>
                        ))
                     )}
                  </div>
               </div>

               <div className="space-y-6">
                  <div>
                    <label className="block text-xs font-black text-gray-500 mb-3 uppercase tracking-widest">Shipment Attachments</label>
                    <div className="grid grid-cols-3 gap-3">
                      {attachments.map((src, idx) => (
                        <div key={idx} className="relative aspect-square rounded-2xl overflow-hidden border-2 border-white shadow-md">
                          <img src={src} className="w-full h-full object-cover" alt="shipment-attachment" />
                          <button 
                            type="button"
                            onClick={() => setAttachments(prev => prev.filter((_, i) => i !== idx))}
                            className="absolute top-1.5 right-1.5 bg-red-500 text-white p-1 rounded-full shadow-lg"
                          >
                            <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={4} d="M6 18L18 6M6 6l12 12" /></svg>
                          </button>
                        </div>
                      ))}
                      <button
                        onClick={() => fileInputRef.current?.click()}
                        className="aspect-square rounded-2xl border-2 border-dashed border-gray-200 text-gray-400 hover:bg-indigo-50 hover:border-indigo-200 flex flex-col items-center justify-center transition-all shadow-inner"
                      >
                         <svg className="w-6 h-6 mb-1" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M12 4v16m8-8H4" strokeWidth={3} /></svg>
                         <span className="text-[8px] font-black uppercase">Attach</span>
                      </button>
                    </div>
                    <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept="image/*" multiple />
                  </div>

                  <div>
                    <label className="block text-xs font-black text-gray-500 mb-2 uppercase tracking-widest">Shipment Note</label>
                    <textarea
                      value={note}
                      onChange={(e) => setNote(e.target.value)}
                      className="w-full px-5 py-4 bg-gray-50 border-none rounded-[1.5rem] focus:ring-2 focus:ring-indigo-500 shadow-inner min-h-[140px] font-medium"
                      placeholder="Trucking details, driver name, carrier info..."
                    />
                  </div>
               </div>
            </div>

            <div className="pt-6 border-t border-gray-50 flex gap-4">
              <button 
                onClick={handleCreateShipment}
                className="flex-1 bg-indigo-600 text-white font-black py-5 rounded-[2rem] shadow-2xl shadow-indigo-200 hover:bg-indigo-700 active:scale-95 transition-all uppercase tracking-widest text-sm"
              >
                Archive Shipment
              </button>
              <button onClick={() => setIsCreating(false)} className="px-10 py-5 bg-gray-100 text-gray-400 font-black rounded-[2rem] hover:bg-gray-200 transition-all uppercase tracking-widest text-xs">Cancel</button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-500 max-w-6xl mx-auto pb-24">
      <header className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <h2 className="text-4xl font-black text-gray-900 uppercase tracking-tighter">Shipment Archives</h2>
          <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest mt-1">Grouped logistics management</p>
        </div>
        <button 
          onClick={() => setIsCreating(true)}
          className="bg-indigo-600 text-white px-8 py-4 rounded-[1.75rem] font-black uppercase tracking-widest text-xs shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all flex items-center gap-3 active:scale-95"
        >
          <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M12 4v16m8-8H4" /></svg>
          Create Shipment
        </button>
      </header>

      {/* Filter Bar */}
      <div className="bg-white p-4 md:p-6 rounded-[2rem] shadow-sm border border-gray-100 sticky top-[80px] z-30 space-y-4">
        <div className="flex flex-col md:flex-row gap-3 items-center">
          <div className="relative flex-1 w-full">
            <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400">
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
            </span>
            <input
              type="text"
