// Fixed: Using named import for Dexie to ensure proper inheritance of instance methods in TypeScript.
import { Dexie } from 'dexie';
import type { Table } from 'dexie';

export interface Order {
  id?: number;
  uuid: string; // Globally unique identifier for cloud sync
  customer: string;
  city: string;
  material: string;
  qty: number;
  status: string;
  createdAt: number;
  updatedAt: number; // Timestamp for sync resolution
  note?: string;
  attachments?: string[]; // Array of base64 strings
}

export interface Shipment {
  id?: number;
  uuid: string;
  reference: string;
  orderUuids: string[];
  attachments: string[];
  createdAt: number;
  updatedAt: number;
  dispatchDate: number; // New: Actual date of dispatch/loading
  note?: string;
}

export interface MasterItem {
  id?: number;
  name: string;
}

// Fixed inheritance visibility: Using named import for Dexie to ensure that instance methods like 'version' are correctly inherited and recognized by the TypeScript compiler on the subclass.
export class OrderTrackerDB extends Dexie {
  orders!: Table<Order>;
  shipments!: Table<Shipment>;
  customersMaster!: Table<MasterItem>;
  citiesMaster!: Table<MasterItem>;
  materialsMaster!: Table<MasterItem>;

  constructor() {
    super('OrderTrackerDB');

    // Updated schema to version 9: Added dispatchDate to shipments.
    this.version(9).stores({
      orders: '++id, &uuid, customer, city, material, qty, status, createdAt, updatedAt',
      shipments: '++id, &uuid, reference, *orderUuids, createdAt, dispatchDate',
      customersMaster: '++id, &name',
      citiesMaster: '++id, &name',
      materialsMaster: '++id, &name'
    });
  }
}

export const db = new OrderTrackerDB();

import { db, Shipment } from '../db';
import { initSupabase } from './syncService';
import { StorageMode } from '../types';

export const getShipments = async (mode: StorageMode): Promise<Shipment[]> => {
  if (mode === StorageMode.OFFLINE) {
    return db.shipments.reverse().sortBy('dispatchDate');
  } else {
    const supabase = initSupabase();
    if (!supabase) throw new Error("Remote access not configured");

    const { data, error } = await supabase
      .from('shipments')
      .select('*')
      .order('dispatch_date', { ascending: false });

    if (error) throw error;

    return (data || []).map(remote => ({
      id: remote.id,
      uuid: remote.uuid,
      reference: remote.reference,
      orderUuids: remote.order_uuids || [],
      attachments: remote.attachments || [],
      dispatchDate: new Date(remote.dispatch_date).getTime(),
      note: remote.note,
      createdAt: new Date(remote.created_at).getTime(),
      updatedAt: new Date(remote.updated_at).getTime()
    }));
  }
};

export const saveShipment = async (mode: StorageMode, shipment: Shipment) => {
  if (mode === StorageMode.OFFLINE) {
    return await db.shipments.add(shipment);
  } else {
    const supabase = initSupabase();
    if (!supabase) throw new Error("Remote access not configured");

    const payload = {
      uuid: shipment.uuid,
      reference: shipment.reference,
      order_uuids: shipment.orderUuids,
      attachments: shipment.attachments,
      dispatch_date: new Date(shipment.dispatchDate).toISOString(),
      note: shipment.note,
      updated_at: new Date().toISOString()
    };

    const { error } = await supabase
      .from('shipments')
      .insert({ ...payload, created_at: new Date().toISOString() });

    if (error) throw error;
  }
};

export const deleteShipment = async (mode: StorageMode, id: number, uuid: string) => {
  if (mode === StorageMode.OFFLINE) {
    return await db.shipments.delete(id);
  } else {
    const supabase = initSupabase();
    if (!supabase) throw new Error("Remote access not configured");
    const { error } = await supabase
      .from('shipments')
      .delete()
      .eq('uuid', uuid);
    if (error) throw error;
  }
};

import { createClient, SupabaseClient } from '@supabase/supabase-js';
import { db, Order, Shipment } from '../db';

let supabase: SupabaseClient | null = null;

const SYNC_CONFIG_KEY = 'order_tracker_supabase_config';
const LAST_SYNC_KEY = 'order_tracker_last_sync_time';

interface SyncConfig {
  url: string;
  publishableKey: string;
}

export const getSyncConfig = (): SyncConfig | null => {
  const data = localStorage.getItem(SYNC_CONFIG_KEY);
  return data ? JSON.parse(data) : null;
};

export const saveSyncConfig = (config: SyncConfig) => {
  localStorage.setItem(SYNC_CONFIG_KEY, JSON.stringify(config));
  supabase = createClient(config.url, config.publishableKey);
};

export const initSupabase = () => {
  const config = getSyncConfig();
  if (config && !supabase) {
    try {
      supabase = createClient(config.url, config.publishableKey);
    } catch (e) {
      console.error("Supabase Init Failed", e);
      return null;
    }
  }
  return supabase;
};

export const clearSupabaseData = async () => {
  const client = initSupabase();
  if (!client) throw new Error("Supabase not configured.");

  // Clear both tables
  const { error: err1 } = await client.from('orders').delete().neq('uuid', '00000000-0000-0000-0000-000000000000'); 
  const { error: err2 } = await client.from('shipments').delete().neq('uuid', '00000000-0000-0000-0000-000000000000'); 

  if (err1) throw err1;
  if (err2) throw err2;

  localStorage.removeItem(LAST_SYNC_KEY);
};

export const syncWithSupabase = async () => {
  const client = initSupabase();
  if (!client) throw new Error("Cloud Datastore not configured.");

  const storedLastSync = localStorage.getItem(LAST_SYNC_KEY);
  let lastSync = 0;
  if (storedLastSync) {
    const parsed = Number(storedLastSync);
    if (!isNaN(parsed)) lastSync = parsed;
  }

  const now = Date.now();

  // --- ORDERS SYNC ---
  const localOrderChanges = await db.orders.where('updatedAt').above(lastSync).toArray();
  if (localOrderChanges.length > 0) {
    await client.from('orders').upsert(localOrderChanges.map(o => ({
      uuid: o.uuid,
      customer: o.customer,
      city: o.city,
      material: o.material,
      qty: o.qty,
      status: o.status,
      note: o.note,
      attachments: o.attachments,
      created_at: new Date(o.createdAt).toISOString(),
      updated_at: new Date(o.updatedAt).toISOString()
    })), { onConflict: 'uuid' });
  }

  // --- SHIPMENTS SYNC ---
  const localShipmentChanges = await db.shipments.where('updatedAt').above(lastSync).toArray();
  if (localShipmentChanges.length > 0) {
    await client.from('shipments').upsert(localShipmentChanges.map(s => ({
      uuid: s.uuid,
      reference: s.reference,
      order_uuids: s.orderUuids,
      attachments: s.attachments,
      dispatch_date: new Date(s.dispatchDate).toISOString(),
      note: s.note,
      created_at: new Date(s.createdAt).toISOString(),
      updated_at: new Date(s.updatedAt).toISOString()
    })), { onConflict: 'uuid' });
  }

  // --- PULL REMOTE ---
  const { data: remoteOrders } = await client.from('orders').select('*').gt('updated_at', new Date(lastSync).toISOString());
  if (remoteOrders) {
    for (const r of remoteOrders) {
      const local = await db.orders.where('uuid').equals(r.uuid).first();
      const updated = {
        uuid: r.uuid, customer: r.customer, city: r.city, material: r.material, qty: r.qty,
        status: r.status, note: r.note, attachments: r.attachments,
        createdAt: new Date(r.created_at).getTime(), updatedAt: new Date(r.updated_at).getTime()
      };
      if (local) await db.orders.update(local.id!, updated);
      else await db.orders.add(updated);
    }
  }

  const { data: remoteShipments } = await client.from('shipments').select('*').gt('updated_at', new Date(lastSync).toISOString());
  if (remoteShipments) {
    for (const r of remoteShipments) {
      const local = await db.shipments.where('uuid').equals(r.uuid).first();
      const updated = {
        uuid: r.uuid, reference: r.reference, orderUuids: r.order_uuids, attachments: r.attachments,
        dispatchDate: new Date(r.dispatch_date).getTime(), note: r.note,
        createdAt: new Date(r.created_at).getTime(), updatedAt: new Date(r.updated_at).getTime()
      };
      if (local) await db.shipments.update(local.id!, updated);
      else await db.shipments.add(updated);
    }
  }

  localStorage.setItem(LAST_SYNC_KEY, now.toString());
  return { pushed: localOrderChanges.length + localShipmentChanges.length, pulled: (remoteOrders?.length || 0) + (remoteShipments?.length || 0) };
};

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { db, Order, Shipment } from '../db';
import { useLiveQuery } from 'dexie-react-hooks';
import { StorageMode } from '../types';
import { getShipments, saveShipment, deleteShipment } from '../services/shipmentService';
import { getOrders } from '../services/orderService';
import { initSupabase } from '../services/syncService';

interface Props {
  mode: StorageMode;
}

const Archive: React.FC<Props> = ({ mode }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [selectedOrderUuids, setSelectedOrderUuids] = useState<Set<string>>(new Set());
  const [reference, setReference] = useState('');
  const [dispatchDate, setDispatchDate] = useState(new Date().toISOString().split('T')[0]);
  const [note, setNote] = useState('');
  const [attachments, setAttachments] = useState<string[]>([]);
  const [isProcessingImages, setIsProcessingImages] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Online data states
  const [onlineShipments, setOnlineShipments] = useState<Shipment[]>([]);
  const [onlineOrders, setOnlineOrders] = useState<Order[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  // Filter states
  const [filterRef, setFilterRef] = useState('');
  const [filterStartDate, setFilterStartDate] = useState('');
  const [filterEndDate, setFilterEndDate] = useState('');
  const [isFilterExpanded, setIsFilterExpanded] = useState(false);

  // Local data
  const localOrders = useLiveQuery(() => db.orders.toArray());
  const localShipments = useLiveQuery(() => db.shipments.toArray());

  const fetchOnlineData = async () => {
    if (mode !== StorageMode.ONLINE) return;
    setIsLoading(true);
    try {
      const [shipmentsData, ordersData] = await Promise.all([
        getShipments(StorageMode.ONLINE),
        getOrders(StorageMode.ONLINE)
      ]);
      setOnlineShipments(shipmentsData);
      setOnlineOrders(ordersData);
    } catch (err) {
      console.error("Archive Fetch Error:", err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (mode === StorageMode.ONLINE) {
      fetchOnlineData();
      const supabase = initSupabase();
      if (supabase) {
        const channel = supabase.channel('archive_realtime')
          .on('postgres_changes', { event: '*', table: 'shipments' }, () => fetchOnlineData())
          .on('postgres_changes', { event: '*', table: 'orders' }, () => fetchOnlineData())
          .subscribe();
        return () => { supabase.removeChannel(channel); };
      }
    }
  }, [mode]);

  const activeShipments = mode === StorageMode.OFFLINE ? (localShipments || []) : onlineShipments;
  const activeOrders = mode === StorageMode.OFFLINE ? (localOrders || []) : onlineOrders;

  const availableOrders = useMemo(() => {
    const archivedUuids = new Set(activeShipments.flatMap(s => s.orderUuids));
    return activeOrders.filter(o => !archivedUuids.has(o.uuid));
  }, [activeOrders, activeShipments]);

  const filteredShipments = useMemo(() => {
    return activeShipments.filter(s => {
      const matchesRef = !filterRef || s.reference.toLowerCase().includes(filterRef.toLowerCase());
      const sDate = new Date(s.dispatchDate).setHours(0,0,0,0);
      const start = filterStartDate ? new Date(filterStartDate).setHours(0,0,0,0) : null;
      const end = filterEndDate ? new Date(filterEndDate).setHours(23,59,59,999) : null;
      return matchesRef && (!start || sDate >= start) && (!end || sDate <= end);
    }).sort((a, b) => b.dispatchDate - a.dispatchDate);
  }, [activeShipments, filterRef, filterStartDate, filterEndDate]);

  const handleToggleOrder = (uuid: string) => {
    const next = new Set(selectedOrderUuids);
    if (next.has(uuid)) next.delete(uuid);
    else next.add(uuid);
    setSelectedOrderUuids(next);
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    setIsProcessingImages(true);
    try {
      const readFileAsDataURL = (file: File): Promise<string> => {
        return new Promise((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = () => resolve(reader.result as string);
          reader.onerror = (error) => reject(error);
          reader.readAsDataURL(file);
        });
      };

      const downscaleImage = (dataUrl: string, maxWidth = 1200, quality = 0.7): Promise<string> => {
        return new Promise((resolve) => {
          const img = new Image();
          img.src = dataUrl;
          img.onload = () => {
            const canvas = document.createElement('canvas');
            let w = img.width, h = img.height;
            if (w > maxWidth) { h = (maxWidth / w) * h; w = maxWidth; }
            canvas.width = w; canvas.height = h;
            canvas.getContext('2d')?.drawImage(img, 0, 0, w, h);
            resolve(canvas.toDataURL('image/jpeg', quality));
          };
          img.onerror = () => resolve(dataUrl);
        });
      };

      const optimized = await Promise.all(Array.from(files).map(async f => downscaleImage(await readFileAsDataURL(f))));
      setAttachments(prev => [...prev, ...optimized]);
    } finally {
      setIsProcessingImages(false);
      if (e.target) e.target.value = '';
    }
  };

  const handleCreateShipment = async () => {
    if (!reference.trim() || selectedOrderUuids.size === 0 || !dispatchDate) {
      alert("Please fill all required fields."); return;
    }

    const newShipment: Shipment = {
      uuid: crypto.randomUUID(),
      reference: reference.trim(),
      orderUuids: Array.from(selectedOrderUuids),
      attachments,
      note: note.trim(),
      dispatchDate: new Date(`${dispatchDate}T12:00:00`).getTime(),
      createdAt: Date.now(),
      updatedAt: Date.now()
    };

    try {
      await saveShipment(mode, newShipment);
      setReference(''); setNote(''); setAttachments([]); setSelectedOrderUuids(new Set());
      setDispatchDate(new Date().toISOString().split('T')[0]);
      setIsCreating(false);
      if (mode === StorageMode.ONLINE) fetchOnlineData();
    } catch (err) { alert("Action failed."); }
  };

  const handleDeleteShipment = async (shipment: Shipment) => {
    if (confirm("Delete this shipment grouping?")) {
      await deleteShipment(mode, shipment.id!, shipment.uuid);
      if (mode === StorageMode.ONLINE) fetchOnlineData();
    }
  };

  if (isCreating) {
    return (
      <div className="max-w-4xl mx-auto animate-in fade-in slide-in-from-bottom-4 duration-500 pb-24">
        <div className="bg-white rounded-[3rem] shadow-2xl p-8 border border-gray-100 mb-8">
          <header className="mb-8 flex justify-between items-center">
            <div>
              <h2 className="text-3xl font-black text-gray-900 uppercase tracking-tighter">New Shipment</h2>
              <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest mt-1">
                {mode === StorageMode.ONLINE ? 'CLOUD STORAGE' : 'OFFLINE STORAGE'}
              </p>
            </div>
            <button onClick={() => setIsCreating(false)} className="text-gray-400 hover:text-gray-900"><svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg></button>
          </header>

          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-xs font-black text-gray-500 mb-2 uppercase tracking-widest">Shipment Ref</label>
                <input type="text" value={reference} onChange={(e) => setReference(e.target.value)} className="w-full px-5 py-3.5 bg-gray-50 border-none rounded-2xl shadow-inner font-black text-lg" placeholder="T-402-B" />
              </div>
              <div>
                <label className="block text-xs font-black text-gray-500 mb-2 uppercase tracking-widest">Dispatch Date</label>
                <input type="date" value={dispatchDate} onChange={(e) => setDispatchDate(e.target.value)} className="w-full px-5 py-3.5 bg-gray-50 border-none rounded-2xl shadow-inner font-bold outline-none" />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
               <div>
                  <label className="block text-xs font-black text-gray-500 mb-4 uppercase tracking-widest">Select Orders ({selectedOrderUuids.size})</label>
                  <div className="bg-gray-50 rounded-[2rem] p-4 h-[400px] overflow-auto shadow-inner space-y-2 border border-gray-100">
                     {availableOrders.length === 0 ? <p className="text-center py-10 text-gray-300 font-bold text-sm">No orders available.</p> : availableOrders.map(order => (
                       <div key={order.uuid} onClick={() => handleToggleOrder(order.uuid)} className={`p-4 rounded-2xl cursor-pointer transition-all border-2 flex items-center gap-4 ${selectedOrderUuids.has(order.uuid) ? 'bg-indigo-600 border-indigo-600 shadow-lg' : 'bg-white border-transparent'}`}>
                          <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center ${selectedOrderUuids.has(order.uuid) ? 'bg-white border-white' : 'border-gray-200'}`}>
                             {selectedOrderUuids.has(order.uuid) && <svg className="w-4 h-4 text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path d="M5 13l4 4L19 7" /></svg>}
                          </div>
                          <div className="flex-1">
                             <p className={`text-sm font-black ${selectedOrderUuids.has(order.uuid) ? 'text-white' : 'text-gray-900'}`}>{order.customer}</p>
                             <p className={`text-[10px] font-bold uppercase ${selectedOrderUuids.has(order.uuid) ? 'text-indigo-100' : 'text-gray-400'}`}>{order.city} • {order.qty} units</p>
                          </div>
                       </div>
                     ))}
                  </div>
               </div>
               <div className="space-y-6">
                  <div>
                    <label className="block text-xs font-black text-gray-500 mb-3 uppercase tracking-widest">Loading Proof</label>
                    <div className="grid grid-cols-3 gap-3">
                      {attachments.map((src, idx) => (
                        <div key={idx} className="relative aspect-square rounded-2xl overflow-hidden border-2 border-white shadow-md">
                          <img src={src} className="w-full h-full object-cover" />
                          <button onClick={() => setAttachments(p => p.filter((_, i) => i !== idx))} className="absolute top-1 right-1 bg-red-500 text-white p-1 rounded-full"><svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M6 18L18 6M6 6l12 12" strokeWidth={4} /></svg></button>
                        </div>
                      ))}
                      <button onClick={() => fileInputRef.current?.click()} className="aspect-square rounded-2xl border-2 border-dashed border-gray-200 text-gray-400 hover:bg-indigo-50 flex flex-col items-center justify-center shadow-inner">
                         <svg className="w-6 h-6 mb-1" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M12 4v16m8-8H4" /></svg>
                         <span className="text-[8px] font-black uppercase">Attach</span>
                      </button>
                    </div>
                    <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept="image/*" multiple />
                  </div>
                  <div>
                    <label className="block text-xs font-black text-gray-500 mb-2 uppercase tracking-widest">Shipment Note</label>
                    <textarea value={note} onChange={(e) => setNote(e.target.value)} className="w-full px-5 py-4 bg-gray-50 border-none rounded-[1.5rem] shadow-inner min-h-[140px] font-medium" placeholder="Trucking details..." />
                  </div>
               </div>
            </div>
            <div className="pt-6 border-t border-gray-50 flex gap-4">
              <button onClick={handleCreateShipment} className="flex-1 bg-indigo-600 text-white font-black py-5 rounded-[2rem] shadow-xl hover:bg-indigo-700 active:scale-95 uppercase tracking-widest text-sm">Archive Shipment</button>
              <button onClick={() => setIsCreating(false)} className="px-10 py-5 bg-gray-100 text-gray-400 font-black rounded-[2rem] uppercase tracking-widest text-xs">Cancel</button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-500 max-w-6xl mx-auto pb-24">
      <header className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <h2 className="text-4xl font-black text-gray-900 uppercase tracking-tighter">Shipment Archives</h2>
          <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest mt-1">Management Hub</p>
        </div>
        <button onClick={() => setIsCreating(true)} className="bg-indigo-600 text-white px-8 py-4 rounded-[1.75rem] font-black uppercase tracking-widest text-xs shadow-xl shadow-indigo-100 hover:bg-indigo-700 flex items-center gap-3">
          <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M12 4v16m8-8H4" /></svg>
          New Shipment
        </button>
      </header>

      <div className="bg-white p-4 md:p-6 rounded-[2rem] shadow-sm border border-gray-100 sticky top-[80px] z-30 flex flex-col md:flex-row gap-3">
        <div className="relative flex-1">
          <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"><svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg></span>
          <input type="text" placeholder="Ref search..." value={filterRef} onChange={(e) => setFilterRef(e.target.value)} className="w-full pl-12 pr-4 py-3.5 bg-gray-50 border-none rounded-2xl shadow-inner font-bold text-gray-900" />
        </div>
        <div className="flex gap-2">
           <button onClick={() => setIsFilterExpanded(!isFilterExpanded)} className={`px-6 py-3.5 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-2 border ${isFilterExpanded ? 'bg-indigo-600 text-white' : 'bg-white text-gray-500'}`}>Dates</button>
           {mode === StorageMode.ONLINE && <button onClick={fetchOnlineData} className={`p-3.5 bg-blue-50 text-blue-600 rounded-2xl ${isLoading ? 'animate-spin' : ''}`}><svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg></button>}
        </div>
      </div>

      {isFilterExpanded && (
        <div className="bg-white p-6 rounded-[2rem] shadow-xl border border-indigo-50 flex gap-4 animate-in slide-in-from-top-4">
           <input type="date" value={filterStartDate} onChange={e => setFilterStartDate(e.target.value)} className="flex-1 bg-gray-50 p-3 rounded-xl font-bold" />
           <input type="date" value={filterEndDate} onChange={e => setFilterEndDate(e.target.value)} className="flex-1 bg-gray-50 p-3 rounded-xl font-bold" />
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {isLoading && activeShipments.length === 0 ? <div className="col-span-full py-20 text-center text-indigo-600 font-black">Connecting...</div> : filteredShipments.length === 0 ? (
          <div className="col-span-full py-20 text-center bg-white rounded-[3rem] border-2 border-dashed border-gray-100">
            <p className="text-gray-300 font-black text-xl italic uppercase tracking-widest">No Shipments</p>
          </div>
        ) : filteredShipments.map(s => {
             const linked = s.orderUuids.map(uuid => activeOrders.find(o => o.uuid === uuid)).filter(Boolean) as Order[];
             return (
               <div key={s.uuid} className="bg-white rounded-[2.5rem] p-6 shadow-sm border border-gray-50 hover:shadow-2xl transition-all flex flex-col">
                 <div className="flex justify-between items-start mb-6">
                    <div>
                       <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest bg-indigo-50 px-3 py-1 rounded-full mb-2 inline-block">Ref: {s.reference}</span>
                       <h3 className="text-xl font-black text-gray-900">{linked.length} Orders</h3>
                       <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Disp: {new Date(s.dispatchDate).toLocaleDateString()}</p>
                    </div>
                    <div className="bg-indigo-600 rounded-2xl p-3 text-center min-w-[60px] shadow-lg">
                       <span className="block text-[8px] text-white opacity-70 font-black uppercase">Total Qty</span>
                       <span className="block text-xl font-black text-white leading-none">{linked.reduce((sum, o) => sum + o.qty, 0)}</span>
                    </div>
                 </div>
                 <div className="flex-1 mb-4">
                    <div className="flex flex-wrap gap-1.5 mb-3">{linked.slice(0, 3).map(o => <span key={o.uuid} className="text-[9px] font-bold text-gray-500 bg-gray-50 px-2 py-1 rounded-lg truncate">{o.customer}</span>)}</div>
                    {s.note && <p className="text-[11px] text-gray-500 italic bg-gray-50 p-3 rounded-xl border border-gray-100/50 line-clamp-2">{s.note}</p>}
                 </div>
                 {s.attachments.length > 0 && <div className="flex gap-2 overflow-x-auto no-scrollbar mb-4">{s.attachments.map((src, i) => <img key={i} src={src} className="w-16 h-16 rounded-xl object-cover border-2 border-white shadow-sm" />)}</div>}
                 <div className="flex justify-end pt-4 border-t border-gray-50"><button onClick={() => handleDeleteShipment(s)} className="p-3 bg-gray-50 text-gray-400 hover:text-red-600 rounded-xl transition-all shadow-sm"><svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button></div>
               </div>
             )
        })}
      </div>
    </div>
  );
};

export default Archive;

// Fixed: Using default import for Dexie to ensure proper inheritance of instance methods in TypeScript.
import Dexie from 'dexie';
import type { Table } from 'dexie';

export interface Order {
  id?: number;
  uuid: string; // Globally unique identifier for cloud sync
  customer: string;
  city: string;
  material: string;
  qty: number;
  status: string;
  createdAt: number;
  updatedAt: number; // Timestamp for sync resolution
  note?: string;
  attachments?: string[]; // Array of base64 strings
}

export interface Shipment {
  id?: number;
  uuid: string;
  reference: string;
  orderUuids: string[];
  attachments: string[];
  createdAt: number;
  updatedAt: number;
  dispatchDate: number; // New: Actual date of dispatch/loading
  note?: string;
}

export interface MasterItem {
  id?: number;
  name: string;
}

// Fixed inheritance visibility: Using default import for Dexie to ensure that instance methods like 'version' are correctly inherited and recognized by the TypeScript compiler on the subclass.
export class OrderTrackerDB extends Dexie {
  orders!: Table<Order>;
  shipments!: Table<Shipment>;
  customersMaster!: Table<MasterItem>;
  citiesMaster!: Table<MasterItem>;
  materialsMaster!: Table<MasterItem>;

  constructor() {
    super('OrderTrackerDB');

    // Updated schema to version 9: Added dispatchDate to shipments.
    this.version(9).stores({
      orders: '++id, &uuid, customer, city, material, qty, status, createdAt, updatedAt',
      shipments: '++id, &uuid, reference, *orderUuids, createdAt, dispatchDate',
      customersMaster: '++id, &name',
      citiesMaster: '++id, &name',
      materialsMaster: '++id, &name'
    });
  }
}

export const db = new OrderTrackerDB();

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { db, Order, Shipment } from '../db';
import { useLiveQuery } from 'dexie-react-hooks';
import { StorageMode } from '../types';
import { getShipments, saveShipment, deleteShipment } from '../services/shipmentService';
import { getOrders } from '../services/orderService';
import { initSupabase } from '../services/syncService';

interface Props {
  mode: StorageMode;
}

const Archive: React.FC<Props> = ({ mode }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [selectedOrderUuids, setSelectedOrderUuids] = useState<Set<string>>(new Set());
  const [reference, setReference] = useState('');
  const [dispatchDate, setDispatchDate] = useState(new Date().toISOString().split('T')[0]);
  const [note, setNote] = useState('');
  const [attachments, setAttachments] = useState<string[]>([]);
  const [isProcessingImages, setIsProcessingImages] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Online data states
  const [onlineShipments, setOnlineShipments] = useState<Shipment[]>([]);
  const [onlineOrders, setOnlineOrders] = useState<Order[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  // Filter states
  const [filterRef, setFilterRef] = useState('');
  const [filterStartDate, setFilterStartDate] = useState('');
  const [filterEndDate, setFilterEndDate] = useState('');
  const [isFilterExpanded, setIsFilterExpanded] = useState(false);

  // Local data
  const localOrders = useLiveQuery(() => db.orders.toArray());
  const localShipments = useLiveQuery(() => db.shipments.toArray());

  const fetchOnlineData = async () => {
    if (mode !== StorageMode.ONLINE) return;
    setIsLoading(true);
    try {
      const [shipmentsData, ordersData] = await Promise.all([
        getShipments(StorageMode.ONLINE),
        getOrders(StorageMode.ONLINE)
      ]);
      setOnlineShipments(shipmentsData);
      setOnlineOrders(ordersData);
    } catch (err) {
      console.error("Archive Fetch Error:", err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (mode === StorageMode.ONLINE) {
      fetchOnlineData();
      const supabase = initSupabase();
      if (supabase) {
        const channel = supabase.channel('archive_realtime')
          .on('postgres_changes', { event: '*', table: 'shipments' }, () => fetchOnlineData())
          .on('postgres_changes', { event: '*', table: 'orders' }, () => fetchOnlineData())
          .subscribe();
        return () => { supabase.removeChannel(channel); };
      }
    }
  }, [mode]);

  const activeShipments = mode === StorageMode.OFFLINE ? (localShipments || []) : onlineShipments;
  const activeOrders = mode === StorageMode.OFFLINE ? (localOrders || []) : onlineOrders;

  const availableOrders = useMemo(() => {
    const archivedUuids = new Set(activeShipments.flatMap(s => s.orderUuids));
    return activeOrders.filter(o => !archivedUuids.has(o.uuid));
  }, [activeOrders, activeShipments]);

  const filteredShipments = useMemo(() => {
    return activeShipments.filter(s => {
      const matchesRef = !filterRef || s.reference.toLowerCase().includes(filterRef.toLowerCase());
      const sDate = new Date(s.dispatchDate).setHours(0,0,0,0);
      const start = filterStartDate ? new Date(filterStartDate).setHours(0,0,0,0) : null;
      const end = filterEndDate ? new Date(filterEndDate).setHours(23,59,59,999) : null;
      return matchesRef && (!start || sDate >= start) && (!end || sDate <= end);
    }).sort((a, b) => b.dispatchDate - a.dispatchDate);
  }, [activeShipments, filterRef, filterStartDate, filterEndDate]);

  const handleToggleOrder = (uuid: string) => {
    const next = new Set(selectedOrderUuids);
    if (next.has(uuid)) next.delete(uuid);
    else next.add(uuid);
    setSelectedOrderUuids(next);
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    setIsProcessingImages(true);
    try {
      const readFileAsDataURL = (file: File): Promise<string> => {
        return new Promise((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = () => resolve(reader.result as string);
          reader.onerror = (error) => reject(error);
          reader.readAsDataURL(file);
        });
      };

      const downscaleImage = (dataUrl: string, maxWidth = 1200, quality = 0.7): Promise<string> => {
        return new Promise((resolve) => {
          const img = new Image();
          img.src = dataUrl;
          img.onload = () => {
            const canvas = document.createElement('canvas');
            let w = img.width, h = img.height;
            if (w > maxWidth) { h = (maxWidth / w) * h; w = maxWidth; }
            canvas.width = w; canvas.height = h;
            canvas.getContext('2d')?.drawImage(img, 0, 0, w, h);
            resolve(canvas.toDataURL('image/jpeg', quality));
          };
          img.onerror = () => resolve(dataUrl);
        });
      };

      // Fixed: Explicitly cast 'f' to 'File' to satisfy the type requirement of readFileAsDataURL.
      const optimized = await Promise.all(Array.from(files).map(async f => downscaleImage(await readFileAsDataURL(f as File))));
      setAttachments(prev => [...prev, ...optimized]);
    } finally {
      setIsProcessingImages(false);
      if (e.target) e.target.value = '';
    }
  };

  const handleCreateShipment = async () => {
    if (!reference.trim() || selectedOrderUuids.size === 0 || !dispatchDate) {
      alert("Please fill all required fields."); return;
    }

    const newShipment: Shipment = {
      uuid: crypto.randomUUID(),
      reference: reference.trim(),
      orderUuids: Array.from(selectedOrderUuids),
      attachments,
      note: note.trim(),
      dispatchDate: new Date(`${dispatchDate}T12:00:00`).getTime(),
      createdAt: Date.now(),
      updatedAt: Date.now()
    };

    try {
      await saveShipment(mode, newShipment);
      setReference(''); setNote(''); setAttachments([]); setSelectedOrderUuids(new Set());
      setDispatchDate(new Date().toISOString().split('T')[0]);
      setIsCreating(false);
      if (mode === StorageMode.ONLINE) fetchOnlineData();
    } catch (err) { alert("Action failed."); }
  };

  const handleDeleteShipment = async (shipment: Shipment) => {
    if (confirm("Delete this shipment grouping?")) {
      await deleteShipment(mode, shipment.id!, shipment.uuid);
      if (mode === StorageMode.ONLINE) fetchOnlineData();
    }
  };

  if (isCreating) {
    return (
      <div className="max-w-4xl mx-auto animate-in fade-in slide-in-from-bottom-4 duration-500 pb-24">
        <div className="bg-white rounded-[3rem] shadow-2xl p-8 border border-gray-100 mb-8">
          <header className="mb-8 flex justify-between items-center">
            <div>
              <h2 className="text-3xl font-black text-gray-900 uppercase tracking-tighter">New Shipment</h2>
              <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest mt-1">
                {mode === StorageMode.ONLINE ? 'CLOUD STORAGE' : 'OFFLINE STORAGE'}
              </p>
            </div>
            <button onClick={() => setIsCreating(false)} className="text-gray-400 hover:text-gray-900"><svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg></button>
          </header>

          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-xs font-black text-gray-500 mb-2 uppercase tracking-widest">Shipment Ref</label>
                <input type="text" value={reference} onChange={(e) => setReference(e.target.value)} className="w-full px-5 py-3.5 bg-gray-50 border-none rounded-2xl shadow-inner font-black text-lg" placeholder="T-402-B" />
              </div>
              <div>
                <label className="block text-xs font-black text-gray-500 mb-2 uppercase tracking-widest">Dispatch Date</label>
                <input type="date" value={dispatchDate} onChange={(e) => setDispatchDate(e.target.value)} className="w-full px-5 py-3.5 bg-gray-50 border-none rounded-2xl shadow-inner font-bold outline-none" />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
               <div>
                  <label className="block text-xs font-black text-gray-500 mb-4 uppercase tracking-widest">Select Orders ({selectedOrderUuids.size})</label>
                  <div className="bg-gray-50 rounded-[2rem] p-4 h-[400px] overflow-auto shadow-inner space-y-2 border border-gray-100">
                     {availableOrders.length === 0 ? <p className="text-center py-10 text-gray-300 font-bold text-sm">No orders available.</p> : availableOrders.map(order => (
                       <div key={order.uuid} onClick={() => handleToggleOrder(order.uuid)} className={`p-4 rounded-2xl cursor-pointer transition-all border-2 flex items-center gap-4 ${selectedOrderUuids.has(order.uuid) ? 'bg-indigo-600 border-indigo-600 shadow-lg' : 'bg-white border-transparent'}`}>
                          <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center ${selectedOrderUuids.has(order.uuid) ? 'bg-white border-white' : 'border-gray-200'}`}>
                             {selectedOrderUuids.has(order.uuid) && <svg className="w-4 h-4 text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path d="M5 13l4 4L19 7" /></svg>}
                          </div>
                          <div className="flex-1">
                             <p className={`text-sm font-black ${selectedOrderUuids.has(order.uuid) ? 'text-white' : 'text-gray-900'}`}>{order.customer}</p>
                             <p className={`text-[10px] font-bold uppercase ${selectedOrderUuids.has(order.uuid) ? 'text-indigo-100' : 'text-gray-400'}`}>{order.city} • {order.qty} units</p>
                          </div>
                       </div>
                     ))}
                  </div>
               </div>
               <div className="space-y-6">
                  <div>
                    <label className="block text-xs font-black text-gray-500 mb-3 uppercase tracking-widest">Loading Proof</label>
                    <div className="grid grid-cols-3 gap-3">
                      {attachments.map((src, idx) => (
                        <div key={idx} className="relative aspect-square rounded-2xl overflow-hidden border-2 border-white shadow-md">
                          <img src={src} className="w-full h-full object-cover" />
                          <button onClick={() => setAttachments(p => p.filter((_, i) => i !== idx))} className="absolute top-1 right-1 bg-red-500 text-white p-1 rounded-full"><svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M6 18L18 6M6 6l12 12" strokeWidth={4} /></svg></button>
                        </div>
                      ))}
                      <button onClick={() => fileInputRef.current?.click()} className="aspect-square rounded-2xl border-2 border-dashed border-gray-200 text-gray-400 hover:bg-indigo-50 flex flex-col items-center justify-center shadow-inner">
                         <svg className="w-6 h-6 mb-1" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M12 4v16m8-8H4" /></svg>
                         <span className="text-[8px] font-black uppercase">Attach</span>
                      </button>
                    </div>
                    <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept="image/*" multiple />
                  </div>
                  <div>
                    <label className="block text-xs font-black text-gray-500 mb-2 uppercase tracking-widest">Shipment Note</label>
                    <textarea value={note} onChange={(e) => setNote(e.target.value)} className="w-full px-5 py-4 bg-gray-50 border-none rounded-[1.5rem] shadow-inner min-h-[140px] font-medium" placeholder="Trucking details..." />
                  </div>
               </div>
            </div>
            <div className="pt-6 border-t border-gray-50 flex gap-4">
              <button onClick={handleCreateShipment} className="flex-1 bg-indigo-600 text-white font-black py-5 rounded-[2rem] shadow-xl hover:bg-indigo-700 active:scale-95 uppercase tracking-widest text-sm">Archive Shipment</button>
              <button onClick={() => setIsCreating(false)} className="px-10 py-5 bg-gray-100 text-gray-400 font-black rounded-[2rem] uppercase tracking-widest text-xs">Cancel</button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-500 max-w-6xl mx-auto pb-24">
      <header className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <h2 className="text-4xl font-black text-gray-900 uppercase tracking-tighter">Shipment Archives</h2>
          <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest mt-1">Management Hub</p>
        </div>
        <button onClick={() => setIsCreating(true)} className="bg-indigo-600 text-white px-8 py-4 rounded-[1.75rem] font-black uppercase tracking-widest text-xs shadow-xl shadow-indigo-100 hover:bg-indigo-700 flex items-center gap-3">
          <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M12 4v16m8-8H4" /></svg>
          New Shipment
        </button>
      </header>

      <div className="bg-white p-4 md:p-6 rounded-[2rem] shadow-sm border border-gray-100 sticky top-[80px] z-30 flex flex-col md:flex-row gap-3">
        <div className="relative flex-1">
          <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"><svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg></span>
          <input type="text" placeholder="Ref search..." value={filterRef} onChange={(e) => setFilterRef(e.target.value)} className="w-full pl-12 pr-4 py-3.5 bg-gray-50 border-none rounded-2xl shadow-inner font-bold text-gray-900" />
        </div>
        <div className="flex gap-2">
           <button onClick={() => setIsFilterExpanded(!isFilterExpanded)} className={`px-6 py-3.5 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-2 border ${isFilterExpanded ? 'bg-indigo-600 text-white' : 'bg-white text-gray-500'}`}>Dates</button>
           {mode === StorageMode.ONLINE && <button onClick={fetchOnlineData} className={`p-3.5 bg-blue-50 text-blue-600 rounded-2xl ${isLoading ? 'animate-spin' : ''}`}><svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg></button>}
        </div>
      </div>

      {isFilterExpanded && (
        <div className="bg-white p-6 rounded-[2rem] shadow-xl border border-indigo-50 flex gap-4 animate-in slide-in-from-top-4">
           <input type="date" value={filterStartDate} onChange={e => setFilterStartDate(e.target.value)} className="flex-1 bg-gray-50 p-3 rounded-xl font-bold" />
           <input type="date" value={filterEndDate} onChange={e => setFilterEndDate(e.target.value)} className="flex-1 bg-gray-50 p-3 rounded-xl font-bold" />
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {isLoading && activeShipments.length === 0 ? <div className="col-span-full py-20 text-center text-indigo-600 font-black">Connecting...</div> : filteredShipments.length === 0 ? (
          <div className="col-span-full py-20 text-center bg-white rounded-[3rem] border-2 border-dashed border-gray-100">
            <p className="text-gray-300 font-black text-xl italic uppercase tracking-widest">No Shipments</p>
          </div>
        ) : filteredShipments.map(s => {
             const linked = s.orderUuids.map(uuid => activeOrders.find(o => o.uuid === uuid)).filter(Boolean) as Order[];
             return (
               <div key={s.uuid} className="bg-white rounded-[2.5rem] p-6 shadow-sm border border-gray-50 hover:shadow-2xl transition-all flex flex-col">
                 <div className="flex justify-between items-start mb-6">
                    <div>
                       <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest bg-indigo-50 px-3 py-1 rounded-full mb-2 inline-block">Ref: {s.reference}</span>
                       <h3 className="text-xl font-black text-gray-900">{linked.length} Orders</h3>
                       <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Disp: {new Date(s.dispatchDate).toLocaleDateString()}</p>
                    </div>
                    <div className="bg-indigo-600 rounded-2xl p-3 text-center min-w-[60px] shadow-lg">
                       <span className="block text-[8px] text-white opacity-70 font-black uppercase">Total Qty</span>
                       <span className="block text-xl font-black text-white leading-none">{linked.reduce((sum, o) => sum + o.qty, 0)}</span>
                    </div>
                 </div>
                 <div className="flex-1 mb-4">
                    <div className="flex flex-wrap gap-1.5 mb-3">{linked.slice(0, 3).map(o => <span key={o.uuid} className="text-[9px] font-bold text-gray-500 bg-gray-50 px-2 py-1 rounded-lg truncate">{o.customer}</span>)}</div>
                    {s.note && <p className="text-[11px] text-gray-500 italic bg-gray-50 p-3 rounded-xl border border-gray-100/50 line-clamp-2">{s.note}</p>}
                 </div>
                 {s.attachments.length > 0 && <div className="flex gap-2 overflow-x-auto no-scrollbar mb-4">{s.attachments.map((src, i) => <img key={i} src={src} className="w-16 h-16 rounded-xl object-cover border-2 border-white shadow-sm" />)}</div>}
                 <div className="flex justify-end pt-4 border-t border-gray-50"><button onClick={() => handleDeleteShipment(s)} className="p-3 bg-gray-50 text-gray-400 hover:text-red-600 rounded-xl transition-all shadow-sm"><svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button></div>
               </div>
             )
        })}
      </div>
    </div>
  );
};

export default Archive;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { db, Order, Shipment } from '../db';
import { useLiveQuery } from 'dexie-react-hooks';
import { StorageMode } from '../types';
import { getShipments, saveShipment, deleteShipment } from '../services/shipmentService';
import { getOrders } from '../services/orderService';
import { initSupabase } from '../services/syncService';

interface Props {
  mode: StorageMode;
}

const Archive: React.FC<Props> = ({ mode }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [selectedOrderUuids, setSelectedOrderUuids] = useState<Set<string>>(new Set());
  const [reference, setReference] = useState('');
  const [dispatchDate, setDispatchDate] = useState(new Date().toISOString().split('T')[0]);
  const [note, setNote] = useState('');
  const [attachments, setAttachments] = useState<string[]>([]);
  const [isProcessingImages, setIsProcessingImages] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Online data states
  const [onlineShipments, setOnlineShipments] = useState<Shipment[]>([]);
  const [onlineOrders, setOnlineOrders] = useState<Order[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  // Filter states
  const [filterRef, setFilterRef] = useState('');
  const [filterStartDate, setFilterStartDate] = useState('');
  const [filterEndDate, setFilterEndDate] = useState('');
  const [isFilterExpanded, setIsFilterExpanded] = useState(false);

  // Local data
  const localOrders = useLiveQuery(() => db.orders.toArray());
  const localShipments = useLiveQuery(() => db.shipments.toArray());

  const fetchOnlineData = async () => {
    if (mode !== StorageMode.ONLINE) return;
    setIsLoading(true);
    try {
      const [shipmentsData, ordersData] = await Promise.all([
        getShipments(StorageMode.ONLINE),
        getOrders(StorageMode.ONLINE)
      ]);
      setOnlineShipments(shipmentsData);
      setOnlineOrders(ordersData);
    } catch (err) {
      console.error("Archive Fetch Error:", err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (mode === StorageMode.ONLINE) {
      fetchOnlineData();
      const supabase = initSupabase();
      if (supabase) {
        const channel = supabase.channel('archive_realtime_v2')
          .on('postgres_changes', { event: '*', table: 'shipments' }, () => fetchOnlineData())
          .on('postgres_changes', { event: '*', table: 'orders' }, () => fetchOnlineData())
          .subscribe();
        return () => { supabase.removeChannel(channel); };
      }
    }
  }, [mode]);

  const activeShipments = mode === StorageMode.OFFLINE ? (localShipments || []) : onlineShipments;
  const activeOrders = mode === StorageMode.OFFLINE ? (localOrders || []) : onlineOrders;

  const availableOrders = useMemo(() => {
    const archivedUuids = new Set(activeShipments.flatMap(s => s.orderUuids));
    return activeOrders.filter(o => !archivedUuids.has(o.uuid));
  }, [activeOrders, activeShipments]);

  const filteredShipments = useMemo(() => {
    return activeShipments.filter(s => {
      const matchesRef = !filterRef || s.reference.toLowerCase().includes(filterRef.toLowerCase());
      const sDate = new Date(s.dispatchDate).setHours(0,0,0,0);
      const start = filterStartDate ? new Date(filterStartDate).setHours(0,0,0,0) : null;
      const end = filterEndDate ? new Date(filterEndDate).setHours(23,59,59,999) : null;
      return matchesRef && (!start || sDate >= start) && (!end || sDate <= end);
    }).sort((a, b) => b.dispatchDate - a.dispatchDate);
  }, [activeShipments, filterRef, filterStartDate, filterEndDate]);

  const handleToggleOrder = (uuid: string) => {
    const next = new Set(selectedOrderUuids);
    if (next.has(uuid)) next.delete(uuid);
    else next.add(uuid);
    setSelectedOrderUuids(next);
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    setIsProcessingImages(true);
    try {
      const readFileAsDataURL = (file: File): Promise<string> => {
        return new Promise((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = () => resolve(reader.result as string);
          reader.onerror = (error) => reject(error);
          reader.readAsDataURL(file);
        });
      };

      const downscaleImage = (dataUrl: string, maxWidth = 1200, quality = 0.7): Promise<string> => {
        return new Promise((resolve) => {
          const img = new Image();
          img.src = dataUrl;
          img.onload = () => {
            const canvas = document.createElement('canvas');
            let w = img.width, h = img.height;
            if (w > maxWidth) { h = (maxWidth / w) * h; w = maxWidth; }
            canvas.width = w; canvas.height = h;
            canvas.getContext('2d')?.drawImage(img, 0, 0, w, h);
            resolve(canvas.toDataURL('image/jpeg', quality));
          };
          img.onerror = () => resolve(dataUrl);
        });
      };

      const optimized = await Promise.all(Array.from(files).map(async f => downscaleImage(await readFileAsDataURL(f as File))));
      setAttachments(prev => [...prev, ...optimized]);
    } finally {
      setIsProcessingImages(false);
      if (e.target) e.target.value = '';
    }
  };

  const handleCreateShipment = async () => {
    if (!reference.trim() || selectedOrderUuids.size === 0 || !dispatchDate) {
      alert("Please fill all required fields: Reference, Date, and at least 1 Order."); 
      return;
    }

    const newShipment: Shipment = {
      uuid: crypto.randomUUID(),
      reference: reference.trim(),
      orderUuids: Array.from(selectedOrderUuids),
      attachments,
      note: note.trim(),
      dispatchDate: new Date(`${dispatchDate}T12:00:00`).getTime(),
      createdAt: Date.now(),
      updatedAt: Date.now()
    };

    try {
      await saveShipment(mode, newShipment);
      setReference(''); setNote(''); setAttachments([]); setSelectedOrderUuids(new Set());
      setDispatchDate(new Date().toISOString().split('T')[0]);
      setIsCreating(false);
      if (mode === StorageMode.ONLINE) fetchOnlineData();
    } catch (err) { alert("Archive creation failed."); }
  };

  const handleDeleteShipment = async (shipment: Shipment) => {
    if (confirm("Permanently delete this shipment record? Linked orders will return to available pool.")) {
      await deleteShipment(mode, shipment.id!, shipment.uuid);
      if (mode === StorageMode.ONLINE) fetchOnlineData();
    }
  };

  const hasActiveFilters = filterRef || filterStartDate || filterEndDate;

  if (isCreating) {
    return (
      <div className="max-w-4xl mx-auto animate-in fade-in slide-in-from-bottom-4 duration-500 pb-24 px-2">
        <div className="bg-white rounded-[3rem] shadow-2xl p-8 border border-gray-100 mb-8">
          <header className="mb-8 flex justify-between items-center">
            <div>
              <h2 className="text-3xl font-black text-gray-900 uppercase tracking-tighter">New Shipment</h2>
              <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest mt-1">
                {mode === StorageMode.ONLINE ? 'Supabase Cloud Record' : 'Offline Local Record'}
              </p>
            </div>
            <button onClick={() => setIsCreating(false)} className="text-gray-400 hover:text-gray-900 transition-colors">
              <svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </header>

          <div className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Reference (Truck # / Container #)</label>
                <input 
                  type="text" 
                  value={reference} 
                  onChange={(e) => setReference(e.target.value)} 
                  className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl shadow-inner font-black text-lg focus:ring-2 focus:ring-indigo-500 transition-all" 
                  placeholder="Ex: T-402-B" 
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Actual Dispatch Date</label>
                <input 
                  type="date" 
                  value={dispatchDate} 
                  onChange={(e) => setDispatchDate(e.target.value)} 
                  className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl shadow-inner font-bold outline-none focus:ring-2 focus:ring-indigo-500 transition-all" 
                />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
               <div className="flex flex-col">
                  <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-4 ml-1">Select Orders to Bundle ({selectedOrderUuids.size})</label>
                  <div className="bg-gray-50 rounded-[2.5rem] p-4 h-[400px] overflow-auto shadow-inner space-y-2 border border-gray-100 custom-scrollbar">
                     {availableOrders.length === 0 ? (
                       <div className="flex flex-col items-center justify-center h-full text-center">
                          <p className="text-gray-300 font-black text-lg italic uppercase tracking-widest">No Available Orders</p>
                          <p className="text-gray-400 text-[10px] font-bold uppercase mt-2">All orders are already archived.</p>
                       </div>
                     ) : availableOrders.map(order => (
                       <div 
                         key={order.uuid} 
                         onClick={() => handleToggleOrder(order.uuid)} 
                         className={`p-5 rounded-[1.75rem] cursor-pointer transition-all border-2 flex items-center gap-4 ${selectedOrderUuids.has(order.uuid) ? 'bg-indigo-600 border-indigo-600 shadow-xl' : 'bg-white border-transparent hover:border-indigo-100 hover:shadow-md'}`}
                       >
                          <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${selectedOrderUuids.has(order.uuid) ? 'bg-white border-white' : 'border-gray-200 bg-gray-50'}`}>
                             {selectedOrderUuids.has(order.uuid) && <svg className="w-4 h-4 text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path d="M5 13l4 4L19 7" /></svg>}
                          </div>
                          <div className="flex-1 truncate">
                             <p className={`text-sm font-black truncate ${selectedOrderUuids.has(order.uuid) ? 'text-white' : 'text-gray-900'}`}>{order.customer}</p>
                             <p className={`text-[10px] font-bold uppercase tracking-widest ${selectedOrderUuids.has(order.uuid) ? 'text-indigo-100' : 'text-gray-400'}`}>{order.city} • {order.qty} units</p>
                          </div>
                       </div>
                     ))}
                  </div>
               </div>

               <div className="space-y-8">
                  <div>
                    <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3 ml-1">Loading Proof Attachments</label>
                    <div className="grid grid-cols-3 gap-4">
                      {attachments.map((src, idx) => (
                        <div key={idx} className="relative aspect-square rounded-[1.5rem] overflow-hidden border-2 border-white shadow-lg group">
                          <img src={src} className="w-full h-full object-cover" alt="proof" />
                          <button 
                            onClick={() => setAttachments(p => p.filter((_, i) => i !== idx))} 
                            className="absolute top-2 right-2 bg-red-500 text-white p-2 rounded-full shadow-xl opacity-0 group-hover:opacity-100 transition-opacity"
                          >
                            <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={4}><path d="M6 18L18 6M6 6l12 12" /></svg>
                          </button>
                        </div>
                      ))}
                      <button 
                        onClick={() => fileInputRef.current?.click()} 
                        disabled={isProcessingImages}
                        className="aspect-square rounded-[1.5rem] border-2 border-dashed border-gray-200 text-gray-400 hover:bg-indigo-50 hover:border-indigo-200 hover:text-indigo-600 transition-all flex flex-col items-center justify-center shadow-inner group"
                      >
                         {isProcessingImages ? (
                           <div className="w-6 h-6 border-3 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
                         ) : (
                           <>
                             <svg className="w-8 h-8 mb-1 transition-transform group-hover:scale-110" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M12 4v16m8-8H4" /></svg>
                             <span className="text-[9px] font-black uppercase tracking-widest">Add Proof</span>
                           </>
                         )}
                      </button>
                    </div>
                    <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept="image/*" multiple />
                  </div>

                  <div>
                    <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Dispatch Notes</label>
                    <textarea 
                      value={note} 
                      onChange={(e) => setNote(e.target.value)} 
                      className="w-full px-6 py-5 bg-gray-50 border-none rounded-[2rem] shadow-inner min-h-[140px] font-medium focus:ring-2 focus:ring-indigo-500 transition-all" 
                      placeholder="Enter carrier info, driver phone, or special loading instructions..." 
                    />
                  </div>
               </div>
            </div>

            <div className="pt-8 border-t border-gray-100 flex gap-4">
              <button 
                onClick={handleCreateShipment} 
                className={`flex-1 font-black py-5 rounded-[2.25rem] shadow-2xl transition-all active:scale-95 uppercase tracking-widest text-sm ${mode === StorageMode.ONLINE ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-100' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100'} text-white`}
              >
                Seal & Archive Shipment
              </button>
              <button 
                onClick={() => setIsCreating(false)} 
                className="px-12 py-5 bg-gray-100 text-gray-500 font-black rounded-[2.25rem] hover:bg-gray-200 transition-all uppercase tracking-widest text-xs"
              >
                Discard
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-500 max-w-6xl mx-auto pb-24 px-2">
      <header className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h2 className="text-4xl font-black text-gray-900 uppercase tracking-tighter">Shipment Archives</h2>
          <p className="text-gray-400 font-bold uppercase text-[10px] tracking-[0.3em] mt-1">Logistics & Grouping Hub</p>
        </div>
        <button 
          onClick={() => setIsCreating(true)} 
          className={`px-8 py-5 rounded-[1.75rem] font-black uppercase tracking-widest text-xs shadow-2xl transition-all flex items-center gap-3 active:scale-95 ${mode === StorageMode.ONLINE ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-100' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100'} text-white`}
        >
          <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M12 4v16m8-8H4" /></svg>
          Bundle New Shipment
        </button>
      </header>

      {/* Enhanced Filter Bar */}
      <div className="bg-white p-4 md:p-6 rounded-[2.5rem] shadow-xl shadow-gray-200/40 border border-gray-100 sticky top-[84px] z-30 flex flex-col md:flex-row gap-4">
        <div className="relative flex-1">
          <span className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400">
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}><path d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          </span>
          <input 
            type="text" 
            placeholder="Search by Shipment Ref..." 
            value={filterRef} 
            onChange={(e) => setFilterRef(e.target.value)} 
            className="w-full pl-14 pr-6 py-4 bg-gray-50 border-none rounded-2xl shadow-inner font-black text-gray-900 focus:ring-2 focus:ring-indigo-500 transition-all placeholder:text-gray-300" 
          />
        </div>
        <div className="flex gap-2">
           <button 
             onClick={() => setIsFilterExpanded(!isFilterExpanded)} 
             className={`px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-2 transition-all border ${isFilterExpanded ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg' : 'bg-white text-gray-500 border-gray-100 hover:bg-gray-50'}`}
           >
             <svg className={`w-4 h-4 transition-transform duration-300 ${isFilterExpanded ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M19 9l-7 7-7-7" /></svg>
             Period {(filterStartDate || filterEndDate) && <span className="w-2 h-2 rounded-full bg-red-500"></span>}
           </button>

           {mode === StorageMode.ONLINE && (
             <button 
               onClick={fetchOnlineData} 
               disabled={isLoading}
               className="p-4 bg-blue-50 text-blue-600 rounded-2xl hover:bg-blue-100 transition-all border border-blue-100"
             >
               <svg className={`w-6 h-6 ${isLoading ? 'animate-spin' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
             </button>
           )}

           {hasActiveFilters && (
              <button 
                onClick={() => { setFilterRef(''); setFilterStartDate(''); setFilterEndDate(''); }} 
                className="p-4 bg-red-50 text-red-500 rounded-2xl hover:bg-red-100 transition-all border border-red-100"
              >
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
           )}
        </div>
      </div>

      {isFilterExpanded && (
        <div className="bg-white p-6 rounded-[2.5rem] shadow-2xl shadow-indigo-100/50 border border-indigo-50 grid grid-cols-1 md:grid-cols-2 gap-6 animate-in slide-in-from-top-4 duration-300">
           <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Dispatched From</label>
              <input type="date" value={filterStartDate} onChange={e => setFilterStartDate(e.target.value)} className="w-full px-5 py-4 bg-gray-50 rounded-xl font-bold border-none focus:ring-2 focus:ring-indigo-500 shadow-inner" />
           </div>
           <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Dispatched To</label>
              <input type="date" value={filterEndDate} onChange={e => setFilterEndDate(e.target.value)} className="w-full px-5 py-4 bg-gray-50 rounded-xl font-bold border-none focus:ring-2 focus:ring-indigo-500 shadow-inner" />
           </div>
        </div>
      )}

      {/* Shipment Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {isLoading && activeShipments.length === 0 ? (
          <div className="col-span-full py-32 text-center">
             <div className="w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mx-auto mb-6"></div>
             <p className="text-indigo-600 font-black uppercase tracking-widest text-lg">Loading Logistics Data...</p>
          </div>
        ) : filteredShipments.length === 0 ? (
          <div className="col-span-full py-32 text-center bg-white rounded-[4rem] border-4 border-dashed border-gray-100">
            <div className="w-24 h-24 bg-gray-50 rounded-[2.5rem] flex items-center justify-center mx-auto mb-6 text-gray-200">
               <svg className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}><path d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" /></svg>
            </div>
            <p className="text-gray-300 font-black text-2xl italic uppercase tracking-tighter">No Shipment Records</p>
            <p className="text-gray-400 text-[11px] font-bold uppercase mt-2 tracking-widest">Adjust filters or create your first bundle</p>
          </div>
        ) : filteredShipments.map(s => {
             const linked = s.orderUuids.map(uuid => activeOrders.find(o => o.uuid === uuid)).filter(Boolean) as Order[];
             const totalQty = linked.reduce((sum, o) => sum + o.qty, 0);

             return (
               <div key={s.uuid} className="bg-white rounded-[3rem] p-8 shadow-sm border border-gray-50 hover:shadow-2xl hover:shadow-indigo-100/50 transition-all duration-500 flex flex-col group relative overflow-hidden">
                 {/* Decorative background accent */}
                 <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-50/30 rounded-full -mr-16 -mt-16 group-hover:bg-indigo-100/50 transition-colors"></div>

                 <div className="flex justify-between items-start mb-8 relative z-10">
                    <div className="flex-1 truncate mr-4">
                       <span className={`text-[10px] font-black uppercase tracking-widest px-3 py-1 rounded-full mb-3 inline-block shadow-sm ${mode === StorageMode.ONLINE ? 'bg-blue-50 text-blue-600' : 'bg-indigo-50 text-indigo-600'}`}>
                         Ref: {s.reference}
                       </span>
                       <h3 className="text-2xl font-black text-gray-900 leading-tight truncate">{linked.length} Orders</h3>
                       <div className="flex items-center gap-2 mt-2">
                          <svg className="w-3.5 h-3.5 text-emerald-500" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                          <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Disp: {new Date(s.dispatchDate).toLocaleDateString()}</p>
                       </div>
                    </div>
                    <div className={`${mode === StorageMode.ONLINE ? 'bg-blue-600 shadow-blue-200' : 'bg-indigo-600 shadow-indigo-200'} rounded-2xl p-4 text-center min-w-[70px] shadow-xl group-hover:scale-110 transition-transform`}>
                       <span className="block text-[10px] text-white opacity-70 font-black uppercase tracking-tighter">Units</span>
                       <span className="block text-2xl font-black text-white leading-none mt-1">{totalQty.toLocaleString()}</span>
                    </div>
                 </div>

                 <div className="flex-1 mb-6 relative z-10">
                    <div className="flex flex-wrap gap-2 mb-4">
                       {linked.slice(0, 4).map(o => (
                         <span key={o.uuid} className="text-[9px] font-bold text-gray-600 bg-gray-50 border border-gray-100 px-2.5 py-1.5 rounded-xl truncate max-w-[120px]">
                           {o.customer}
                         </span>
                       ))}
                       {linked.length > 4 && (
                          <span className="text-[9px] font-black text-indigo-400 bg-indigo-50 px-2.5 py-1.5 rounded-xl">+{linked.length - 4} More</span>
                       )}
                    </div>
                    {s.note && (
                       <p className="text-sm font-medium text-gray-500 italic bg-gray-50/50 p-4 rounded-2xl border border-gray-100/50 line-clamp-2 leading-relaxed">
                          {s.note}
                       </p>
                    )}
                 </div>

                 {s.attachments.length > 0 && (
                    <div className="flex gap-3 overflow-x-auto no-scrollbar mb-6 relative z-10 pb-2">
                       {s.attachments.map((src, i) => (
                          <img key={i} src={src} className="w-16 h-16 rounded-[1.25rem] object-cover border-2 border-white shadow-md flex-shrink-0 hover:scale-105 transition-transform" alt="loading-proof" />
                       ))}
                    </div>
                 )}

                 <div className="flex justify-end gap-3 pt-6 border-t border-gray-50 relative z-10">
                    <button className="p-3.5 bg-gray-50 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all shadow-sm">
                       <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}><path d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /><path d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" /></svg>
                    </button>
                    <button 
                      onClick={() => handleDeleteShipment(s)} 
                      className="p-3.5 bg-gray-50 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all shadow-sm"
                    >
                       <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                    </button>
                 </div>
               </div>
             )
        })}
      </div>
    </div>
  );
};

export default Archive;

// Fixed: Using named import for Dexie to ensure proper inheritance of instance methods in TypeScript.
import { Dexie } from 'dexie';
import type { Table } from 'dexie';

export interface Order {
  id?: number;
  uuid: string; // Globally unique identifier for cloud sync
  customer: string;
  city: string;
  material: string;
  qty: number;
  status: string;
  createdAt: number;
  updatedAt: number; // Timestamp for sync resolution
  note?: string;
  attachments?: string[]; // Array of base64 strings
}

export interface Shipment {
  id?: number;
  uuid: string;
  reference: string;
  orderUuids: string[];
  attachments: string[];
  createdAt: number;
  updatedAt: number;
  dispatchDate: number; // New: Actual date of dispatch/loading
  note?: string;
}

export interface MasterItem {
  id?: number;
  name: string;
}

// Fixed inheritance visibility: Using named import for Dexie to ensure that instance methods like 'version' are correctly inherited and recognized by the TypeScript compiler on the subclass.
export class OrderTrackerDB extends Dexie {
  orders!: Table<Order>;
  shipments!: Table<Shipment>;
  customersMaster!: Table<MasterItem>;
  citiesMaster!: Table<MasterItem>;
  materialsMaster!: Table<MasterItem>;

  constructor() {
    super('OrderTrackerDB');

    // Updated schema to version 9: Added dispatchDate to shipments.
    this.version(9).stores({
      orders: '++id, &uuid, customer, city, material, qty, status, createdAt, updatedAt',
      shipments: '++id, &uuid, reference, *orderUuids, createdAt, dispatchDate',
      customersMaster: '++id, &name',
      citiesMaster: '++id, &name',
      materialsMaster: '++id, &name'
    });
  }
}

export const db = new OrderTrackerDB();

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { db, Order, Shipment } from '../db';
import { useLiveQuery } from 'dexie-react-hooks';
import { StorageMode } from '../types';
import { getShipments, saveShipment, deleteShipment } from '../services/shipmentService';
import { getOrders } from '../services/orderService';
import { initSupabase } from '../services/syncService';

interface Props {
  mode: StorageMode;
}

const Archive: React.FC<Props> = ({ mode }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [selectedOrderUuids, setSelectedOrderUuids] = useState<Set<string>>(new Set());
  const [reference, setReference] = useState('');
  const [dispatchDate, setDispatchDate] = useState(new Date().toISOString().split('T')[0]);
  const [note, setNote] = useState('');
  const [attachments, setAttachments] = useState<string[]>([]);
  const [isProcessingImages, setIsProcessingImages] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Online data states
  const [onlineShipments, setOnlineShipments] = useState<Shipment[]>([]);
  const [onlineOrders, setOnlineOrders] = useState<Order[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  // Filter states
  const [filterRef, setFilterRef] = useState('');
  const [filterStartDate, setFilterStartDate] = useState('');
  const [filterEndDate, setFilterEndDate] = useState('');
  const [isFilterExpanded, setIsFilterExpanded] = useState(false);

  // Local data
  const localOrders = useLiveQuery(() => db.orders.toArray());
  const localShipments = useLiveQuery(() => db.shipments.toArray());

  const fetchOnlineData = async () => {
    if (mode !== StorageMode.ONLINE) return;
    setIsLoading(true);
    try {
      const [shipmentsData, ordersData] = await Promise.all([
        getShipments(StorageMode.ONLINE),
        getOrders(StorageMode.ONLINE)
      ]);
      setOnlineShipments(shipmentsData || []);
      setOnlineOrders(ordersData || []);
    } catch (err) {
      console.error("Archive Fetch Error:", err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (mode === StorageMode.ONLINE) {
      fetchOnlineData();
      const supabase = initSupabase();
      if (supabase) {
        const channel = supabase.channel('archive_realtime_v3')
          .on('postgres_changes', { event: '*', table: 'shipments' }, () => fetchOnlineData())
          .on('postgres_changes', { event: '*', table: 'orders' }, () => fetchOnlineData())
          .subscribe();
        return () => { supabase.removeChannel(channel); };
      }
    }
  }, [mode]);

  const activeShipments: Shipment[] = mode === StorageMode.OFFLINE ? (localShipments || []) : onlineShipments;
  const activeOrders: Order[] = mode === StorageMode.OFFLINE ? (localOrders || []) : onlineOrders;

  const availableOrders = useMemo(() => {
    // Explicitly using reduce for maximum compatibility and type safety
    const archivedUuids = new Set<string>(
      activeShipments.reduce((acc: string[], s: Shipment) => [...acc, ...s.orderUuids], [] as string[])
    );
    return activeOrders.filter(o => !archivedUuids.has(o.uuid));
  }, [activeOrders, activeShipments]);

  const filteredShipments = useMemo(() => {
    return activeShipments.filter(s => {
      const matchesRef = !filterRef || s.reference.toLowerCase().includes(filterRef.toLowerCase());

      const sDate = new Date(s.dispatchDate).setHours(0,0,0,0);
      const start = filterStartDate ? new Date(filterStartDate).setHours(0,0,0,0) : null;
      const end = filterEndDate ? new Date(filterEndDate).setHours(23,59,59,999) : null;

      const matchesStart = !start || sDate >= start;
      const matchesEnd = !end || sDate <= end;

      return matchesRef && matchesStart && matchesEnd;
    }).sort((a, b) => b.dispatchDate - a.dispatchDate);
  }, [activeShipments, filterRef, filterStartDate, filterEndDate]);

  const handleToggleOrder = (uuid: string) => {
    const next = new Set(selectedOrderUuids);
    if (next.has(uuid)) next.delete(uuid);
    else next.add(uuid);
    setSelectedOrderUuids(next);
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    setIsProcessingImages(true);
    try {
      const readFileAsDataURL = (file: File): Promise<string> => {
        return new Promise((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = () => resolve(reader.result as string);
          reader.onerror = (error) => reject(error);
          reader.readAsDataURL(file);
        });
      };

      const downscaleImage = (dataUrl: string, maxWidth = 1200, quality = 0.7): Promise<string> => {
        return new Promise((resolve) => {
          const img = new Image();
          img.src = dataUrl;
          img.onload = () => {
            const canvas = document.createElement('canvas');
            let w = img.width;
            let h = img.height;
            if (w > maxWidth) {
              h = (maxWidth / w) * h;
              w = maxWidth;
            }
            canvas.width = w;
            canvas.height = h;
            const ctx = canvas.getContext('2d');
            ctx?.drawImage(img, 0, 0, w, h);
            resolve(canvas.toDataURL('image/jpeg', quality));
          };
          img.onerror = () => resolve(dataUrl);
        });
      };

      const fileArray = Array.from(files);
      const optimized = await Promise.all(
        fileArray.map(async (f: File) => {
          const dataUrl = await readFileAsDataURL(f);
          return downscaleImage(dataUrl);
        })
      );
      setAttachments(prev => [...prev, ...optimized]);
    } finally {
      setIsProcessingImages(false);
      if (e.target) e.target.value = '';
    }
  };

  const handleCreateShipment = async () => {
    if (!reference.trim() || selectedOrderUuids.size === 0 || !dispatchDate) {
      alert("Required: Reference, Dispatch Date, and at least one order.");
      return;
    }

    const newShipment: Shipment = {
      uuid: crypto.randomUUID(),
      reference: reference.trim(),
      orderUuids: Array.from(selectedOrderUuids),
      attachments,
      note: note.trim(),
      dispatchDate: new Date(`${dispatchDate}T12:00:00`).getTime(),
      createdAt: Date.now(),
      updatedAt: Date.now()
    };

    try {
      await saveShipment(mode, newShipment);
      setReference('');
      setNote('');
      setAttachments([]);
      setSelectedOrderUuids(new Set());
      setDispatchDate(new Date().toISOString().split('T')[0]);
      setIsCreating(false);
      if (mode === StorageMode.ONLINE) fetchOnlineData();
    } catch (err) {
      alert("Save failed.");
    }
  };

  const handleDeleteShipment = async (shipment: Shipment) => {
    if (confirm("Delete this archive bundle? Linked orders will return to history for re-bundling.")) {
      await deleteShipment(mode, shipment.id!, shipment.uuid);
      if (mode === StorageMode.ONLINE) fetchOnlineData();
    }
  };

  const hasActiveFilters = filterRef || filterStartDate || filterEndDate;

  if (isCreating) {
    return (
      <div className="max-w-4xl mx-auto animate-in fade-in slide-in-from-bottom-4 duration-500 pb-24 px-2">
        <div className="bg-white rounded-[3rem] shadow-2xl p-8 border border-gray-100 mb-8">
          <header className="mb-8 flex justify-between items-center">
            <div>
              <h2 className="text-3xl font-black text-gray-900 uppercase tracking-tighter">New Shipment</h2>
              <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest mt-1">
                {mode === StorageMode.ONLINE ? 'Supabase Live' : 'Standalone Local'} Mode
              </p>
            </div>
            <button onClick={() => setIsCreating(false)} className="text-gray-400 hover:text-gray-900 transition-colors">
              <svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </header>

          <div className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Shipment Reference (Truck/CNTR)</label>
                <input
                  type="text"
                  value={reference}
                  onChange={(e) => setReference(e.target.value)}
                  className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl shadow-inner font-black text-lg focus:ring-2 focus:ring-indigo-500 transition-all"
                  placeholder="Ex: T-402-B"
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Actual Dispatch Date</label>
                <input
                  type="date"
                  value={dispatchDate}
                  onChange={(e) => setDispatchDate(e.target.value)}
                  className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl shadow-inner font-bold outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
                />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
               <div className="flex flex-col">
                  <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-4 ml-1">Select Orders ({selectedOrderUuids.size})</label>
                  <div className="bg-gray-50 rounded-[2.5rem] p-4 h-[400px] overflow-auto shadow-inner space-y-2 border border-gray-100">
                     {availableOrders.length === 0 ? (
                        <div className="flex flex-col items-center justify-center h-full text-center p-8">
                           <p className="text-gray-300 font-black text-lg italic uppercase tracking-widest">No available orders</p>
                           <p className="text-gray-400 text-[10px] font-bold uppercase mt-2">All orders are already in shipments.</p>
                        </div>
                     ) : (
                        availableOrders.map(order => (
                           <div 
                             key={order.uuid} 
                             onClick={() => handleToggleOrder(order.uuid)}
                             className={`p-5 rounded-[1.75rem] cursor-pointer transition-all border-2 flex items-center gap-4 ${selectedOrderUuids.has(order.uuid) ? 'bg-indigo-600 border-indigo-600 shadow-xl' : 'bg-white border-transparent hover:border-indigo-100'}`}
                           >
                              <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${selectedOrderUuids.has(order.uuid) ? 'bg-white border-white' : 'border-gray-200'}`}>
                                 {selectedOrderUuids.has(order.uuid) && <svg className="w-4 h-4 text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path d="M5 13l4 4L19 7" /></svg>}
                              </div>
                              <div className="flex-1 truncate">
                                 <p className={`text-sm font-black ${selectedOrderUuids.has(order.uuid) ? 'text-white' : 'text-gray-900'}`}>{order.customer}</p>
                                 <p className={`text-[10px] font-bold uppercase tracking-widest ${selectedOrderUuids.has(order.uuid) ? 'text-indigo-100' : 'text-gray-400'}`}>{order.city} • {order.qty} units</p>
                              </div>
                           </div>
                        ))
                     )}
                  </div>
               </div>

               <div className="space-y-8">
                  <div>
                    <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3 ml-1">Loading Proof Photos</label>
                    <div className="grid grid-cols-3 gap-4">
                      {attachments.map((src, idx) => (
                        <div key={idx} className="relative aspect-square rounded-[1.5rem] overflow-hidden border-2 border-white shadow-lg group">
                          <img src={src} className="w-full h-full object-cover" alt="proof" />
                          <button 
                            type="button"
                            onClick={() => setAttachments(p => p.filter((_, i) => i !== idx))}
                            className="absolute top-2 right-2 bg-red-500 text-white p-2 rounded-full shadow-xl opacity-0 group-hover:opacity-100 transition-opacity"
                          >
                            <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={4}><path d="M6 18L18 6M6 6l12 12" /></svg>
                          </button>
                        </div>
                      ))}
                      <button
                        type="button"
                        onClick={() => fileInputRef.current?.click()}
                        disabled={isProcessingImages}
                        className="aspect-square rounded-[1.5rem] border-2 border-dashed border-gray-200 text-gray-400 hover:bg-indigo-50 hover:border-indigo-200 hover:text-indigo-600 transition-all flex flex-col items-center justify-center shadow-inner group"
                      >
                         {isProcessingImages ? (
                           <div className="w-6 h-6 border-3 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
                         ) : (
                           <>
                            <svg className="w-8 h-8 mb-1 group-hover:scale-110 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M12 4v16m8-8H4" /></svg>
                            <span className="text-[9px] font-black uppercase tracking-widest">Attach Proof</span>
                           </>
                         )}
                      </button>
                    </div>
                    <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept="image/*" multiple />
                  </div>

                  <div>
                    <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Dispatch Notes</label>
                    <textarea
                      value={note}
                      onChange={(e) => setNote(e.target.value)}
                      className="w-full px-6 py-5 bg-gray-50 border-none rounded-[2rem] shadow-inner min-h-[140px] font-medium focus:ring-2 focus:ring-indigo-500 transition-all"
                      placeholder="Driver info, carrier ID, or loading details..."
                    />
                  </div>
               </div>
            </div>

            <div className="pt-8 border-t border-gray-100 flex gap-4">
              <button 
                onClick={handleCreateShipment}
                className={`flex-1 font-black py-5 rounded-[2.25rem] shadow-2xl transition-all active:scale-95 uppercase tracking-widest text-sm ${mode === StorageMode.ONLINE ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-200' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100'} text-white`}
              >
                Seal & Archive Bundle
              </button>
              <button onClick={() => setIsCreating(false)} className="px-12 py-5 bg-gray-100 text-gray-500 font-black rounded-[2.25rem] hover:bg-gray-200 transition-all uppercase tracking-widest text-xs">Cancel</button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-500 max-w-6xl mx-auto pb-24 px-2">
      <header className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h2 className="text-4xl font-black text-gray-900 uppercase tracking-tighter">Shipment Archives</h2>
          <p className="text-gray-400 font-bold uppercase text-[10px] tracking-[0.3em] mt-1">Management Hub</p>
        </div>
        <button 
          onClick={() => setIsCreating(true)}
          className={`px-8 py-5 rounded-[1.75rem] font-black uppercase tracking-widest text-xs shadow-2xl transition-all flex items-center gap-3 active:scale-95 ${mode === StorageMode.ONLINE ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-100' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100'} text-white`}
        >
          <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M12 4v16m8-8H4" /></svg>
          Bundle New Shipment
        </button>
      </header>

      {/* Filter Bar */}
      <div className="bg-white p-4 md:p-6 rounded-[2.5rem] shadow-xl shadow-gray-200/40 border border-gray-100 sticky top-[84px] z-30 flex flex-col md:flex-row gap-4">
        <div className="relative flex-1 w-full">
          <span className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400">
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}><path d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          </span>
          <input
            type="text"
            placeholder="Search by Shipment Ref..."
            value={filterRef}
            onChange={(e) => setFilterRef(e.target.value)}
            className="w-full pl-14 pr-6 py-4 bg-gray-50 border-none rounded-2xl shadow-inner font-black text-gray-900 focus:ring-2 focus:ring-indigo-500 transition-all placeholder:text-gray-300"
          />
        </div>
        <div className="flex gap-2">
          <button 
            onClick={() => setIsFilterExpanded(!isFilterExpanded)}
            className={`px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-2 transition-all border ${isFilterExpanded ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg shadow-indigo-100' : 'bg-white text-gray-500 border-gray-100 hover:bg-gray-50'}`}
          >
            <svg className={`w-4 h-4 transition-transform duration-300 ${isFilterExpanded ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M19 9l-7 7-7-7" /></svg>
            Period {hasActiveFilters && <span className="w-2 h-2 rounded-full bg-red-500"></span>}
          </button>

          {mode === StorageMode.ONLINE && (
            <button 
              onClick={fetchOnlineData}
              className={`p-4 bg-blue-50 text-blue-600 rounded-2xl hover:bg-blue-100 transition-all border border-blue-100 ${isLoading ? 'animate-spin' : ''}`}
            >
              <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
            </button>
          )}

          {hasActiveFilters && (
            <button 
              onClick={() => { setFilterRef(''); setFilterStartDate(''); setFilterEndDate(''); }} 
              className="p-4 bg-red-50 text-red-500 rounded-2xl hover:bg-red-100 transition-all border border-red-100"
            >
              <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          )}
        </div>
      </div>

      {isFilterExpanded && (
        <div className="bg-white p-6 rounded-[2.5rem] shadow-2xl shadow-indigo-100/50 border border-indigo-50 grid grid-cols-1 md:grid-cols-2 gap-6 animate-in slide-in-from-top-4 duration-300">
           <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Dispatch Range (From)</label>
              <input type="date" value={filterStartDate} onChange={e => setFilterStartDate(e.target.value)} className="w-full px-5 py-4 bg-gray-50 rounded-xl font-bold border-none focus:ring-2 focus:ring-indigo-500 shadow-inner" />
           </div>
           <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Dispatch Range (To)</label>
              <input type="date" value={filterEndDate} onChange={e => setFilterEndDate(e.target.value)} className="w-full px-5 py-4 bg-gray-50 rounded-xl font-bold border-none focus:ring-2 focus:ring-indigo-500 shadow-inner" />
           </div>
        </div>
      )}

      {/* Shipment Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {isLoading && activeShipments.length === 0 ? (
          <div className="col-span-full py-32 text-center">
             <div className="w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mx-auto mb-6"></div>
             <p className="text-indigo-600 font-black uppercase tracking-widest text-lg">Fetching Archives...</p>
          </div>
        ) : filteredShipments.length === 0 ? (
          <div className="col-span-full py-32 text-center bg-white rounded-[4rem] border-4 border-dashed border-gray-100">
            <div className="w-24 h-24 bg-gray-50 rounded-[2.5rem] flex items-center justify-center mx-auto mb-6 text-gray-200">
               <svg className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}><path d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" /></svg>
            </div>
            <p className="text-gray-300 font-black text-2xl italic uppercase tracking-tighter">No Bundles Found</p>
            <p className="text-gray-400 text-[11px] font-bold uppercase mt-2 tracking-widest">Bundle existing orders into a shipment reference.</p>
          </div>
        ) : (
          filteredShipments.map(shipment => {
             const linked = shipment.orderUuids.map(uuid => activeOrders.find(o => o.uuid === uuid)).filter(Boolean) as Order[];
             const totalQty = linked.reduce((sum, o) => sum + o.qty, 0);

             return (
               <div key={shipment.uuid} className="bg-white rounded-[3rem] p-8 shadow-sm border border-gray-50 hover:shadow-2xl hover:shadow-indigo-100/50 transition-all duration-500 flex flex-col group relative overflow-hidden">
                 <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-50/30 rounded-full -mr-16 -mt-16 group-hover:bg-indigo-100/50 transition-colors"></div>

                 <div className="flex justify-between items-start mb-8 relative z-10">
                    <div className="flex-1 truncate mr-4">
                       <span className={`text-[10px] font-black uppercase tracking-widest px-3 py-1 rounded-full mb-3 inline-block shadow-sm ${mode === StorageMode.ONLINE ? 'bg-blue-50 text-blue-600' : 'bg-indigo-50 text-indigo-600'}`}>
                         Ref: {shipment.reference}
                       </span>
                       <h3 className="text-2xl font-black text-gray-900 leading-tight truncate">{linked.length} Order{linked.length !== 1 ? 's' : ''}</h3>
                       <div className="flex items-center gap-2 mt-2">
                          <svg className="w-3.5 h-3.5 text-emerald-500" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                          <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Disp: {new Date(shipment.dispatchDate).toLocaleDateString()}</p>
                       </div>
                    </div>
                    <div className={`${mode === StorageMode.ONLINE ? 'bg-blue-600 shadow-blue-200' : 'bg-indigo-600 shadow-indigo-200'} rounded-2xl p-4 text-center min-w-[70px] shadow-xl group-hover:scale-110 transition-transform`}>
                       <span className="block text-[10px] text-white opacity-70 font-black uppercase tracking-tighter">Units</span>
                       <span className="block text-2xl font-black text-white leading-none mt-1">{totalQty.toLocaleString()}</span>
                    </div>
                 </div>

                 <div className="flex-1 mb-6 relative z-10">
                    <div className="flex flex-wrap gap-2 mb-4">
                       {linked.slice(0, 4).map(o => (
                          <span key={o.uuid} className="text-[9px] font-bold text-gray-600 bg-gray-50 border border-gray-100 px-2.5 py-1.5 rounded-xl truncate max-w-[120px]">{o.customer}</span>
                       ))}
                       {linked.length > 4 && (
                          <span className="text-[9px] font-black text-indigo-400 bg-indigo-50 px-2.5 py-1.5 rounded-xl">+{linked.length - 4} More</span>
                       )}
                    </div>
                    {shipment.note && (
                       <p className="text-sm font-medium text-gray-500 italic bg-gray-50/50 p-4 rounded-2xl border border-gray-100/50 line-clamp-2 leading-relaxed">
                          {shipment.note}
                       </p>
                    )}
                 </div>

                 {shipment.attachments.length > 0 && (
                    <div className="flex gap-3 overflow-x-auto no-scrollbar mb-6 relative z-10 pb-2">
                       {shipment.attachments.map((src, i) => (
                          <img key={i} src={src} className="w-16 h-16 rounded-[1.25rem] object-cover border-2 border-white shadow-md flex-shrink-0 hover:scale-105 transition-transform" alt="loading-proof" />
                       ))}
                    </div>
                 )}

                 <div className="flex justify-end gap-3 pt-6 border-t border-gray-50 relative z-10">
                    <button 
                      onClick={() => handleDeleteShipment(shipment)}
                      className="p-3.5 bg-gray-50 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all shadow-sm"
                      title="Un-bundle Shipment"
                    >
                       <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                    </button>
                 </div>
               </div>
             )
          })
        )}
      </div>
    </div>
  );
};

export default Archive;

import { Dexie, type Table } from 'dexie';

export interface Order {
  id?: number;
  uuid: string; // Globally unique identifier for cloud sync
  customer: string;
  city: string;
  material: string;
  qty: number;
  status: string;
  createdAt: number;
  updatedAt: number; // Timestamp for sync resolution
  note?: string;
  attachments?: string[]; // Array of base64 strings
}

export interface Shipment {
  id?: number;
  uuid: string;
  reference: string;
  orderUuids: string[];
  attachments: string[];
  createdAt: number;
  updatedAt: number;
  dispatchDate: number; // New: Actual date of dispatch/loading
  note?: string;
}

export interface MasterItem {
  id?: number;
  name: string;
}

export class OrderTrackerDB extends Dexie {
  orders!: Table<Order>;
  shipments!: Table<Shipment>;
  customersMaster!: Table<MasterItem>;
  citiesMaster!: Table<MasterItem>;
  materialsMaster!: Table<MasterItem>;

  constructor() {
    super('OrderTrackerDB');

    this.version(9).stores({
      orders: '++id, &uuid, customer, city, material, qty, status, createdAt, updatedAt',
      shipments: '++id, &uuid, reference, *orderUuids, createdAt, dispatchDate',
      customersMaster: '++id, &name',
      citiesMaster: '++id, &name',
      materialsMaster: '++id, &name'
    });
  }
}

export const db = new OrderTrackerDB();

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { db, Order, Shipment } from '../db';
import { useLiveQuery } from 'dexie-react-hooks';
import { StorageMode } from '../types';
import { getShipments, saveShipment, deleteShipment } from '../services/shipmentService';
import { getOrders } from '../services/orderService';
import { initSupabase } from '../services/syncService';

interface Props {
  mode: StorageMode;
}

const Archive: React.FC<Props> = ({ mode }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [selectedOrderUuids, setSelectedOrderUuids] = useState<Set<string>>(new Set());
  const [reference, setReference] = useState('');
  const [dispatchDate, setDispatchDate] = useState(new Date().toISOString().split('T')[0]);
  const [note, setNote] = useState('');
  const [attachments, setAttachments] = useState<string[]>([]);
  const [isProcessingImages, setIsProcessingImages] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Online data states
  const [onlineShipments, setOnlineShipments] = useState<Shipment[]>([]);
  const [onlineOrders, setOnlineOrders] = useState<Order[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  // Filter states
  const [filterRef, setFilterRef] = useState('');
  const [filterStartDate, setFilterStartDate] = useState('');
  const [filterEndDate, setFilterEndDate] = useState('');
  const [isFilterExpanded, setIsFilterExpanded] = useState(false);

  // Local data
  const localOrders = useLiveQuery(() => db.orders.toArray());
  const localShipments = useLiveQuery(() => db.shipments.toArray());

  const fetchOnlineData = async () => {
    if (mode !== StorageMode.ONLINE) return;
    setIsLoading(true);
    try {
      const [shipmentsData, ordersData] = await Promise.all([
        getShipments(StorageMode.ONLINE),
        getOrders(StorageMode.ONLINE)
      ]);
      setOnlineShipments(shipmentsData || []);
      setOnlineOrders(ordersData || []);
    } catch (err) {
      console.error("Archive Fetch Error:", err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (mode === StorageMode.ONLINE) {
      fetchOnlineData();
      const supabase = initSupabase();
      if (supabase) {
        const channel = supabase.channel('archive_realtime_v3_fixed')
          .on('postgres_changes', { event: '*', table: 'shipments' }, () => fetchOnlineData())
          .on('postgres_changes', { event: '*', table: 'orders' }, () => fetchOnlineData())
          .subscribe();
        return () => { supabase.removeChannel(channel); };
      }
    }
  }, [mode]);

  const activeShipments: Shipment[] = mode === StorageMode.OFFLINE ? (localShipments || []) : onlineShipments;
  const activeOrders: Order[] = mode === StorageMode.OFFLINE ? (localOrders || []) : onlineOrders;

  const availableOrders = useMemo(() => {
    // Fixed: Using explicit loops to avoid iterator/overload issues in Set constructor
    const archivedUuids = new Set<string>();
    activeShipments.forEach(s => {
      if (s.orderUuids && Array.isArray(s.orderUuids)) {
        s.orderUuids.forEach(uuid => archivedUuids.add(uuid));
      }
    });
    return activeOrders.filter(o => !archivedUuids.has(o.uuid));
  }, [activeOrders, activeShipments]);

  const filteredShipments = useMemo(() => {
    return activeShipments.filter(s => {
      const matchesRef = !filterRef || s.reference.toLowerCase().includes(filterRef.toLowerCase());

      const sDate = new Date(s.dispatchDate).setHours(0,0,0,0);
      const start = filterStartDate ? new Date(filterStartDate).setHours(0,0,0,0) : null;
      const end = filterEndDate ? new Date(filterEndDate).setHours(23,59,59,999) : null;

      const matchesStart = !start || sDate >= start;
      const matchesEnd = !end || sDate <= end;

      return matchesRef && matchesStart && matchesEnd;
    }).sort((a, b) => b.dispatchDate - a.dispatchDate);
  }, [activeShipments, filterRef, filterStartDate, filterEndDate]);

  const handleToggleOrder = (uuid: string) => {
    const next = new Set(selectedOrderUuids);
    if (next.has(uuid)) next.delete(uuid);
    else next.add(uuid);
    setSelectedOrderUuids(next);
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    setIsProcessingImages(true);
    try {
      const readFileAsDataURL = (file: File): Promise<string> => {
        return new Promise((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = () => resolve(reader.result as string);
          reader.onerror = (error) => reject(error);
          reader.readAsDataURL(file);
        });
      };

      const downscaleImage = (dataUrl: string, maxWidth = 1200, quality = 0.7): Promise<string> => {
        return new Promise((resolve) => {
          const img = new Image();
          img.src = dataUrl;
          img.onload = () => {
            const canvas = document.createElement('canvas');
            let w = img.width;
            let h = img.height;
            if (w > maxWidth) {
              h = (maxWidth / w) * h;
              w = maxWidth;
            }
            canvas.width = w;
            canvas.height = h;
            const ctx = canvas.getContext('2d');
            ctx?.drawImage(img, 0, 0, w, h);
            resolve(canvas.toDataURL('image/jpeg', quality));
          };
          img.onerror = () => resolve(dataUrl);
        });
      };

      const fileArray: File[] = Array.from(files);
      const optimized = await Promise.all(
        fileArray.map(async (f: File) => {
          const dataUrl = await readFileAsDataURL(f);
          return downscaleImage(dataUrl);
        })
      );
      setAttachments(prev => [...prev, ...optimized]);
    } catch (err) {
      console.error("Error processing archive images", err);
    } finally {
      setIsProcessingImages(false);
      if (e.target) e.target.value = '';
    }
  };

  const handleCreateShipment = async () => {
    if (!reference.trim() || selectedOrderUuids.size === 0 || !dispatchDate) {
      alert("Required: Reference, Dispatch Date, and at least one order.");
      return;
    }

    const newShipment: Shipment = {
      uuid: crypto.randomUUID(),
      reference: reference.trim(),
      orderUuids: Array.from(selectedOrderUuids),
      attachments,
      note: note.trim(),
      dispatchDate: new Date(`${dispatchDate}T12:00:00`).getTime(),
      createdAt: Date.now(),
      updatedAt: Date.now()
    };

    try {
      await saveShipment(mode, newShipment);
      setReference('');
      setNote('');
      setAttachments([]);
      setSelectedOrderUuids(new Set());
      setDispatchDate(new Date().toISOString().split('T')[0]);
      setIsCreating(false);
      if (mode === StorageMode.ONLINE) fetchOnlineData();
    } catch (err) {
      alert("Save failed.");
    }
  };

  const handleDeleteShipment = async (shipment: Shipment) => {
    if (confirm("Delete this archive bundle? Linked orders will return to history for re-bundling.")) {
      await deleteShipment(mode, shipment.id!, shipment.uuid);
      if (mode === StorageMode.ONLINE) fetchOnlineData();
    }
  };

  const hasActiveFilters = filterRef || filterStartDate || filterEndDate;

  if (isCreating) {
    return (
      <div className="max-w-4xl mx-auto animate-in fade-in slide-in-from-bottom-4 duration-500 pb-24 px-2">
        <div className="bg-white rounded-[3rem] shadow-2xl p-8 border border-gray-100 mb-8">
          <header className="mb-8 flex justify-between items-center">
            <div>
              <h2 className="text-3xl font-black text-gray-900 uppercase tracking-tighter">New Shipment</h2>
              <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest mt-1">
                {mode === StorageMode.ONLINE ? 'Supabase Live' : 'Standalone Local'} Mode
              </p>
            </div>
            <button onClick={() => setIsCreating(false)} className="text-gray-400 hover:text-gray-900 transition-colors">
              <svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </header>

          <div className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Shipment Reference (Truck/CNTR)</label>
                <input
                  type="text"
                  value={reference}
                  onChange={(e) => setReference(e.target.value)}
                  className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl shadow-inner font-black text-lg focus:ring-2 focus:ring-indigo-500 transition-all"
                  placeholder="Ex: T-402-B"
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Actual Dispatch Date</label>
                <input
                  type="date"
                  value={dispatchDate}
                  onChange={(e) => setDispatchDate(e.target.value)}
                  className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl shadow-inner font-bold outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
                />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
               <div className="flex flex-col">
                  <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-4 ml-1">Select Orders ({selectedOrderUuids.size})</label>
                  <div className="bg-gray-50 rounded-[2.5rem] p-4 h-[400px] overflow-auto shadow-inner space-y-2 border border-gray-100 custom-scrollbar">
                     {availableOrders.length === 0 ? (
                        <div className="flex flex-col items-center justify-center h-full text-center p-8">
                           <p className="text-gray-300 font-black text-lg italic uppercase tracking-widest">No available orders</p>
                           <p className="text-gray-400 text-[10px] font-bold uppercase mt-2">All orders are already in shipments.</p>
                        </div>
                     ) : (
                        availableOrders.map(order => (
                           <div 
                             key={order.uuid} 
                             onClick={() => handleToggleOrder(order.uuid)}
                             className={`p-5 rounded-[1.75rem] cursor-pointer transition-all border-2 flex items-center gap-4 ${selectedOrderUuids.has(order.uuid) ? 'bg-indigo-600 border-indigo-600 shadow-xl' : 'bg-white border-transparent hover:border-indigo-100'}`}
                           >
                              <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${selectedOrderUuids.has(order.uuid) ? 'bg-white border-white' : 'border-gray-200'}`}>
                                 {selectedOrderUuids.has(order.uuid) && <svg className="w-4 h-4 text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path d="M5 13l4 4L19 7" /></svg>}
                              </div>
                              <div className="flex-1 truncate">
                                 <p className={`text-sm font-black ${selectedOrderUuids.has(order.uuid) ? 'text-white' : 'text-gray-900'}`}>{order.customer}</p>
                                 <p className={`text-[10px] font-bold uppercase tracking-widest ${selectedOrderUuids.has(order.uuid) ? 'text-indigo-100' : 'text-gray-400'}`}>{order.city} • {order.qty} units</p>
                              </div>
                           </div>
                        ))
                     )}
                  </div>
               </div>

               <div className="space-y-8">
                  <div>
                    <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3 ml-1">Loading Proof Photos</label>
                    <div className="grid grid-cols-3 gap-4">
                      {attachments.map((src, idx) => (
                        <div key={idx} className="relative aspect-square rounded-[1.5rem] overflow-hidden border-2 border-white shadow-lg group">
                          <img src={src} className="w-full h-full object-cover" alt="proof" />
                          <button 
                            type="button"
                            onClick={() => setAttachments(p => p.filter((_, i) => i !== idx))}
                            className="absolute top-2 right-2 bg-red-500 text-white p-2 rounded-full shadow-xl opacity-0 group-hover:opacity-100 transition-opacity"
                          >
                            <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={4}><path d="M6 18L18 6M6 6l12 12" /></svg>
                          </button>
                        </div>
                      ))}
                      <button
                        type="button"
                        onClick={() => fileInputRef.current?.click()}
                        disabled={isProcessingImages}
                        className="aspect-square rounded-[1.5rem] border-2 border-dashed border-gray-200 text-gray-400 hover:bg-indigo-50 hover:border-indigo-200 hover:text-indigo-600 transition-all flex flex-col items-center justify-center shadow-inner group"
                      >
                         {isProcessingImages ? (
                           <div className="w-6 h-6 border-3 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
                         ) : (
                           <>
                            <svg className="w-8 h-8 mb-1 group-hover:scale-110 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M12 4v16m8-8H4" /></svg>
                            <span className="text-[9px] font-black uppercase tracking-widest">Attach Proof</span>
                           </>
                         )}
                      </button>
                    </div>
                    <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept="image/*" multiple />
                  </div>

                  <div>
                    <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Dispatch Notes</label>
                    <textarea
                      value={note}
                      onChange={(e) => setNote(e.target.value)}
                      className="w-full px-6 py-5 bg-gray-50 border-none rounded-[2rem] shadow-inner min-h-[140px] font-medium focus:ring-2 focus:ring-indigo-500 transition-all"
                      placeholder="Driver info, carrier ID, or loading details..."
                    />
                  </div>
               </div>
            </div>

            <div className="pt-8 border-t border-gray-100 flex gap-4">
              <button 
                onClick={handleCreateShipment}
                className={`flex-1 font-black py-5 rounded-[2.25rem] shadow-2xl transition-all active:scale-95 uppercase tracking-widest text-sm ${mode === StorageMode.ONLINE ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-200' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100'} text-white`}
              >
                Seal & Archive Bundle
              </button>
              <button onClick={() => setIsCreating(false)} className="px-12 py-5 bg-gray-100 text-gray-500 font-black rounded-[2.25rem] hover:bg-gray-200 transition-all uppercase tracking-widest text-xs">Cancel</button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-500 max-w-6xl mx-auto pb-24 px-2">
      <header className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h2 className="text-4xl font-black text-gray-900 uppercase tracking-tighter">Shipment Archives</h2>
          <p className="text-gray-400 font-bold uppercase text-[10px] tracking-[0.3em] mt-1">Management Hub</p>
        </div>
        <button 
          onClick={() => setIsCreating(true)}
          className={`px-8 py-5 rounded-[1.75rem] font-black uppercase tracking-widest text-xs shadow-2xl transition-all flex items-center gap-3 active:scale-95 ${mode === StorageMode.ONLINE ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-100' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100'} text-white`}
        >
          <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M12 4v16m8-8H4" /></svg>
          Bundle New Shipment
        </button>
      </header>

      {/* Filter Bar */}
      <div className="bg-white p-4 md:p-6 rounded-[2.5rem] shadow-xl shadow-gray-200/40 border border-gray-100 sticky top-[84px] z-30 flex flex-col md:flex-row gap-4">
        <div className="relative flex-1 w-full">
          <span className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400">
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}><path d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          </span>
          <input
            type="text"
            placeholder="Search by Shipment Ref..."
            value={filterRef}
            onChange={(e) => setFilterRef(e.target.value)}
            className="w-full pl-14 pr-6 py-4 bg-gray-50 border-none rounded-2xl shadow-inner font-black text-gray-900 focus:ring-2 focus:ring-indigo-500 transition-all placeholder:text-gray-300"
          />
        </div>
        <div className="flex gap-2">
          <button 
            onClick={() => setIsFilterExpanded(!isFilterExpanded)}
            className={`px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-2 transition-all border ${isFilterExpanded ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg shadow-indigo-100' : 'bg-white text-gray-500 border-gray-100 hover:bg-gray-50'}`}
          >
            <svg className={`w-4 h-4 transition-transform duration-300 ${isFilterExpanded ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M19 9l-7 7-7-7" /></svg>
            Period {hasActiveFilters && <span className="w-2 h-2 rounded-full bg-red-500"></span>}
          </button>

          {mode === StorageMode.ONLINE && (
            <button 
              onClick={fetchOnlineData}
              className={`p-4 bg-blue-50 text-blue-600 rounded-2xl hover:bg-blue-100 transition-all border border-blue-100 ${isLoading ? 'animate-spin' : ''}`}
            >
              <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
            </button>
          )}

          {hasActiveFilters && (
            <button 
              onClick={() => { setFilterRef(''); setFilterStartDate(''); setFilterEndDate(''); }} 
              className="p-4 bg-red-50 text-red-500 rounded-2xl hover:bg-red-100 transition-all border border-red-100"
            >
              <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          )}
        </div>
      </div>

      {isFilterExpanded && (
        <div className="bg-white p-6 rounded-[2.5rem] shadow-2xl shadow-indigo-100/50 border border-indigo-50 grid grid-cols-1 md:grid-cols-2 gap-6 animate-in slide-in-from-top-4 duration-300">
           <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Dispatch Range (From)</label>
              <input type="date" value={filterStartDate} onChange={e => setFilterStartDate(e.target.value)} className="w-full px-5 py-4 bg-gray-50 rounded-xl font-bold border-none focus:ring-2 focus:ring-indigo-500 shadow-inner" />
           </div>
           <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Dispatch Range (To)</label>
              <input type="date" value={filterEndDate} onChange={e => setFilterEndDate(e.target.value)} className="w-full px-5 py-4 bg-gray-50 rounded-xl font-bold border-none focus:ring-2 focus:ring-indigo-500 shadow-inner" />
           </div>
        </div>
      )}

      {/* Shipment Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {isLoading && activeShipments.length === 0 ? (
          <div className="col-span-full py-32 text-center">
             <div className="w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mx-auto mb-6"></div>
             <p className="text-indigo-600 font-black uppercase tracking-widest text-lg">Fetching Archives...</p>
          </div>
        ) : filteredShipments.length === 0 ? (
          <div className="col-span-full py-32 text-center bg-white rounded-[4rem] border-4 border-dashed border-gray-100">
            <div className="w-24 h-24 bg-gray-50 rounded-[2.5rem] flex items-center justify-center mx-auto mb-6 text-gray-200">
               <svg className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}><path d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" /></svg>
            </div>
            <p className="text-gray-300 font-black text-2xl italic uppercase tracking-tighter">No Bundles Found</p>
            <p className="text-gray-400 text-[11px] font-bold uppercase mt-2 tracking-widest">Bundle existing orders into a shipment reference.</p>
          </div>
        ) : (
          filteredShipments.map(shipment => {
             const linked = shipment.orderUuids.map(uuid => activeOrders.find(o => o.uuid === uuid)).filter(Boolean) as Order[];
             const totalQty = linked.reduce((sum, o) => sum + o.qty, 0);

             return (
               <div key={shipment.uuid} className="bg-white rounded-[3rem] p-8 shadow-sm border border-gray-50 hover:shadow-2xl hover:shadow-indigo-100/50 transition-all duration-500 flex flex-col group relative overflow-hidden">
                 <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-50/30 rounded-full -mr-16 -mt-16 group-hover:bg-indigo-100/50 transition-colors"></div>

                 <div className="flex justify-between items-start mb-8 relative z-10">
                    <div className="flex-1 truncate mr-4">
                       <span className={`text-[10px] font-black uppercase tracking-widest px-3 py-1 rounded-full mb-3 inline-block shadow-sm ${mode === StorageMode.ONLINE ? 'bg-blue-50 text-blue-600' : 'bg-indigo-50 text-indigo-600'}`}>
                         Ref: {shipment.reference}
                       </span>
                       <h3 className="text-2xl font-black text-gray-900 leading-tight truncate">{linked.length} Order{linked.length !== 1 ? 's' : ''}</h3>
                       <div className="flex items-center gap-2 mt-2">
                          <svg className="w-3.5 h-3.5 text-emerald-500" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                          <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Disp: {new Date(shipment.dispatchDate).toLocaleDateString()}</p>
                       </div>
                    </div>
                    <div className={`${mode === StorageMode.ONLINE ? 'bg-blue-600 shadow-blue-200' : 'bg-indigo-600 shadow-indigo-200'} rounded-2xl p-4 text-center min-w-[70px] shadow-xl group-hover:scale-110 transition-transform`}>
                       <span className="block text-[10px] text-white opacity-70 font-black uppercase tracking-tighter">Units</span>
                       <span className="block text-2xl font-black text-white leading-none mt-1">{totalQty.toLocaleString()}</span>
                    </div>
                 </div>

                 <div className="flex-1 mb-6 relative z-10">
                    <div className="flex flex-wrap gap-2 mb-4">
                       {linked.slice(0, 4).map(o => (
                          <span key={o.uuid} className="text-[9px] font-bold text-gray-600 bg-gray-50 border border-gray-100 px-2.5 py-1.5 rounded-xl truncate max-w-[120px]">{o.customer}</span>
                       ))}
                       {linked.length > 4 && (
                          <span className="text-[9px] font-black text-indigo-400 bg-indigo-50 px-2.5 py-1.5 rounded-xl">+{linked.length - 4} More</span>
                       )}
                    </div>
                    {shipment.note && (
                       <p className="text-sm font-medium text-gray-500 italic bg-gray-50/50 p-4 rounded-2xl border border-gray-100/50 line-clamp-2 leading-relaxed">
                          {shipment.note}
                       </p>
                    )}
                 </div>

                 {shipment.attachments.length > 0 && (
                    <div className="flex gap-3 overflow-x-auto no-scrollbar mb-6 relative z-10 pb-2">
                       {shipment.attachments.map((src, i) => (
                          <img key={i} src={src} className="w-16 h-16 rounded-[1.25rem] object-cover border-2 border-white shadow-md flex-shrink-0 hover:scale-105 transition-transform" alt="loading-proof" />
                       ))}
                    </div>
                 )}

                 <div className="flex justify-end gap-3 pt-6 border-t border-gray-50 relative z-10">
                    <button 
                      onClick={() => handleDeleteShipment(shipment)}
                      className="p-3.5 bg-gray-50 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all shadow-sm"
                      title="Un-bundle Shipment"
                    >
                       <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                    </button>
                 </div>
               </div>
             )
          })
        )}
      </div>
    </div>
  );
};

export default Archive;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { db, Order, Shipment } from '../db';
import { useLiveQuery } from 'dexie-react-hooks';
import { StorageMode } from '../types';
import { getShipments, saveShipment, deleteShipment } from '../services/shipmentService';
import { getOrders } from '../services/orderService';
import { initSupabase } from '../services/syncService';

interface Props {
  mode: StorageMode;
}

const Archive: React.FC<Props> = ({ mode }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [selectedOrderUuids, setSelectedOrderUuids] = useState<Set<string>>(new Set());
  const [reference, setReference] = useState('');
  const [dispatchDate, setDispatchDate] = useState(new Date().toISOString().split('T')[0]);
  const [note, setNote] = useState('');
  const [attachments, setAttachments] = useState<string[]>([]);
  const [isProcessingImages, setIsProcessingImages] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Online data states
  const [onlineShipments, setOnlineShipments] = useState<Shipment[]>([]);
  const [onlineOrders, setOnlineOrders] = useState<Order[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  // Filter states
  const [filterRef, setFilterRef] = useState('');
  const [filterStartDate, setFilterStartDate] = useState('');
  const [filterEndDate, setFilterEndDate] = useState('');
  const [isFilterExpanded, setIsFilterExpanded] = useState(false);

  // Local data
  const localOrders = useLiveQuery(() => db.orders.toArray());
  const localShipments = useLiveQuery(() => db.shipments.toArray());

  const fetchOnlineData = async () => {
    if (mode !== StorageMode.ONLINE) return;
    setIsLoading(true);
    try {
      const [shipmentsData, ordersData] = await Promise.all([
        getShipments(StorageMode.ONLINE),
        getOrders(StorageMode.ONLINE)
      ]);
      setOnlineShipments(shipmentsData || []);
      setOnlineOrders(ordersData || []);
    } catch (err) {
      console.error("Archive Fetch Error:", err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (mode === StorageMode.ONLINE) {
      fetchOnlineData();
      const supabase = initSupabase();
      if (supabase) {
        // Fix: Use 'postgres_changes' as a literal type and include 'schema' to satisfy overloads
        const channel = supabase.channel('archive_realtime_v3_fixed_v2')
          .on(
            'postgres_changes' as any, 
            { event: '*', table: 'shipments', schema: 'public' }, 
            () => fetchOnlineData()
          )
          .on(
            'postgres_changes' as any, 
            { event: '*', table: 'orders', schema: 'public' }, 
            () => fetchOnlineData()
          )
          .subscribe();
        return () => { supabase.removeChannel(channel); };
      }
    }
  }, [mode]);

  const activeShipments: Shipment[] = mode === StorageMode.OFFLINE ? (localShipments || []) : onlineShipments;
  const activeOrders: Order[] = mode === StorageMode.OFFLINE ? (localOrders || []) : onlineOrders;

  const availableOrders = useMemo(() => {
    const archivedUuids = new Set<string>();
    activeShipments.forEach(s => {
      if (s.orderUuids && Array.isArray(s.orderUuids)) {
        s.orderUuids.forEach(uuid => archivedUuids.add(uuid));
      }
    });
    return activeOrders.filter(o => !archivedUuids.has(o.uuid));
  }, [activeOrders, activeShipments]);

  const filteredShipments = useMemo(() => {
    return activeShipments.filter(s => {
      const matchesRef = !filterRef || s.reference.toLowerCase().includes(filterRef.toLowerCase());

      const sDate = new Date(s.dispatchDate).setHours(0,0,0,0);
      const start = filterStartDate ? new Date(filterStartDate).setHours(0,0,0,0) : null;
      const end = filterEndDate ? new Date(filterEndDate).setHours(23,59,59,999) : null;

      const matchesStart = !start || sDate >= start;
      const matchesEnd = !end || sDate <= end;

      return matchesRef && matchesStart && matchesEnd;
    }).sort((a, b) => b.dispatchDate - a.dispatchDate);
  }, [activeShipments, filterRef, filterStartDate, filterEndDate]);

  const handleToggleOrder = (uuid: string) => {
    const next = new Set(selectedOrderUuids);
    if (next.has(uuid)) next.delete(uuid);
    else next.add(uuid);
    setSelectedOrderUuids(next);
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    setIsProcessingImages(true);
    try {
      const readFileAsDataURL = (file: File): Promise<string> => {
        return new Promise((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = () => resolve(reader.result as string);
          reader.onerror = (error) => reject(error);
          reader.readAsDataURL(file);
        });
      };

      const downscaleImage = (dataUrl: string, maxWidth = 1200, quality = 0.7): Promise<string> => {
        return new Promise((resolve) => {
          const img = new Image();
          img.src = dataUrl;
          img.onload = () => {
            const canvas = document.createElement('canvas');
            let w = img.width;
            let h = img.height;
            if (w > maxWidth) {
              h = (maxWidth / w) * h;
              w = maxWidth;
            }
            canvas.width = w;
            canvas.height = h;
            const ctx = canvas.getContext('2d');
            ctx?.drawImage(img, 0, 0, w, h);
            resolve(canvas.toDataURL('image/jpeg', quality));
          };
          img.onerror = () => resolve(dataUrl);
        });
      };

      const fileArray: File[] = Array.from(files);
      const optimized = await Promise.all(
        fileArray.map(async (f: File) => {
          const dataUrl = await readFileAsDataURL(f);
          return downscaleImage(dataUrl);
        })
      );
      setAttachments(prev => [...prev, ...optimized]);
    } catch (err) {
      console.error("Error processing archive images", err);
    } finally {
      setIsProcessingImages(false);
      if (e.target) e.target.value = '';
    }
  };

  const handleCreateShipment = async () => {
    if (!reference.trim() || selectedOrderUuids.size === 0 || !dispatchDate) {
      alert("Required: Reference, Dispatch Date, and at least one order.");
      return;
    }

    const newShipment: Shipment = {
      uuid: crypto.randomUUID(),
      reference: reference.trim(),
      orderUuids: Array.from(selectedOrderUuids),
      attachments,
      note: note.trim(),
      dispatchDate: new Date(`${dispatchDate}T12:00:00`).getTime(),
      createdAt: Date.now(),
      updatedAt: Date.now()
    };

    try {
      await saveShipment(mode, newShipment);
      setReference('');
      setNote('');
      setAttachments([]);
      setSelectedOrderUuids(new Set());
      setDispatchDate(new Date().toISOString().split('T')[0]);
      setIsCreating(false);
      if (mode === StorageMode.ONLINE) fetchOnlineData();
    } catch (err) {
      alert("Save failed.");
    }
  };

  const handleDeleteShipment = async (shipment: Shipment) => {
    if (confirm("Delete this archive bundle? Linked orders will return to history for re-bundling.")) {
      await deleteShipment(mode, shipment.id!, shipment.uuid);
      if (mode === StorageMode.ONLINE) fetchOnlineData();
    }
  };

  const hasActiveFilters = filterRef || filterStartDate || filterEndDate;

  if (isCreating) {
    return (
      <div className="max-w-4xl mx-auto animate-in fade-in slide-in-from-bottom-4 duration-500 pb-24 px-2">
        <div className="bg-white rounded-[3rem] shadow-2xl p-8 border border-gray-100 mb-8">
          <header className="mb-8 flex justify-between items-center">
            <div>
              <h2 className="text-3xl font-black text-gray-900 uppercase tracking-tighter">New Shipment</h2>
              <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest mt-1">
                {mode === StorageMode.ONLINE ? 'Supabase Live' : 'Standalone Local'} Mode
              </p>
            </div>
            <button onClick={() => setIsCreating(false)} className="text-gray-400 hover:text-gray-900 transition-colors">
              <svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </header>

          <div className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Shipment Reference (Truck/CNTR)</label>
                <input
                  type="text"
                  value={reference}
                  onChange={(e) => setReference(e.target.value)}
                  className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl shadow-inner font-black text-lg focus:ring-2 focus:ring-indigo-500 transition-all"
                  placeholder="Ex: T-402-B"
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Actual Dispatch Date</label>
                <input
                  type="date"
                  value={dispatchDate}
                  onChange={(e) => setDispatchDate(e.target.value)}
                  className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl shadow-inner font-bold outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
                />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
               <div className="flex flex-col">
                  <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-4 ml-1">Select Orders ({selectedOrderUuids.size})</label>
                  <div className="bg-gray-50 rounded-[2.5rem] p-4 h-[400px] overflow-auto shadow-inner space-y-2 border border-gray-100 custom-scrollbar">
                     {availableOrders.length === 0 ? (
                        <div className="flex flex-col items-center justify-center h-full text-center p-8">
                           <p className="text-gray-300 font-black text-lg italic uppercase tracking-widest">No available orders</p>
                           <p className="text-gray-400 text-[10px] font-bold uppercase mt-2">All orders are already in shipments.</p>
                        </div>
                     ) : (
                        availableOrders.map(order => (
                           <div 
                             key={order.uuid} 
                             onClick={() => handleToggleOrder(order.uuid)}
                             className={`p-5 rounded-[1.75rem] cursor-pointer transition-all border-2 flex items-center gap-4 ${selectedOrderUuids.has(order.uuid) ? 'bg-indigo-600 border-indigo-600 shadow-xl' : 'bg-white border-transparent hover:border-indigo-100'}`}
                           >
                              <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${selectedOrderUuids.has(order.uuid) ? 'bg-white border-white' : 'border-gray-200'}`}>
                                 {selectedOrderUuids.has(order.uuid) && <svg className="w-4 h-4 text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path d="M5 13l4 4L19 7" /></svg>}
                              </div>
                              <div className="flex-1 truncate">
                                 <p className={`text-sm font-black ${selectedOrderUuids.has(order.uuid) ? 'text-white' : 'text-gray-900'}`}>{order.customer}</p>
                                 <p className={`text-[10px] font-bold uppercase tracking-widest ${selectedOrderUuids.has(order.uuid) ? 'text-indigo-100' : 'text-gray-400'}`}>{order.city} • {order.qty} units</p>
                              </div>
                           </div>
                        ))
                     )}
                  </div>
               </div>

               <div className="space-y-8">
                  <div>
                    <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3 ml-1">Loading Proof Photos</label>
                    <div className="grid grid-cols-3 gap-4">
                      {attachments.map((src, idx) => (
                        <div key={idx} className="relative aspect-square rounded-[1.5rem] overflow-hidden border-2 border-white shadow-lg group">
                          <img src={src} className="w-full h-full object-cover" alt="proof" />
                          <button 
                            type="button"
                            onClick={() => setAttachments(p => p.filter((_, i) => i !== idx))}
                            className="absolute top-2 right-2 bg-red-500 text-white p-2 rounded-full shadow-xl opacity-0 group-hover:opacity-100 transition-opacity"
                          >
                            <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={4}><path d="M6 18L18 6M6 6l12 12" /></svg>
                          </button>
                        </div>
                      ))}
                      <button
                        type="button"
                        onClick={() => fileInputRef.current?.click()}
                        disabled={isProcessingImages}
                        className="aspect-square rounded-[1.5rem] border-2 border-dashed border-gray-200 text-gray-400 hover:bg-indigo-50 hover:border-indigo-200 hover:text-indigo-600 transition-all flex flex-col items-center justify-center shadow-inner group"
                      >
                         {isProcessingImages ? (
                           <div className="w-6 h-6 border-3 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
                         ) : (
                           <>
                            <svg className="w-8 h-8 mb-1 group-hover:scale-110 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M12 4v16m8-8H4" /></svg>
                            <span className="text-[9px] font-black uppercase tracking-widest">Attach Proof</span>
                           </>
                         )}
                      </button>
                    </div>
                    <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept="image/*" multiple />
                  </div>

                  <div>
                    <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Dispatch Notes</label>
                    <textarea
                      value={note}
                      onChange={(e) => setNote(e.target.value)}
                      className="w-full px-6 py-5 bg-gray-50 border-none rounded-[2rem] shadow-inner min-h-[140px] font-medium focus:ring-2 focus:ring-indigo-500 transition-all"
                      placeholder="Driver info, carrier ID, or loading details..."
                    />
                  </div>
               </div>
            </div>

            <div className="pt-8 border-t border-gray-100 flex gap-4">
              <button 
                onClick={handleCreateShipment}
                className={`flex-1 font-black py-5 rounded-[2.25rem] shadow-2xl transition-all active:scale-95 uppercase tracking-widest text-sm ${mode === StorageMode.ONLINE ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-200' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100'} text-white`}
              >
                Seal & Archive Bundle
              </button>
              <button onClick={() => setIsCreating(false)} className="px-12 py-5 bg-gray-100 text-gray-500 font-black rounded-[2.25rem] hover:bg-gray-200 transition-all uppercase tracking-widest text-xs">Cancel</button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-500 max-w-6xl mx-auto pb-24 px-2">
      <header className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h2 className="text-4xl font-black text-gray-900 uppercase tracking-tighter">Shipment Archives</h2>
          <p className="text-gray-400 font-bold uppercase text-[10px] tracking-[0.3em] mt-1">Management Hub</p>
        </div>
        <button 
          onClick={() => setIsCreating(true)}
          className={`px-8 py-5 rounded-[1.75rem] font-black uppercase tracking-widest text-xs shadow-2xl transition-all flex items-center gap-3 active:scale-95 ${mode === StorageMode.ONLINE ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-100' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100'} text-white`}
        >
          <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M12 4v16m8-8H4" /></svg>
          Bundle New Shipment
        </button>
      </header>

      {/* Filter Bar */}
      <div className="bg-white p-4 md:p-6 rounded-[2.5rem] shadow-xl shadow-gray-200/40 border border-gray-100 sticky top-[84px] z-30 flex flex-col md:flex-row gap-4">
        <div className="relative flex-1 w-full">
          <span className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400">
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}><path d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          </span>
          <input
            type="text"
            placeholder="Search by Shipment Ref..."
            value={filterRef}
            onChange={(e) => setFilterRef(e.target.value)}
            className="w-full pl-14 pr-6 py-4 bg-gray-50 border-none rounded-2xl shadow-inner font-black text-gray-900 focus:ring-2 focus:ring-indigo-500 transition-all placeholder:text-gray-300"
          />
        </div>
        <div className="flex gap-2">
          <button 
            onClick={() => setIsFilterExpanded(!isFilterExpanded)}
            className={`px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-2 transition-all border ${isFilterExpanded ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg shadow-indigo-100' : 'bg-white text-gray-500 border-gray-100 hover:bg-gray-50'}`}
          >
            <svg className={`w-4 h-4 transition-transform duration-300 ${isFilterExpanded ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M19 9l-7 7-7-7" /></svg>
            Period {hasActiveFilters && <span className="w-2 h-2 rounded-full bg-red-500"></span>}
          </button>

          {mode === StorageMode.ONLINE && (
            <button 
              onClick={fetchOnlineData}
              className={`p-4 bg-blue-50 text-blue-600 rounded-2xl hover:bg-blue-100 transition-all border border-blue-100 ${isLoading ? 'animate-spin' : ''}`}
            >
              <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
            </button>
          )}

          {hasActiveFilters && (
            <button 
              onClick={() => { setFilterRef(''); setFilterStartDate(''); setFilterEndDate(''); }} 
              className="p-4 bg-red-50 text-red-500 rounded-2xl hover:bg-red-100 transition-all border border-red-100"
            >
              <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          )}
        </div>
      </div>

      {isFilterExpanded && (
        <div className="bg-white p-6 rounded-[2.5rem] shadow-2xl shadow-indigo-100/50 border border-indigo-50 grid grid-cols-1 md:grid-cols-2 gap-6 animate-in slide-in-from-top-4 duration-300">
           <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Dispatch Range (From)</label>
              <input type="date" value={filterStartDate} onChange={e => setFilterStartDate(e.target.value)} className="w-full px-5 py-4 bg-gray-50 rounded-xl font-bold border-none focus:ring-2 focus:ring-indigo-500 shadow-inner" />
           </div>
           <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Dispatch Range (To)</label>
              <input type="date" value={filterEndDate} onChange={e => setFilterEndDate(e.target.value)} className="w-full px-5 py-4 bg-gray-50 rounded-xl font-bold border-none focus:ring-2 focus:ring-indigo-500 shadow-inner" />
           </div>
        </div>
      )}

      {/* Shipment Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {isLoading && activeShipments.length === 0 ? (
          <div className="col-span-full py-32 text-center">
             <div className="w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mx-auto mb-6"></div>
             <p className="text-indigo-600 font-black uppercase tracking-widest text-lg">Fetching Archives...</p>
          </div>
        ) : filteredShipments.length === 0 ? (
          <div className="col-span-full py-32 text-center bg-white rounded-[4rem] border-4 border-dashed border-gray-100">
            <div className="w-24 h-24 bg-gray-50 rounded-[2.5rem] flex items-center justify-center mx-auto mb-6 text-gray-200">
               <svg className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}><path d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" /></svg>
            </div>
            <p className="text-gray-300 font-black text-2xl italic uppercase tracking-tighter">No Bundles Found</p>
            <p className="text-gray-400 text-[11px] font-bold uppercase mt-2 tracking-widest">Bundle existing orders into a shipment reference.</p>
          </div>
        ) : (
          filteredShipments.map(shipment => {
             const linked = shipment.orderUuids.map(uuid => activeOrders.find(o => o.uuid === uuid)).filter(Boolean) as Order[];
             const totalQty = linked.reduce((sum, o) => sum + o.qty, 0);

             return (
               <div key={shipment.uuid} className="bg-white rounded-[3rem] p-8 shadow-sm border border-gray-50 hover:shadow-2xl hover:shadow-indigo-100/50 transition-all duration-500 flex flex-col group relative overflow-hidden">
                 <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-50/30 rounded-full -mr-16 -mt-16 group-hover:bg-indigo-100/50 transition-colors"></div>

                 <div className="flex justify-between items-start mb-8 relative z-10">
                    <div className="flex-1 truncate mr-4">
                       <span className={`text-[10px] font-black uppercase tracking-widest px-3 py-1 rounded-full mb-3 inline-block shadow-sm ${mode === StorageMode.ONLINE ? 'bg-blue-50 text-blue-600' : 'bg-indigo-50 text-indigo-600'}`}>
                         Ref: {shipment.reference}
                       </span>
                       <h3 className="text-2xl font-black text-gray-900 leading-tight truncate">{linked.length} Order{linked.length !== 1 ? 's' : ''}</h3>
                       <div className="flex items-center gap-2 mt-2">
                          <svg className="w-3.5 h-3.5 text-emerald-500" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                          <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Disp: {new Date(shipment.dispatchDate).toLocaleDateString()}</p>
                       </div>
                    </div>
                    <div className={`${mode === StorageMode.ONLINE ? 'bg-blue-600 shadow-blue-200' : 'bg-indigo-600 shadow-indigo-200'} rounded-2xl p-4 text-center min-w-[70px] shadow-xl group-hover:scale-110 transition-transform`}>
                       <span className="block text-[10px] text-white opacity-70 font-black uppercase tracking-tighter">Units</span>
                       <span className="block text-2xl font-black text-white leading-none mt-1">{totalQty.toLocaleString()}</span>
                    </div>
                 </div>

                 <div className="flex-1 mb-6 relative z-10">
                    <div className="flex flex-wrap gap-2 mb-4">
                       {linked.slice(0, 4).map(o => (
                          <span key={o.uuid} className="text-[9px] font-bold text-gray-600 bg-gray-50 border border-gray-100 px-2.5 py-1.5 rounded-xl truncate max-w-[120px]">{o.customer}</span>
                       ))}
                       {linked.length > 4 && (
                          <span className="text-[9px] font-black text-indigo-400 bg-indigo-50 px-2.5 py-1.5 rounded-xl">+{linked.length - 4} More</span>
                       )}
                    </div>
                    {shipment.note && (
                       <p className="text-sm font-medium text-gray-500 italic bg-gray-50/50 p-4 rounded-2xl border border-gray-100/50 line-clamp-2 leading-relaxed">
                          {shipment.note}
                       </p>
                    )}
                 </div>

                 {shipment.attachments.length > 0 && (
                    <div className="flex gap-3 overflow-x-auto no-scrollbar mb-6 relative z-10 pb-2">
                       {shipment.attachments.map((src, i) => (
                          <img key={i} src={src} className="w-16 h-16 rounded-[1.25rem] object-cover border-2 border-white shadow-md flex-shrink-0 hover:scale-105 transition-transform" alt="loading-proof" />
                       ))}
                    </div>
                 )}

                 <div className="flex justify-end gap-3 pt-6 border-t border-gray-50 relative z-10">
                    <button 
                      onClick={() => handleDeleteShipment(shipment)}
                      className="p-3.5 bg-gray-50 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all shadow-sm"
                      title="Un-bundle Shipment"
                    >
                       <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                    </button>
                 </div>
               </div>
             )
          })
        )}
      </div>
    </div>
  );
};

export default Archive;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { db, Order, Shipment } from '../db';
import { useLiveQuery } from 'dexie-react-hooks';
import { StorageMode } from '../types';
import { getShipments, saveShipment, deleteShipment } from '../services/shipmentService';
import { getOrders } from '../services/orderService';
import { initSupabase } from '../services/syncService';

interface Props {
  mode: StorageMode;
}

const Archive: React.FC<Props> = ({ mode }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [openedShipmentUuid, setOpenedShipmentUuid] = useState<string | null>(null);
  const [selectedOrderUuids, setSelectedOrderUuids] = useState<Set<string>>(new Set());
  const [reference, setReference] = useState('');
  const [dispatchDate, setDispatchDate] = useState(new Date().toISOString().split('T')[0]);
  const [note, setNote] = useState('');
  const [attachments, setAttachments] = useState<string[]>([]);
  const [isProcessingImages, setIsProcessingImages] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Online data states
  const [onlineShipments, setOnlineShipments] = useState<Shipment[]>([]);
  const [onlineOrders, setOnlineOrders] = useState<Order[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  // Filter states
  const [filterRef, setFilterRef] = useState('');
  const [filterStartDate, setFilterStartDate] = useState('');
  const [filterEndDate, setFilterEndDate] = useState('');
  const [isFilterExpanded, setIsFilterExpanded] = useState(false);

  // Local data
  const localOrders = useLiveQuery(() => db.orders.toArray());
  const localShipments = useLiveQuery(() => db.shipments.toArray());

  const fetchOnlineData = async () => {
    if (mode !== StorageMode.ONLINE) return;
    setIsLoading(true);
    try {
      const [shipmentsData, ordersData] = await Promise.all([
        getShipments(StorageMode.ONLINE),
        getOrders(StorageMode.ONLINE)
      ]);
      setOnlineShipments(shipmentsData || []);
      setOnlineOrders(ordersData || []);
    } catch (err) {
      console.error("Archive Fetch Error:", err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (mode === StorageMode.ONLINE) {
      fetchOnlineData();
      const supabase = initSupabase();
      if (supabase) {
        const channel = supabase.channel('archive_realtime_v4')
          .on(
            'postgres_changes' as any, 
            { event: '*', table: 'shipments', schema: 'public' }, 
            () => fetchOnlineData()
          )
          .on(
            'postgres_changes' as any, 
            { event: '*', table: 'orders', schema: 'public' }, 
            () => fetchOnlineData()
          )
          .subscribe();
        return () => { supabase.removeChannel(channel); };
      }
    }
  }, [mode]);

  const activeShipments: Shipment[] = mode === StorageMode.OFFLINE ? (localShipments || []) : onlineShipments;
  const activeOrders: Order[] = mode === StorageMode.OFFLINE ? (localOrders || []) : onlineOrders;

  const availableOrders = useMemo(() => {
    const archivedUuids = new Set<string>();
    activeShipments.forEach(s => {
      if (s.orderUuids && Array.isArray(s.orderUuids)) {
        s.orderUuids.forEach(uuid => archivedUuids.add(uuid));
      }
    });
    return activeOrders.filter(o => !archivedUuids.has(o.uuid));
  }, [activeOrders, activeShipments]);

  const filteredShipments = useMemo(() => {
    return activeShipments.filter(s => {
      const matchesRef = !filterRef || s.reference.toLowerCase().includes(filterRef.toLowerCase());

      const sDate = new Date(s.dispatchDate).setHours(0,0,0,0);
      const start = filterStartDate ? new Date(filterStartDate).setHours(0,0,0,0) : null;
      const end = filterEndDate ? new Date(filterEndDate).setHours(23,59,59,999) : null;

      const matchesStart = !start || sDate >= start;
      const matchesEnd = !end || sDate <= end;

      return matchesRef && matchesStart && matchesEnd;
    }).sort((a, b) => b.dispatchDate - a.dispatchDate);
  }, [activeShipments, filterRef, filterStartDate, filterEndDate]);

  const openedShipment = useMemo(() => 
    activeShipments.find(s => s.uuid === openedShipmentUuid), 
  [activeShipments, openedShipmentUuid]);

  const openedShipmentOrders = useMemo(() => {
    if (!openedShipment) return [];
    return openedShipment.orderUuids
      .map(uuid => activeOrders.find(o => o.uuid === uuid))
      .filter(Boolean) as Order[];
  }, [openedShipment, activeOrders]);

  const handleToggleOrder = (uuid: string) => {
    const next = new Set(selectedOrderUuids);
    if (next.has(uuid)) next.delete(uuid);
    else next.add(uuid);
    setSelectedOrderUuids(next);
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    setIsProcessingImages(true);
    try {
      const readFileAsDataURL = (file: File): Promise<string> => {
        return new Promise((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = () => resolve(reader.result as string);
          reader.onerror = (error) => reject(error);
          reader.readAsDataURL(file);
        });
      };

      const downscaleImage = (dataUrl: string, maxWidth = 1200, quality = 0.7): Promise<string> => {
        return new Promise((resolve) => {
          const img = new Image();
          img.src = dataUrl;
          img.onload = () => {
            const canvas = document.createElement('canvas');
            let w = img.width;
            let h = img.height;
            if (w > maxWidth) {
              h = (maxWidth / w) * h;
              w = maxWidth;
            }
            canvas.width = w;
            canvas.height = h;
            const ctx = canvas.getContext('2d');
            ctx?.drawImage(img, 0, 0, w, h);
            resolve(canvas.toDataURL('image/jpeg', quality));
          };
          img.onerror = () => resolve(dataUrl);
        });
      };

      const fileArray: File[] = Array.from(files);
      const optimized = await Promise.all(
        fileArray.map(async (f: File) => {
          const dataUrl = await readFileAsDataURL(f);
          return downscaleImage(dataUrl);
        })
      );
      setAttachments(prev => [...prev, ...optimized]);
    } catch (err) {
      console.error("Error processing archive images", err);
    } finally {
      setIsProcessingImages(false);
      if (e.target) e.target.value = '';
    }
  };

  const handleCreateShipment = async () => {
    if (!reference.trim() || selectedOrderUuids.size === 0 || !dispatchDate) {
      alert("Required: Reference, Dispatch Date, and at least one order.");
      return;
    }

    const newShipment: Shipment = {
      uuid: crypto.randomUUID(),
      reference: reference.trim(),
      orderUuids: Array.from(selectedOrderUuids),
      attachments,
      note: note.trim(),
      dispatchDate: new Date(`${dispatchDate}T12:00:00`).getTime(),
      createdAt: Date.now(),
      updatedAt: Date.now()
    };

    try {
      await saveShipment(mode, newShipment);
      setReference('');
      setNote('');
      setAttachments([]);
      setSelectedOrderUuids(new Set());
      setDispatchDate(new Date().toISOString().split('T')[0]);
      setIsCreating(false);
      if (mode === StorageMode.ONLINE) fetchOnlineData();
    } catch (err) {
      alert("Save failed.");
    }
  };

  const handleDeleteShipment = async (shipment: Shipment, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm("Delete this archive bundle? Linked orders will return to history for re-bundling.")) {
      await deleteShipment(mode, shipment.id!, shipment.uuid);
      if (openedShipmentUuid === shipment.uuid) setOpenedShipmentUuid(null);
      if (mode === StorageMode.ONLINE) fetchOnlineData();
    }
  };

  const hasActiveFilters = filterRef || filterStartDate || filterEndDate;

  // --- DETAIL MANIFEST VIEW ---
  if (openedShipment && openedShipmentUuid) {
    const totalQty = openedShipmentOrders.reduce((sum, o) => sum + o.qty, 0);

    return (
      <div className="fixed inset-0 z-[100] bg-gray-50 flex flex-col animate-in slide-in-from-right duration-500 overflow-hidden">
        {/* Detail Header */}
        <header className="bg-white border-b border-gray-100 px-4 md:px-8 py-4 flex items-center justify-between sticky top-0 z-10 shadow-sm">
          <div className="flex items-center gap-4">
            <button 
              onClick={() => setOpenedShipmentUuid(null)}
              className="p-3 bg-gray-100 text-gray-600 rounded-2xl hover:bg-indigo-600 hover:text-white transition-all active:scale-90"
            >
              <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M15 19l-7-7 7-7" /></svg>
            </button>
            <div>
              <div className="flex items-center gap-2">
                <span className="text-[10px] font-black uppercase tracking-widest text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-full">Archive Manifest</span>
                <span className="text-[10px] font-black uppercase tracking-widest text-gray-400">ID: {openedShipment.uuid.split('-')[0]}</span>
              </div>
              <h2 className="text-2xl font-black text-gray-900 tracking-tighter uppercase leading-none mt-1">Ref: {openedShipment.reference}</h2>
            </div>
          </div>
          <div className="flex items-center gap-3">
             <button 
               onClick={(e) => handleDeleteShipment(openedShipment, e as any)}
               className="px-6 py-3 bg-red-50 text-red-600 font-black rounded-xl hover:bg-red-600 hover:text-white transition-all text-xs uppercase tracking-widest"
             >
               Delete Bundle
             </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-8">
           <div className="max-w-6xl mx-auto space-y-12">
              {/* Stats & Metadata Overview */}
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-gray-100 flex flex-col justify-center">
                   <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Total Load Weight</p>
                   <p className="text-4xl font-black text-gray-900">{totalQty.toLocaleString()} <span className="text-sm font-bold text-gray-300">UNITS</span></p>
                </div>
                <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-gray-100 flex flex-col justify-center">
                   <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Manifest Size</p>
                   <p className="text-4xl font-black text-gray-900">{openedShipmentOrders.length} <span className="text-sm font-bold text-gray-300">ORDERS</span></p>
                </div>
                <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-gray-100 flex flex-col justify-center">
                   <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Dispatch Date</p>
                   <p className="text-4xl font-black text-indigo-600">{new Date(openedShipment.dispatchDate).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}</p>
                </div>
              </div>

              {/* Loading Proof Section */}
              {openedShipment.attachments.length > 0 && (
                <section>
                   <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.3em] mb-4 ml-2">Loading Proof Gallery</h3>
                   <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4">
                      {openedShipment.attachments.map((src, i) => (
                        <div key={i} className="aspect-square bg-white p-1 rounded-3xl shadow-sm border border-gray-100 group overflow-hidden cursor-zoom-in">
                          <img 
                            src={src} 
                            className="w-full h-full object-cover rounded-[1.25rem] group-hover:scale-110 transition-transform duration-500" 
                            alt="loading proof"
                            onClick={() => window.open(src, '_blank')}
                          />
                        </div>
                      ))}
                   </div>
                </section>
              )}

              {openedShipment.note && (
                <section className="bg-white p-8 rounded-[3rem] border-2 border-dashed border-gray-200">
                   <h3 className="text-xs font-black text-indigo-400 uppercase tracking-[0.3em] mb-4">Shipment Supervisor Notes</h3>
                   <p className="text-lg font-medium text-gray-700 leading-relaxed italic">"{openedShipment.note}"</p>
                </section>
              )}

              {/* Orders List Section */}
              <section className="space-y-6">
                <div className="flex items-center justify-between mb-8">
                   <h3 className="text-xl font-black text-gray-900 uppercase tracking-tighter">Items in Manifest</h3>
                   <div className="h-px flex-1 mx-8 bg-gray-100 hidden md:block"></div>
                </div>

                <div className="space-y-4">
                   {openedShipmentOrders.map((order, idx) => (
                      <div key={order.uuid} className="bg-white rounded-[2.5rem] p-6 md:p-8 shadow-sm border border-gray-100 hover:shadow-md transition-shadow">
                        <div className="flex flex-col md:flex-row gap-6">
                           <div className="bg-gray-50 rounded-[2rem] w-full md:w-32 h-32 flex flex-col items-center justify-center text-center p-4">
                              <span className="text-[10px] font-black text-gray-400 uppercase tracking-tighter">Order qty</span>
                              <p className="text-2xl font-black text-gray-900">{order.qty}</p>
                           </div>
                           <div className="flex-1 space-y-4">
                              <div className="flex flex-wrap items-center justify-between gap-4">
                                 <div>
                                    <h4 className="text-xl font-black text-gray-900">{order.customer}</h4>
                                    <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mt-1">{order.city} • {order.material}</p>
                                 </div>
                                 <div className="flex items-center gap-3">
                                    <span className="px-3 py-1.5 bg-gray-50 text-gray-500 border border-gray-100 rounded-xl text-[10px] font-black uppercase tracking-widest">
                                       {order.status}
                                    </span>
                                 </div>
                              </div>
                              {order.note && <p className="text-sm text-gray-500 bg-gray-50 px-4 py-3 rounded-2xl italic">Note: {order.note}</p>}

                              {order.attachments && order.attachments.length > 0 && (
                                <div className="flex gap-3 overflow-x-auto no-scrollbar pt-2">
                                   {order.attachments.map((img, i) => (
                                      <img 
                                        key={i} 
                                        src={img} 
                                        className="w-16 h-16 rounded-2xl object-cover border border-gray-100 shadow-sm hover:scale-105 transition-transform" 
                                        alt="item detail" 
                                      />
                                   ))}
                                </div>
                              )}
                           </div>
                        </div>
                      </div>
                   ))}
                </div>
              </section>
           </div>
        </div>
      </div>
    );
  }

  // --- CREATION VIEW ---
  if (isCreating) {
    return (
      <div className="max-w-4xl mx-auto animate-in fade-in slide-in-from-bottom-4 duration-500 pb-24 px-2">
        <div className="bg-white rounded-[3rem] shadow-2xl p-8 border border-gray-100 mb-8">
          <header className="mb-8 flex justify-between items-center">
            <div>
              <h2 className="text-3xl font-black text-gray-900 uppercase tracking-tighter">New Shipment</h2>
              <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest mt-1">
                {mode === StorageMode.ONLINE ? 'Supabase Live' : 'Standalone Local'} Mode
              </p>
            </div>
            <button onClick={() => setIsCreating(false)} className="text-gray-400 hover:text-gray-900 transition-colors">
              <svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </header>

          <div className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Shipment Reference (Truck/CNTR)</label>
                <input
                  type="text"
                  value={reference}
                  onChange={(e) => setReference(e.target.value)}
                  className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl shadow-inner font-black text-lg focus:ring-2 focus:ring-indigo-500 transition-all"
                  placeholder="Ex: T-402-B"
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Actual Dispatch Date</label>
                <input
                  type="date"
                  value={dispatchDate}
                  onChange={(e) => setDispatchDate(e.target.value)}
                  className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl shadow-inner font-bold outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
                />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
               <div className="flex flex-col">
                  <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-4 ml-1">Select Orders ({selectedOrderUuids.size})</label>
                  <div className="bg-gray-50 rounded-[2.5rem] p-4 h-[400px] overflow-auto shadow-inner space-y-2 border border-gray-100 custom-scrollbar">
                     {availableOrders.length === 0 ? (
                        <div className="flex flex-col items-center justify-center h-full text-center p-8">
                           <p className="text-gray-300 font-black text-lg italic uppercase tracking-widest">No available orders</p>
                           <p className="text-gray-400 text-[10px] font-bold uppercase mt-2">All orders are already in shipments.</p>
                        </div>
                     ) : (
                        availableOrders.map(order => (
                           <div 
                             key={order.uuid} 
                             onClick={() => handleToggleOrder(order.uuid)}
                             className={`p-5 rounded-[1.75rem] cursor-pointer transition-all border-2 flex items-center gap-4 ${selectedOrderUuids.has(order.uuid) ? 'bg-indigo-600 border-indigo-600 shadow-xl' : 'bg-white border-transparent hover:border-indigo-100'}`}
                           >
                              <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${selectedOrderUuids.has(order.uuid) ? 'bg-white border-white' : 'border-gray-200'}`}>
                                 {selectedOrderUuids.has(order.uuid) && <svg className="w-4 h-4 text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path d="M5 13l4 4L19 7" /></svg>}
                              </div>
                              <div className="flex-1 truncate">
                                 <p className={`text-sm font-black ${selectedOrderUuids.has(order.uuid) ? 'text-white' : 'text-gray-900'}`}>{order.customer}</p>
                                 <p className={`text-[10px] font-bold uppercase tracking-widest ${selectedOrderUuids.has(order.uuid) ? 'text-indigo-100' : 'text-gray-400'}`}>{order.city} • {order.qty} units</p>
                              </div>
                           </div>
                        ))
                     )}
                  </div>
               </div>

               <div className="space-y-8">
                  <div>
                    <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3 ml-1">Loading Proof Photos</label>
                    <div className="grid grid-cols-3 gap-4">
                      {attachments.map((src, idx) => (
                        <div key={idx} className="relative aspect-square rounded-[1.5rem] overflow-hidden border-2 border-white shadow-lg group">
                          <img src={src} className="w-full h-full object-cover" alt="proof" />
                          <button 
                            type="button"
                            onClick={() => setAttachments(p => p.filter((_, i) => i !== idx))}
                            className="absolute top-2 right-2 bg-red-500 text-white p-2 rounded-full shadow-xl opacity-0 group-hover:opacity-100 transition-opacity"
                          >
                            <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={4}><path d="M6 18L18 6M6 6l12 12" /></svg>
                          </button>
                        </div>
                      ))}
                      <button
                        type="button"
                        onClick={() => fileInputRef.current?.click()}
                        disabled={isProcessingImages}
                        className="aspect-square rounded-[1.5rem] border-2 border-dashed border-gray-200 text-gray-400 hover:bg-indigo-50 hover:border-indigo-200 hover:text-indigo-600 transition-all flex flex-col items-center justify-center shadow-inner group"
                      >
                         {isProcessingImages ? (
                           <div className="w-6 h-6 border-3 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
                         ) : (
                           <>
                            <svg className="w-8 h-8 mb-1 group-hover:scale-110 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M12 4v16m8-8H4" /></svg>
                            <span className="text-[9px] font-black uppercase tracking-widest">Attach Proof</span>
                           </>
                         )}
                      </button>
                    </div>
                    <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept="image/*" multiple />
                  </div>

                  <div>
                    <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Dispatch Notes</label>
                    <textarea
                      value={note}
                      onChange={(e) => setNote(e.target.value)}
                      className="w-full px-6 py-5 bg-gray-50 border-none rounded-[2rem] shadow-inner min-h-[140px] font-medium focus:ring-2 focus:ring-indigo-500 transition-all"
                      placeholder="Driver info, carrier ID, or loading details..."
                    />
                  </div>
               </div>
            </div>

            <div className="pt-8 border-t border-gray-100 flex gap-4">
              <button 
                onClick={handleCreateShipment}
                className={`flex-1 font-black py-5 rounded-[2.25rem] shadow-2xl transition-all active:scale-95 uppercase tracking-widest text-sm ${mode === StorageMode.ONLINE ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-200' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100'} text-white`}
              >
                Seal & Archive Bundle
              </button>
              <button onClick={() => setIsCreating(false)} className="px-12 py-5 bg-gray-100 text-gray-500 font-black rounded-[2.25rem] hover:bg-gray-200 transition-all uppercase tracking-widest text-xs">Cancel</button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // --- ARCHIVE GRID VIEW ---
  return (
    <div className="space-y-8 animate-in fade-in duration-500 max-w-6xl mx-auto pb-24 px-2">
      <header className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h2 className="text-4xl font-black text-gray-900 uppercase tracking-tighter">Shipment Archives</h2>
          <p className="text-gray-400 font-bold uppercase text-[10px] tracking-[0.3em] mt-1">Management Hub</p>
        </div>
        <button 
          onClick={() => setIsCreating(true)}
          className={`px-8 py-5 rounded-[1.75rem] font-black uppercase tracking-widest text-xs shadow-2xl transition-all flex items-center gap-3 active:scale-95 ${mode === StorageMode.ONLINE ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-100' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100'} text-white`}
        >
          <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M12 4v16m8-8H4" /></svg>
          Bundle New Shipment
        </button>
      </header>

      {/* Filter Bar */}
      <div className="bg-white p-4 md:p-6 rounded-[2.5rem] shadow-xl shadow-gray-200/40 border border-gray-100 sticky top-[84px] z-30 flex flex-col md:flex-row gap-4">
        <div className="relative flex-1 w-full">
          <span className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400">
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}><path d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          </span>
          <input
            type="text"
            placeholder="Search by Shipment Ref..."
            value={filterRef}
            onChange={(e) => setFilterRef(e.target.value)}
            className="w-full pl-14 pr-6 py-4 bg-gray-50 border-none rounded-2xl shadow-inner font-black text-gray-900 focus:ring-2 focus:ring-indigo-500 transition-all placeholder:text-gray-300"
          />
        </div>
        <div className="flex gap-2">
          <button 
            onClick={() => setIsFilterExpanded(!isFilterExpanded)}
            className={`px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-2 transition-all border ${isFilterExpanded ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg shadow-indigo-100' : 'bg-white text-gray-500 border-gray-100 hover:bg-gray-50'}`}
          >
            <svg className={`w-4 h-4 transition-transform duration-300 ${isFilterExpanded ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M19 9l-7 7-7-7" /></svg>
            Period {hasActiveFilters && <span className="w-2 h-2 rounded-full bg-red-500"></span>}
          </button>

          {mode === StorageMode.ONLINE && (
            <button 
              onClick={fetchOnlineData}
              className={`p-4 bg-blue-50 text-blue-600 rounded-2xl hover:bg-blue-100 transition-all border border-blue-100 ${isLoading ? 'animate-spin' : ''}`}
            >
              <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
            </button>
          )}

          {hasActiveFilters && (
            <button 
              onClick={() => { setFilterRef(''); setFilterStartDate(''); setFilterEndDate(''); }} 
              className="p-4 bg-red-50 text-red-500 rounded-2xl hover:bg-red-100 transition-all border border-red-100"
            >
              <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          )}
        </div>
      </div>

      {isFilterExpanded && (
        <div className="bg-white p-6 rounded-[2.5rem] shadow-2xl shadow-indigo-100/50 border border-indigo-50 grid grid-cols-1 md:grid-cols-2 gap-6 animate-in slide-in-from-top-4 duration-300">
           <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Dispatch Range (From)</label>
              <input type="date" value={filterStartDate} onChange={e => setFilterStartDate(e.target.value)} className="w-full px-5 py-4 bg-gray-50 rounded-xl font-bold border-none focus:ring-2 focus:ring-indigo-500 shadow-inner" />
           </div>
           <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Dispatch Range (To)</label>
              <input type="date" value={filterEndDate} onChange={e => setFilterEndDate(e.target.value)} className="w-full px-5 py-4 bg-gray-50 rounded-xl font-bold border-none focus:ring-2 focus:ring-indigo-500 shadow-inner" />
           </div>
        </div>
      )}

      {/* Shipment Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {isLoading && activeShipments.length === 0 ? (
          <div className="col-span-full py-32 text-center">
             <div className="w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mx-auto mb-6"></div>
             <p className="text-indigo-600 font-black uppercase tracking-widest text-lg">Fetching Archives...</p>
          </div>
        ) : filteredShipments.length === 0 ? (
          <div className="col-span-full py-32 text-center bg-white rounded-[4rem] border-4 border-dashed border-gray-100">
            <div className="w-24 h-24 bg-gray-50 rounded-[2.5rem] flex items-center justify-center mx-auto mb-6 text-gray-200">
               <svg className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}><path d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" /></svg>
            </div>
            <p className="text-gray-300 font-black text-2xl italic uppercase tracking-tighter">No Bundles Found</p>
            <p className="text-gray-400 text-[11px] font-bold uppercase mt-2 tracking-widest">Bundle existing orders into a shipment reference.</p>
          </div>
        ) : (
          filteredShipments.map(shipment => {
             const linked = shipment.orderUuids.map(uuid => activeOrders.find(o => o.uuid === uuid)).filter(Boolean) as Order[];
             const totalQty = linked.reduce((sum, o) => sum + o.qty, 0);

             return (
               <div 
                 key={shipment.uuid} 
                 onClick={() => setOpenedShipmentUuid(shipment.uuid)}
                 className="bg-white rounded-[3rem] p-8 shadow-sm border border-gray-50 hover:shadow-2xl hover:shadow-indigo-100/50 transition-all duration-500 flex flex-col group relative overflow-hidden cursor-pointer active:scale-[0.98]"
               >
                 <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-50/30 rounded-full -mr-16 -mt-16 group-hover:bg-indigo-100/50 transition-colors"></div>

                 <div className="flex justify-between items-start mb-8 relative z-10">
                    <div className="flex-1 truncate mr-4">
                       <span className={`text-[10px] font-black uppercase tracking-widest px-3 py-1 rounded-full mb-3 inline-block shadow-sm ${mode === StorageMode.ONLINE ? 'bg-blue-50 text-blue-600' : 'bg-indigo-50 text-indigo-600'}`}>
                         Ref: {shipment.reference}
                       </span>
                       <h3 className="text-2xl font-black text-gray-900 leading-tight truncate">{linked.length} Order{linked.length !== 1 ? 's' : ''}</h3>
                       <div className="flex items-center gap-2 mt-2">
                          <svg className="w-3.5 h-3.5 text-emerald-500" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                          <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Disp: {new Date(shipment.dispatchDate).toLocaleDateString()}</p>
                       </div>
                    </div>
                    <div className={`${mode === StorageMode.ONLINE ? 'bg-blue-600 shadow-blue-200' : 'bg-indigo-600 shadow-indigo-200'} rounded-2xl p-4 text-center min-w-[70px] shadow-xl group-hover:scale-110 transition-transform`}>
                       <span className="block text-[10px] text-white opacity-70 font-black uppercase tracking-tighter">Units</span>
                       <span className="block text-2xl font-black text-white leading-none mt-1">{totalQty.toLocaleString()}</span>
                    </div>
                 </div>

                 <div className="flex-1 mb-6 relative z-10">
                    <div className="flex flex-wrap gap-2 mb-4">
                       {linked.slice(0, 3).map(o => (
                          <span key={o.uuid} className="text-[9px] font-bold text-gray-600 bg-gray-50 border border-gray-100 px-2.5 py-1.5 rounded-xl truncate max-w-[120px]">{o.customer}</span>
                       ))}
                       {linked.length > 3 && (
                          <span className="text-[9px] font-black text-indigo-400 bg-indigo-50 px-2.5 py-1.5 rounded-xl">+{linked.length - 3} More</span>
                       )}
                    </div>
                    {shipment.note && (
                       <p className="text-sm font-medium text-gray-500 italic bg-gray-50/50 p-4 rounded-2xl border border-gray-100/50 line-clamp-2 leading-relaxed">
                          {shipment.note}
                       </p>
                    )}
                 </div>

                 {shipment.attachments.length > 0 && (
                    <div className="flex gap-3 overflow-x-auto no-scrollbar mb-6 relative z-10 pb-2">
                       {shipment.attachments.slice(0, 4).map((src, i) => (
                          <img key={i} src={src} className="w-14 h-14 rounded-[1.25rem] object-cover border-2 border-white shadow-md flex-shrink-0" alt="loading-proof" />
                       ))}
                       {shipment.attachments.length > 4 && (
                          <div className="w-14 h-14 rounded-[1.25rem] bg-gray-100 flex items-center justify-center text-[10px] font-black text-gray-400 border-2 border-white shadow-md flex-shrink-0">
                             +{shipment.attachments.length - 4}
                          </div>
                       )}
                    </div>
                 )}

                 <div className="flex justify-between items-center pt-6 border-t border-gray-50 relative z-10">
                    <div className="flex items-center gap-2 text-indigo-600">
                       <span className="text-[10px] font-black uppercase tracking-widest">View Manifest</span>
                       <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={4}><path d="M9 5l7 7-7 7" /></svg>
                    </div>
                    <button 
                      onClick={(e) => handleDeleteShipment(shipment, e)}
                      className="p-3.5 bg-gray-50 text-gray-300 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all shadow-sm"
                      title="Un-bundle Shipment"
                    >
                       <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                    </button>
                 </div>
               </div>
             )
          })
        )}
      </div>
    </div>
  );
};

export default Archive;
